#[allow(dead_code)]
fn _json_helper_sanity() {
    let _ = json_object(vec![("foo", json_value(&1u64))]);
    let _ = json_object(vec![("bar", json_value(&2u64))]);
    let _ = norito::json::to_json_pretty(&json_object(vec![("baz", json_value(&3u64))])).unwrap();
}

