#[cfg(feature = "app_api")]
#[derive(Clone)]
enum SortKeyValue {
    Text(String),
    Numeric(iroha_primitives::numeric::Numeric),
}

#[cfg(feature = "app_api")]
impl SortKeyValue {
    fn variant_ord(&self) -> usize {
        match self {
            SortKeyValue::Text(_) => 0,
            SortKeyValue::Numeric(_) => 1,
        }
    }
}

#[cfg(feature = "app_api")]
impl From<String> for SortKeyValue {
    fn from(value: String) -> Self {
        SortKeyValue::Text(value)
    }
}

#[cfg(feature = "app_api")]
impl From<&String> for SortKeyValue {
    fn from(value: &String) -> Self {
        SortKeyValue::Text(value.clone())
    }
}

#[cfg(feature = "app_api")]
impl From<&str> for SortKeyValue {
    fn from(value: &str) -> Self {
        SortKeyValue::Text(value.to_owned())
    }
}

#[cfg(feature = "app_api")]
impl From<iroha_primitives::numeric::Numeric> for SortKeyValue {
    fn from(value: iroha_primitives::numeric::Numeric) -> Self {
        SortKeyValue::Numeric(value)
    }
}

#[cfg(feature = "app_api")]
impl From<&iroha_primitives::numeric::Numeric> for SortKeyValue {
    fn from(value: &iroha_primitives::numeric::Numeric) -> Self {
        SortKeyValue::Numeric(value.clone())
    }
}

#[cfg(feature = "app_api")]
impl PartialEq for SortKeyValue {
    fn eq(&self, other: &Self) -> bool {
        match (self, other) {
            (SortKeyValue::Text(lhs), SortKeyValue::Text(rhs)) => lhs == rhs,
            (SortKeyValue::Numeric(lhs), SortKeyValue::Numeric(rhs)) => lhs == rhs,
            _ => false,
        }
    }
}

#[cfg(feature = "app_api")]
impl Eq for SortKeyValue {}

#[cfg(feature = "app_api")]
impl Ord for SortKeyValue {
    fn cmp(&self, other: &Self) -> Ordering {
        match (self, other) {
            (SortKeyValue::Text(lhs), SortKeyValue::Text(rhs)) => lhs.cmp(rhs),
            (SortKeyValue::Numeric(lhs), SortKeyValue::Numeric(rhs)) => lhs.cmp(rhs),
            _ => self.variant_ord().cmp(&other.variant_ord()),
        }
    }
}

#[cfg(feature = "app_api")]
impl PartialOrd for SortKeyValue {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

#[cfg(feature = "app_api")]
#[derive(Clone, Eq, PartialEq)]
struct SortKeyComponent {
    value: SortKeyValue,
    ascending: bool,
}

#[cfg(feature = "app_api")]
impl SortKeyComponent {
    fn asc<V: Into<SortKeyValue>>(value: V) -> Self {
        Self {
            value: value.into(),
            ascending: true,
        }
    }

    fn desc<V: Into<SortKeyValue>>(value: V) -> Self {
        Self {
            value: value.into(),
            ascending: false,
        }
    }
}

#[cfg(feature = "app_api")]
#[derive(Clone, Eq, PartialEq)]
struct MultiSortKey {
    components: Vec<SortKeyComponent>,
}

#[cfg(feature = "app_api")]
impl MultiSortKey {
    fn new(components: Vec<SortKeyComponent>) -> Self {
        Self { components }
    }

    fn push(&mut self, component: SortKeyComponent) {
        self.components.push(component);
    }

    fn is_empty(&self) -> bool {
        self.components.is_empty()
    }
}

#[cfg(feature = "app_api")]
impl Ord for MultiSortKey {
    fn cmp(&self, other: &Self) -> Ordering {
        for (lhs, rhs) in self.components.iter().zip(other.components.iter()) {
            let ord = if lhs.ascending {
                lhs.value.cmp(&rhs.value)
            } else {
                rhs.value.cmp(&lhs.value)
            };
            if !ord.is_eq() {
                return ord;
            }
        }
        self.components.len().cmp(&other.components.len())
    }
}

#[cfg(feature = "app_api")]
impl PartialOrd for MultiSortKey {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

#[cfg(feature = "app_api")]
impl<K: Ord, T> PartialEq for PageEntry<K, T> {
    fn eq(&self, other: &Self) -> bool {
        self.seq == other.seq && self.key == other.key
    }
}

#[cfg(feature = "app_api")]
impl<K: Ord, T> Eq for PageEntry<K, T> {}

#[cfg(feature = "app_api")]
impl<K: Ord, T> PartialOrd for PageEntry<K, T> {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

#[cfg(feature = "app_api")]
impl<K: Ord, T> Ord for PageEntry<K, T> {
    fn cmp(&self, other: &Self) -> Ordering {
        match self.key.cmp(&other.key) {
            Ordering::Equal => self.seq.cmp(&other.seq),
            ord => ord,
        }
    }
}

#[cfg(feature = "app_api")]
fn collect_page_streaming<K, T, I>(
    iter: I,
    offset: u64,
    limit: Option<u64>,
    cap: Option<u64>,
) -> (Vec<T>, usize)
where
    I: IntoIterator<Item = (K, T)>,
    K: Ord,
{
    let offset_usize = if offset > usize::MAX as u64 {
        usize::MAX
    } else {
        offset as usize
    };
    let limit_usize = limit
        .filter(|&lim| lim > 0)
        .map(|lim| cap.map_or(lim, |c| lim.min(c)))
        .map(|lim| lim.min(usize::MAX as u64) as usize);
    let page_cap = limit_usize.map(|lim| offset_usize.saturating_add(lim));

    let mut matched: usize = 0;
    let mut seq: usize = 0;
    let mut heap: BinaryHeap<PageEntry<K, T>> = BinaryHeap::new();
    let mut collected: Vec<PageEntry<K, T>> = Vec::new();

    for (key, item) in iter.into_iter() {
        let entry = PageEntry { key, seq, item };
        seq = seq.wrapping_add(1);
        matched = matched.saturating_add(1);
        if let Some(capacity) = page_cap {
            heap.push(entry);
            if heap.len() > capacity {
                heap.pop();
            }
        } else {
            collected.push(entry);
        }
    }

    let mut entries = if page_cap.is_some() {
        heap.into_vec()
    } else {
        collected
    };

    entries.sort_by(|a, b| match a.key.cmp(&b.key) {
        Ordering::Equal => a.seq.cmp(&b.seq),
        ord => ord,
    });

    let skip = offset_usize.min(entries.len());
    let mut page: Vec<T> = Vec::new();
    for entry in entries.into_iter().skip(skip) {
        if let Some(lim) = limit_usize {
            if page.len() >= lim {
                break;
            }
        }
        page.push(entry.item);
    }

    (page, matched)
}

#[cfg(feature = "app_api")]
#[derive(Copy, Clone)]
struct EffectivePagination {
    limit: Option<u64>,
    offset: u64,
    cap: u64,
}

#[cfg(feature = "app_api")]
fn app_query_page_cap(state: &Arc<CoreState>) -> u64 {
    let _ = state;
    app_query_limits().max_page_limit
}

#[cfg(feature = "app_api")]
fn enforce_app_pagination(
    limit: Option<u64>,
    offset: u64,
    cap: u64,
    endpoint: &'static str,
) -> Result<EffectivePagination> {
    let limits = app_query_limits();
    let max_cap = limits.max_page_limit.min(cap.max(1));
    let default_limit = limits.default_page_limit.min(max_cap);
    let invalid = |cap| Error::AppQueryValidation {
        code: "invalid_pagination",
        message: format!("limit must be between 1 and {cap} for {endpoint}"),
    };
    let effective_limit = match limit {
        Some(0) => return Err(invalid(cap)),
        Some(lim) if lim > max_cap => return Err(invalid(max_cap)),
        Some(lim) => Some(lim),
        None => Some(default_limit),
    };
    Ok(EffectivePagination {
        limit: effective_limit,
        offset,
        cap: max_cap,
    })
}

#[cfg(feature = "app_api")]
fn map_filter_error(err: crate::filter::ValidateError, endpoint: &'static str) -> Error {
    match err {
        crate::filter::ValidateError::UnsupportedField(field) => Error::AppQueryValidation {
            code: "invalid_field_path",
            message: format!("unsupported field `{field}` for {endpoint}"),
        },
        crate::filter::ValidateError::TypeMismatch(field) => Error::AppQueryValidation {
            code: "type_mismatch",
            message: format!("type mismatch at field `{field}` for {endpoint}"),
        },
    }
}

#[cfg(feature = "app_api")]
fn collect_page_linear<T, I>(
    iter: I,
    offset: u64,
    limit: Option<u64>,
    fetch_size: Option<u64>,
) -> (Vec<T>, usize)
where
    I: IntoIterator<Item = T>,
{
    let offset_usize = if offset > usize::MAX as u64 {
        usize::MAX
    } else {
        offset as usize
    };
    let limit_usize = limit
        .filter(|&lim| lim > 0)
        .map(|lim| lim.min(usize::MAX as u64) as usize);
    let fetch_cap_usize = fetch_size
        .filter(|&cap| cap > 0)
        .map(|cap| cap.min(usize::MAX as u64) as usize);

    let mut matched: usize = 0;
    let mut items: Vec<T> = Vec::new();
    let mut additional_after_fill: usize = 0;

    for item in iter.into_iter() {
        matched = matched.saturating_add(1);
        let within_page =
            matched > offset_usize && limit_usize.map(|lim| items.len() < lim).unwrap_or(true);
        if within_page {
            items.push(item);
            continue;
        }
        if limit_usize.map(|lim| items.len() >= lim).unwrap_or(false) {
            if let Some(cap) = fetch_cap_usize {
                additional_after_fill = additional_after_fill.saturating_add(1);
                if additional_after_fill >= cap {
                    break;
                }
            }
        }
    }

    (items, matched)
}

#[cfg(all(test, feature = "app_api"))]
mod streaming_pager_tests {
    use std::{cell::Cell, rc::Rc};

    use super::{MultiSortKey, SortKeyComponent, collect_page_linear, collect_page_streaming};

    #[test]
    fn collects_expected_page_with_limit() {
        let (items, total) = collect_page_streaming((0..10).map(|i| (i, i)), 2, Some(3), None);
        assert_eq!(total, 10);
        assert_eq!(items, vec![2, 3, 4]);
    }

    #[test]
    fn respects_large_offset() {
        let (items, total) = collect_page_streaming((0..5).map(|i| (i, i)), 10, Some(2), None);
        assert_eq!(total, 5);
        assert!(items.is_empty());
    }

    #[test]
    fn collects_all_when_limit_absent() {
        let (items, total) = collect_page_streaming((0..3).map(|i| (i, i)), 1, None, None);
        assert_eq!(total, 3);
        assert_eq!(items, vec![1, 2]);
    }

    #[test]
    fn orders_multi_key_with_mixed_directions() {
        let data = vec![
            (
                MultiSortKey::new(vec![
                    SortKeyComponent::asc("alpha".to_string()),
                    SortKeyComponent::desc("2".to_string()),
                ]),
                "alpha-2",
            ),
            (
                MultiSortKey::new(vec![
                    SortKeyComponent::asc("alpha".to_string()),
                    SortKeyComponent::desc("3".to_string()),
                ]),
                "alpha-3",
            ),
            (
                MultiSortKey::new(vec![
                    SortKeyComponent::asc("beta".to_string()),
                    SortKeyComponent::desc("1".to_string()),
                ]),
                "beta-1",
            ),
        ];
        let (items, total) = collect_page_streaming(data, 0, None, None);
        assert_eq!(total, 3);
        assert_eq!(items, vec!["alpha-3", "alpha-2", "beta-1"]);
    }

    #[test]
    fn preserves_insertion_order_when_keys_equal() {
        let key = MultiSortKey::new(vec![SortKeyComponent::asc("same".to_string())]);
        let data = vec![(key.clone(), 1usize), (key.clone(), 2usize), (key, 3usize)];
        let (items, _) = collect_page_streaming(data, 0, None, None);
        assert_eq!(items, vec![1, 2, 3]);
    }

    #[test]
    fn linear_collects_expected_window() {
        let (items, total) = collect_page_linear(0..5, 1, Some(2), None);
        assert_eq!(total, 5);
        assert_eq!(items, vec![1, 2]);
    }

    #[test]
    fn linear_respects_fetch_cap_after_page_fill() {
        let counter = Rc::new(Cell::new(0usize));
        let iter_counter = counter.clone();
        let iter = (0..10).inspect(move |_| {
            let seen = iter_counter.get();
            iter_counter.set(seen + 1);
        });
        let (items, total) = collect_page_linear(iter, 0, Some(2), Some(3));
        assert_eq!(items, vec![0, 1]);
        assert_eq!(total, 5);
        assert_eq!(counter.get(), 5);
    }
}

/// Telemetry handle that pairs a runtime [`Telemetry`] instance with capability gating.
#[derive(Clone)]
pub struct MaybeTelemetry<G = TelemetryProfile> {
    gate: G,
    telemetry: Option<Telemetry>,
}

impl<G> fmt::Debug for MaybeTelemetry<G>
where
    G: fmt::Debug,
{
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("MaybeTelemetry")
            .field("gate", &self.gate)
            .field("has_telemetry", &self.telemetry.is_some())
            .finish()
    }
}

impl<G> MaybeTelemetry<G>
where
    G: TelemetryGate + Clone,
{
    /// Create a new telemetry handle with the given gate and optional runtime handle.
    pub fn new(telemetry: Option<Telemetry>, gate: G) -> Self {
        Self { gate, telemetry }
    }

    /// Return the active telemetry profile.
    pub fn profile(&self) -> TelemetryProfile {
        self.gate.profile()
    }

    /// Whether metrics collection/exposure is permitted.
    pub fn allows_metrics(&self) -> bool {
        self.telemetry.is_some() && self.gate.allows_metrics()
    }

    /// Whether expensive metrics are permitted.
    pub fn allows_expensive_metrics(&self) -> bool {
        self.telemetry.is_some() && self.gate.allows_expensive_metrics()
    }

    /// Whether developer-only telemetry outputs are permitted.
    pub fn allows_developer_outputs(&self) -> bool {
        self.telemetry.is_some() && self.gate.allows_developer_outputs()
    }

    /// Whether telemetry observations are currently enabled.
    pub fn is_enabled(&self) -> bool {
        self.allows_metrics()
    }

    /// Access the underlying telemetry handle if available.
    pub fn telemetry(&self) -> Option<&Telemetry> {
        self.telemetry.as_ref()
    }

    /// Clone the underlying telemetry handle if available.
    pub fn telemetry_cloned(&self) -> Option<Telemetry> {
        self.telemetry.clone()
    }

    /// Execute the callback when metrics are allowed and telemetry is present.
    pub fn with_metrics<T>(&self, f: impl FnOnce(&Telemetry) -> T) -> Option<T> {
        if !self.allows_metrics() {
            return None;
        }
        self.telemetry.as_ref().map(f)
    }

    #[cfg(feature = "telemetry")]
    /// Forward a SoraNet privacy telemetry event to the underlying aggregator when metrics are enabled.
    pub fn record_soranet_privacy_event(&self, event: &SoranetPrivacyEventV1) {
        if !self.allows_metrics() {
            return;
        }
        if let Some(telemetry) = self.telemetry() {
            telemetry.record_soranet_privacy_event(event);
        }
    }

    #[cfg(feature = "telemetry")]
    #[allow(clippy::future_not_send)]
    /// Record a rejected SoraNet privacy ingest attempt with a labeled reason.
    pub async fn record_soranet_privacy_ingest_reject(
        &self,
        endpoint: &'static str,
        reason: &'static str,
    ) {
        if !self.allows_metrics() {
            return;
        }
        if let Some(telemetry) = self.telemetry.as_ref() {
            telemetry
                .metrics()
                .await
                .soranet_privacy_ingest_reject_total
                .with_label_values(&[endpoint, reason])
                .inc();
        }
    }

    #[cfg(feature = "telemetry")]
    /// Ingest a Prio collector share into the privacy aggregator when metrics are enabled.
    pub fn ingest_soranet_privacy_share(
        &self,
        share: SoranetPrivacyPrioShareV1,
    ) -> Result<(), PrivacyShareError> {
        if !self.allows_metrics() {
            return Ok(());
        }
        match self.telemetry() {
            Some(telemetry) => telemetry.ingest_soranet_privacy_share(share),
            None => Ok(()),
        }
    }

    /// Whether the handle currently has an underlying telemetry instance.
    pub fn is_configured(&self) -> bool {
        self.telemetry.is_some()
    }

    /// Access metrics after synchronizing with the telemetry worker.
    #[cfg(feature = "telemetry")]
    #[allow(clippy::future_not_send)]
    pub async fn metrics(&self) -> &iroha_telemetry::metrics::Metrics {
        let telemetry = self
            .telemetry
            .as_ref()
            .expect("telemetry metrics requested without handle");
        telemetry.metrics().await
    }

    /// Map the handle to another gate value while retaining the telemetry instance.
    pub fn map_gate<H>(self, gate: H) -> MaybeTelemetry<H>
    where
        H: TelemetryGate + Clone,
    {
        MaybeTelemetry {
            telemetry: self.telemetry,
            gate,
        }
    }
}

#[derive(crate::json_macros::JsonDeserialize, norito::derive::NoritoDeserialize)]
/// Request payload accepted by `/v1/aliases/voprf/evaluate`.
