impl<G> TelemetryGate for MaybeTelemetry<G>
where
    G: TelemetryGate + Clone,
{
    fn profile(&self) -> TelemetryProfile {
        self.gate.profile()
    }
}

impl MaybeTelemetry {
    /// Construct a handle from a telemetry profile and optional runtime telemetry.
    pub fn from_profile(telemetry: Option<Telemetry>, profile: TelemetryProfile) -> Self {
        Self::new(telemetry, profile)
    }

    /// Disabled handle without telemetry backing.
    pub fn disabled() -> Self {
        Self::from_profile(None, TelemetryProfile::Disabled)
    }

    /// Build a telemetry handle suitable for tests.
    pub fn for_tests() -> Self {
        #[cfg(feature = "telemetry")]
        {
            use std::sync::Arc;

            use iroha_core::{
                kura::Kura,
                query::store::LiveQueryStore,
                queue::Queue,
                state::{State, World},
                telemetry as core_telemetry,
            };
            use iroha_primitives::time::TimeSource;
            use tokio::sync::watch;

            let metrics = iroha_telemetry::metrics::global_or_default();
            let kura = Kura::blank_kura_for_testing();
            let query = LiveQueryStore::start_test();
            let local_peer_id = PeerId::new(KeyPair::random().public_key().clone());
            let world = World::default();
            let mut world_block = world.block();
            let peers = world_block.peers_mut_for_testing().get_mut();
            let _ = peers.push(local_peer_id.clone());
            world_block.commit();
            let state = Arc::new(State::new(
                world,
                kura.clone(),
                query,
                core_telemetry::StateTelemetry::new(metrics.clone(), true),
            ));
            let (peers_tx, peers_rx) = watch::channel(<_>::default());
            let (_mh, time_source) = TimeSource::new_mock(core::time::Duration::default());
            let queue_cfg = iroha_config::parameters::actual::Queue {
                capacity: nonzero_ext::nonzero!(1usize),
                capacity_per_user: nonzero_ext::nonzero!(1usize),
                transaction_time_to_live: core::time::Duration::from_secs(1),
                ..Default::default()
            };
            let events_sender: iroha_core::EventsSender = tokio::sync::broadcast::channel(1).0;
            let queue = Arc::new(Queue::from_config(queue_cfg, events_sender));
            let (tel, _child) = core_telemetry::start(
                metrics,
                state,
                kura,
                queue,
                peers_rx,
                local_peer_id,
                time_source,
                true,
            );
            let _ = peers_tx;
            MaybeTelemetry::from_profile(Some(tel), TelemetryProfile::Operator)
        }
        #[cfg(not(feature = "telemetry"))]
        {
            MaybeTelemetry::disabled()
        }
    }
}
