/// Wrapped response for proof lookups that preserves payload size for egress gating.
#[cfg(feature = "app_api")]
pub struct ProofHttpResponse {
    /// Final HTTP response.
    pub response: axum::response::Response,
    /// Serialized payload length in bytes (0 for 304).
    pub bytes: u64,
}

