#[cfg(feature = "app_api")]
/// POST /v1/zk/submit-proof — minimal demo endpoint that accepts either Norito
/// (`application/x-norito`) or JSON and returns `{ "ok": true|false, "id": "<hex>" }`.
///
/// This is a convenience, non-consensus-critical handler intended for quick
/// end-to-end demos. It does not perform cryptographic verification or durable
/// storage. The returned `id` is a deterministic Blake2b-32 hash of the raw
/// request body bytes (after any JSON serialization).
pub async fn handle_v1_zk_submit_proof(
    headers: axum::http::HeaderMap,
    body: axum::body::Bytes,
) -> Result<Response> {
    let ct = headers
        .get(axum::http::header::CONTENT_TYPE)
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    // Determine acceptance boolean, mirroring verify semantics
    let ok = if ct.contains(super::utils::NORITO_MIME_TYPE) {
        // For Norito, any non-empty payload is considered accepted by the demo handler.
        !body.is_empty()
    } else if ct.contains("application/json") || ct.contains("text/json") {
        norito::json::from_slice::<norito::json::Value>(&body).is_ok()
    } else {
        // Unknown content type; try JSON as a last resort.
        norito::json::from_slice::<norito::json::Value>(&body).is_ok()
    };
    // Compute a deterministic id for reference/tracking (not persisted here).
    let id_hex = {
        let h = iroha_crypto::Hash::new(&body);
        hex::encode::<[u8; 32]>(h.into())
    };
    let accept = headers.get(axum::http::header::ACCEPT).cloned();
    let format = match crate::utils::negotiate_response_format(accept.as_ref()) {
        Ok(fmt) => fmt,
        Err(resp) => return Ok(resp),
    };
    Ok(crate::utils::respond_with_format(
        OkIdResponse { ok, id: id_hex },
        format,
    ))
}

#[cfg(feature = "zk-verify-batch")]
/// POST /v1/zk/verify-batch — verify a batch of OpenVerify envelopes (transparent IPA)
/// and return JSON `{ "ok": true, "statuses": [true|false, ...] }`.
///
/// Content types:
/// - `application/x-norito`: request body is a Norito-encoded `Vec<iroha_zkp_halo2::OpenVerifyEnvelope>`.
/// - `application/json`: currently not supported by this minimal handler (returns ok=false).
pub async fn handle_v1_zk_verify_batch(
    headers: axum::http::HeaderMap,
    body: axum::body::Bytes,
) -> Result<impl IntoResponse> {
    let ct = headers
        .get(axum::http::header::CONTENT_TYPE)
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    let mut ok = false;
    let mut statuses_json: Value = Value::Array(Vec::new());
    if ct.contains(super::utils::NORITO_MIME_TYPE) {
        if let Ok(envs) =
            norito::decode_from_bytes::<Vec<iroha_zkp_halo2::OpenVerifyEnvelope>>(&body)
        {
            let results = iroha_zkp_halo2::batch::verify_open_batch(&envs);
            let statuses: Vec<bool> = results.into_iter().map(|r| matches!(r, Ok(true))).collect();
            statuses_json = bools_to_json_array(&statuses);
            ok = true;
        }
    } else if ct.contains("application/json") || ct.contains("text/json") {
        // JSON: accept array of base64-encoded Norito envelopes.
        if let Ok(v) = norito::json::from_slice::<norito::json::Value>(&body) {
            if let Some(arr) = v.as_array() {
                let mut envs = Vec::with_capacity(arr.len());
                for item in arr {
                    if let Some(s) = item.as_str() {
                        if let Ok(bytes) =
                            base64::engine::general_purpose::STANDARD.decode(s.as_bytes())
                        {
                            if let Ok(env) = norito::decode_from_bytes::<
                                iroha_zkp_halo2::OpenVerifyEnvelope,
                            >(&bytes)
                            {
                                envs.push(env);
                            }
                        }
                    }
                }
                if !envs.is_empty() {
                    let results = iroha_zkp_halo2::batch::verify_open_batch(&envs);
                    let statuses: Vec<bool> =
                        results.into_iter().map(|r| matches!(r, Ok(true))).collect();
                    statuses_json = bools_to_json_array(&statuses);
                    ok = true;
                }
            }
        }
    }
    let payload = json_object(vec![
        json_entry("ok", ok),
        json_entry("statuses", statuses_json),
    ]);
    let body = json::to_json_pretty(&payload).map_err(norito_internal_error)?;
    let mut resp = axum::response::Response::new(axum::body::Body::from(body));
    resp.headers_mut().insert(
        axum::http::header::CONTENT_TYPE,
        axum::http::HeaderValue::from_static("application/json"),
    );
    Ok(resp)
}

#[cfg(feature = "app_api")]
/// POST /v1/zk/roots — convenience endpoint returning recent shielded roots as JSON.
///
/// This is an example wrapper for the Norito TLV APIs available via IVM syscalls.
/// Returns recent shielded roots for the requested asset, bounded by the configured
/// `zk.root_history_cap`. If the asset has no shielded state, returns an empty set.
pub async fn handle_v1_zk_roots(
    state: Arc<CoreState>,
    accept: Option<axum::http::HeaderValue>,
    NoritoJson(req): NoritoJson<ZkRootsGetRequestDto>,
) -> Result<Response> {
    use iroha_data_model::prelude::AssetDefinitionId;
    // Parse and validate asset id
    let ad: AssetDefinitionId = match req.asset_id.parse() {
        Ok(id) => id,
        Err(_) => {
            return Err(Error::Query(
                iroha_data_model::ValidationFail::NotPermitted(
                    "invalid asset_id; expected `name#domain`".to_owned(),
                ),
            ));
        }
    };
    let world = state.world_view();
    let zk = state.zk_snapshot();
    // Bound the requested window by config cap (0 -> cap)
    let cap = zk.root_history_cap;
    let want = if req.max == 0 {
        cap
    } else {
        core::cmp::min(cap, req.max as usize)
    };
    // Fetch roots from WSV (if any); build response window
    let roots_all = world
        .zk_assets()
        .get(&ad)
        .map(|st| st.root_history.clone())
        .unwrap_or_default();
    let latest_opt = roots_all.last().copied();
    let roots_tail: Vec<[u8; 32]> = if roots_all.len() <= want {
        roots_all.clone()
    } else {
        roots_all[roots_all.len() - want..].to_vec()
    };
    let resp = ZkRootsGetResponseDto {
        latest: latest_opt.map(hex::encode).unwrap_or_default(),
        roots: roots_tail.into_iter().map(hex::encode).collect(),
        // For convenience, report the total number of roots recorded for this asset.
        height: roots_all.len() as u32,
    };
    let format = match crate::utils::negotiate_response_format(accept.as_ref()) {
        Ok(fmt) => fmt,
        Err(resp) => return Ok(resp),
    };
    Ok(crate::utils::respond_with_format(resp, format))
}

