fn reject_direct_multisig_signing(
    world: &impl WorldReadOnly,
    tx: &SignedTransaction,
) -> Option<AcceptTransactionFail> {
    let _account = world.accounts().get(tx.authority())?;
    if tx.authority().controller().multisig_policy().is_none() {
        return None;
    }

    let only_custom_instruction_envelopes = matches!(
        tx.instructions(),
        Executable::Instructions(items)
            if !items.is_empty()
                && items.iter().all(|instruction| {
                    instruction
                        .as_any()
                        .downcast_ref::<iroha_data_model::isi::CustomInstruction>()
                        .is_some()
                })
    );
    if only_custom_instruction_envelopes {
        return None;
    }

    let rejection = SignatureVerificationFail::new(
        tx.signature().clone(),
        SignatureRejectionCode::UnsupportedAuthority,
        "direct signing with multisig accounts is forbidden; use multisig propose/approve",
    );
    Some(AcceptTransactionFail::SignatureVerification(rejection))
}

#[cfg(test)]
mod multisig_guard_tests {
    use iroha_core::{
        kura::Kura,
        query::store::LiveQueryStore,
        state::{State, World},
    };
    use iroha_crypto::KeyPair;
    use iroha_data_model::{
        account::{MultisigMember, MultisigPolicy},
        isi::CustomInstruction,
        role::{Role, RoleId},
    };

    use super::*;

    #[test]
    fn direct_multisig_signing_rejected_during_admission() {
        let domain_id: DomainId = "wonderland".parse().unwrap();
        let chain_id: ChainId = "multisig-direct-sign-guard".parse().unwrap();
        let signer_keypair = KeyPair::random();
        let policy = MultisigPolicy::new(
            1,
            vec![MultisigMember::new(signer_keypair.public_key().clone(), 1).unwrap()],
        )
        .unwrap();
        let multisig_id = ScopedAccountId::new_multisig(domain_id.clone(), policy);

        let domain = Domain::new(domain_id.clone()).build(multisig_id.account());
        let multisig_account = Account::new(multisig_id.clone()).build(multisig_id.account());
        let world = World::with([domain], [multisig_account], []);
        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let state = State::new_for_testing(world, kura, query_handle);
        let tx = TransactionBuilder::new(chain_id, multisig_id.clone().into())
            .with_executable(Executable::Instructions(Vec::new().into()))
            .sign(signer_keypair.private_key());

        let view = state.view();
        let rejection = reject_direct_multisig_signing(view.world(), &tx);
        match rejection {
            Some(AcceptTransactionFail::SignatureVerification(fail)) => {
                assert_eq!(fail.code(), SignatureRejectionCode::UnsupportedAuthority);
            }
            other => panic!("expected multisig direct-sign rejection, got {other:?}"),
        }
    }

    #[test]
    fn single_signatory_with_multisig_role_is_not_rejected() {
        let domain_id: DomainId = "wonderland".parse().unwrap();
        let chain_id: ChainId = "multisig-role-guard".parse().unwrap();
        let signer = KeyPair::random();
        let signatory_id = ScopedAccountId::new(domain_id.clone(), signer.public_key().clone());

        let role_id: RoleId = "MULTISIG_SIGNATORY/test/0".parse().unwrap();
        let role =
            Role::new(role_id.clone(), signatory_id.clone().into()).build(signatory_id.account());

        let domain = Domain::new(domain_id.clone()).build(signatory_id.account());
        let account = Account::new(signatory_id.clone()).build(signatory_id.account());
        let mut world = World::with_assets_and_roles([domain], [account], [], [], [], [role]);
        world.grant_role_for_tests(signatory_id.clone().into(), role_id);

        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let state = State::new_for_testing(world, kura, query_handle);
        let tx = TransactionBuilder::new(chain_id, signatory_id.clone().into())
            .with_executable(Executable::Instructions(Vec::new().into()))
            .sign(signer.private_key());

        let view = state.view();
        let rejection = reject_direct_multisig_signing(view.world(), &tx);
        assert!(
            rejection.is_none(),
            "single-signature signatories with multisig role must pass admission guard"
        );
    }

    #[test]
    fn multisig_authority_with_custom_instruction_envelope_is_not_rejected() {
        let domain_id: DomainId = "wonderland".parse().unwrap();
        let chain_id: ChainId = "multisig-custom-envelope-guard".parse().unwrap();
        let signer_keypair = KeyPair::random();
        let policy = MultisigPolicy::new(
            1,
            vec![MultisigMember::new(signer_keypair.public_key().clone(), 1).unwrap()],
        )
        .unwrap();
        let multisig_id = ScopedAccountId::new_multisig(domain_id.clone(), policy);

        let domain = Domain::new(domain_id.clone()).build(multisig_id.account());
        let multisig_account = Account::new(multisig_id.clone()).build(multisig_id.account());
        let world = World::with([domain], [multisig_account], []);
        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let state = State::new_for_testing(world, kura, query_handle);

        let custom: InstructionBox = CustomInstruction::new("multisig-envelope").into();
        let tx = TransactionBuilder::new(chain_id, multisig_id.clone().into())
            .with_executable(Executable::Instructions(vec![custom].into()))
            .sign(signer_keypair.private_key());

        let view = state.view();
        let rejection = reject_direct_multisig_signing(view.world(), &tx);
        assert!(
            rejection.is_none(),
            "multisig custom instruction envelopes must pass admission guard"
        );
    }
}

#[iroha_futures::telemetry_future]
async fn handle_transaction_inner(
    chain_id: Arc<ChainId>,
    queue: Arc<Queue>,
    state: Arc<CoreState>,
    tx: SignedTransaction,
    _telemetry: &MaybeTelemetry,
) -> Result<RoutingDecision> {
    let (max_clock_drift, tx_limits, state_view) = {
        let state_view = state.world.view();
        let params = state_view.parameters();
        (
            params.sumeragi().max_clock_drift(),
            params.transaction(),
            state_view,
        )
    };
    if let Some(rejection) = reject_direct_multisig_signing(&state_view, &tx) {
        iroha_logger::warn!(
            authority = %tx.authority(),
            "rejecting transaction directly signed by multisig account"
        );
        #[cfg(feature = "telemetry")]
        _telemetry.with_metrics(|tel| {
            tel.inc_torii_multisig_direct_sign_reject();
            let signature_count = tx.signature_count() as u64;
            let signature_limit = tx_limits.max_signatures().get();
            let authority_label = match tx.authority().controller() {
                iroha_data_model::account::AccountController::Single(_) => "single",
                iroha_data_model::account::AccountController::Multisig(_) => "multisig",
            };
            tel.inc_torii_signature_limit_reject(signature_count, signature_limit, authority_label);
        });
        return Err(Error::AcceptTransaction(rejection));
    }
    drop(state_view);
    #[cfg(feature = "telemetry")]
    let signature_count = tx.signature_count() as u64;
    #[cfg(feature = "telemetry")]
    let signature_limit = tx_limits.max_signatures().get();
    #[cfg(feature = "telemetry")]
    let authority_label = match tx.authority().controller() {
        iroha_data_model::account::AccountController::Single(_) => "single",
        iroha_data_model::account::AccountController::Multisig(_) => "multisig",
    };
    let crypto_cfg = state.crypto();
    let accepted_tx = match AcceptedTransaction::accept(
        tx,
        &chain_id,
        max_clock_drift,
        tx_limits,
        crypto_cfg.as_ref(),
    ) {
        Ok(tx) => tx,
        Err(err) => {
            iroha_logger::warn!(?err, "transaction rejected during admission");
            #[cfg(feature = "telemetry")]
            _telemetry.with_metrics(|tel| {
                if let AcceptTransactionFail::TransactionLimit(limit) = &err {
                    if limit.reason.starts_with(SIGNATURE_LIMIT_REASON_PREFIX) {
                        tel.inc_torii_signature_limit_reject(
                            signature_count,
                            signature_limit,
                            authority_label,
                        );
                    }
                }
                if matches!(err, AcceptTransactionFail::NetworkTimeUnhealthy { .. }) {
                    tel.inc_torii_nts_unhealthy_reject();
                }
            });
            return Err(Error::AcceptTransaction(err));
        }
    };
    iroha_logger::debug!(
        tx = %accepted_tx.as_ref().hash(),
        "transaction accepted by Torii; enqueuing"
    );

    queue
        .push_with_lane_with_state(accepted_tx, state.as_ref())
        .map_err(|queue::Failure { tx, err }| {
            iroha_logger::warn!(
                tx_hash=%tx.as_ref().as_ref().hash(), ?err,
                "Failed to push into queue"
            );

            drop(tx);
            (err, queue.current_backpressure())
        })
        .map_err(|(err, backpressure)| Error::PushIntoQueue {
            source: Box::new(err),
            backpressure,
        })
        .inspect(|decision| {
            iroha_logger::debug!(
                lane = %decision.lane_id.as_u32(),
                dataspace = %decision.dataspace_id.as_u64(),
                "transaction enqueued successfully"
            );
        })
}

pub async fn handle_transaction(
    chain_id: Arc<ChainId>,
    queue: Arc<Queue>,
    state: Arc<CoreState>,
    tx: SignedTransaction,
) -> Result<()> {
    let telemetry = MaybeTelemetry::disabled();
    handle_transaction_inner(chain_id, queue, state, tx, &telemetry)
        .await
        .map(|_| ())
}

#[cfg(feature = "telemetry")]
const TELEMETRY_SYNC_TIMEOUT: std::time::Duration = std::time::Duration::from_millis(500);

#[cfg(feature = "telemetry")]
async fn observe_lane_admission_latency(
    telemetry: &MaybeTelemetry,
    endpoint: &'static str,
    lane_id: iroha_data_model::nexus::LaneId,
    elapsed_seconds: f64,
) {
    if !telemetry.is_enabled() {
        return;
    }

    let Ok(metrics) = tokio::time::timeout(TELEMETRY_SYNC_TIMEOUT, telemetry.metrics()).await
    else {
        iroha_logger::warn!(
            lane = %lane_id.as_u32(),
            endpoint,
            timeout_ms = TELEMETRY_SYNC_TIMEOUT.as_millis(),
            "telemetry sync timed out; skipping lane admission latency record"
        );
        return;
    };

    let lane_label = lane_id.as_u32().to_string();
    metrics
        .torii_lane_admission_latency_seconds
        .with_label_values(&[lane_label.as_str(), endpoint])
        .observe(elapsed_seconds);
}

#[cfg_attr(not(feature = "telemetry"), allow(unused_variables))]
pub async fn handle_transaction_with_metrics(
    chain_id: Arc<ChainId>,
    queue: Arc<Queue>,
    state: Arc<CoreState>,
    tx: SignedTransaction,
    telemetry: MaybeTelemetry,
    endpoint: &'static str,
) -> Result<RoutingDecision> {
    #[cfg(feature = "telemetry")]
    let start = std::time::Instant::now();

    let result = handle_transaction_inner(chain_id, queue, state, tx, &telemetry).await;

    #[cfg(feature = "telemetry")]
    if let Ok(decision) = &result {
        observe_lane_admission_latency(
            &telemetry,
            endpoint,
            decision.lane_id,
            start.elapsed().as_secs_f64(),
        )
        .await;
    }

    result
}

