#[cfg(feature = "app_api")]
fn parse_commitment_hex(s: &str) -> Result<[u8; 32]> {
    let bytes = hex::decode(s).map_err(|e| {
        Error::Query(iroha_data_model::ValidationFail::QueryFailed(
            iroha_data_model::query::error::QueryExecutionFail::Conversion(e.to_string()),
        ))
    })?;
    if bytes.len() != 32 {
        return Err(Error::Query(iroha_data_model::ValidationFail::QueryFailed(
            iroha_data_model::query::error::QueryExecutionFail::Conversion(
                "expected 32-byte commitment".into(),
            ),
        )));
    }
    let mut arr = [0u8; 32];
    arr.copy_from_slice(&bytes);
    Ok(arr)
}

#[cfg(feature = "app_api")]
fn parse_hex32_str(value: &str, field: &str) -> Result<[u8; 32]> {
    let trimmed = value.trim_start_matches("0x");
    let bytes = hex::decode(trimmed).map_err(|e| {
        Error::Query(iroha_data_model::ValidationFail::QueryFailed(
            iroha_data_model::query::error::QueryExecutionFail::Conversion(format!(
                "invalid {field}: {e}"
            )),
        ))
    })?;
    if bytes.len() != 32 {
        return Err(Error::Query(iroha_data_model::ValidationFail::QueryFailed(
            iroha_data_model::query::error::QueryExecutionFail::Conversion(format!(
                "{field} must be 32 bytes"
            )),
        )));
    }
    let mut arr = [0u8; 32];
    arr.copy_from_slice(&bytes);
    Ok(arr)
}

#[cfg(feature = "app_api")]
struct VkRecordInputs {
    backend: String,
    version: u32,
    status: Option<iroha_data_model::confidential::ConfidentialStatus>,
    vk_bytes: Option<Vec<u8>>,
    commitment_hex: Option<String>,
    circuit_id: String,
    public_inputs_schema_hex: String,
    curve: Option<String>,
    gas_schedule_id: Option<String>,
    vk_len: Option<u32>,
    max_proof_bytes: Option<u32>,
    metadata_uri_cid: Option<String>,
    vk_bytes_cid: Option<String>,
    activation_height: Option<u64>,
    withdraw_height: Option<u64>,
}

#[cfg(feature = "app_api")]
fn mk_record_from_inputs(
    inputs: VkRecordInputs,
) -> Result<iroha_data_model::proof::VerifyingKeyRecord> {
    use iroha_core::zk::hash_vk;
    use iroha_data_model::{
        confidential::ConfidentialStatus,
        proof::{VerifyingKeyBox, VerifyingKeyRecord},
        zk::BackendTag,
    };
    let VkRecordInputs {
        backend,
        version,
        status,
        vk_bytes,
        commitment_hex,
        circuit_id,
        public_inputs_schema_hex,
        curve,
        gas_schedule_id,
        vk_len,
        max_proof_bytes,
        metadata_uri_cid,
        vk_bytes_cid,
        activation_height,
        withdraw_height,
    } = inputs;
    if let Some(ref status_value) = status {
        if !matches!(
            *status_value,
            iroha_data_model::confidential::ConfidentialStatus::Active
                | iroha_data_model::confidential::ConfidentialStatus::Proposed
        ) {
            return Err(Error::Query(iroha_data_model::ValidationFail::QueryFailed(
                iroha_data_model::query::error::QueryExecutionFail::Conversion(
                    "status must be Active or Proposed".into(),
                ),
            )));
        }
    }
    let mut key_opt = None;
    let commitment: [u8; 32];
    let vk_len_value;
    if let Some(bytes) = vk_bytes {
        let vk = VerifyingKeyBox::new(backend.as_str().into(), bytes);
        let h = hash_vk(&vk);
        if let Some(hex) = &commitment_hex {
            let parsed = parse_commitment_hex(hex)?;
            if parsed != h {
                return Err(Error::Query(iroha_data_model::ValidationFail::QueryFailed(
                    iroha_data_model::query::error::QueryExecutionFail::Conversion(
                        "commitment mismatch with provided vk_bytes".into(),
                    ),
                )));
            }
        }
        commitment = h;
        let actual_len = vk.bytes.len() as u32;
        if let Some(explicit_len) = vk_len {
            if explicit_len != actual_len {
                return Err(Error::Query(iroha_data_model::ValidationFail::QueryFailed(
                    iroha_data_model::query::error::QueryExecutionFail::Conversion(
                        "vk_len mismatch with provided vk_bytes".into(),
                    ),
                )));
            }
        }
        vk_len_value = actual_len;
        key_opt = Some(vk);
    } else if let Some(hex) = commitment_hex {
        commitment = parse_commitment_hex(&hex)?;
        let explicit_len = vk_len.ok_or_else(|| {
            Error::Query(iroha_data_model::ValidationFail::QueryFailed(
                iroha_data_model::query::error::QueryExecutionFail::Conversion(
                    "vk_len required when vk_bytes omitted".into(),
                ),
            ))
        })?;
        if explicit_len == 0 {
            return Err(Error::Query(iroha_data_model::ValidationFail::QueryFailed(
                iroha_data_model::query::error::QueryExecutionFail::Conversion(
                    "vk_len must be > 0".into(),
                ),
            )));
        }
        vk_len_value = explicit_len;
    } else {
        return Err(Error::Query(iroha_data_model::ValidationFail::QueryFailed(
            iroha_data_model::query::error::QueryExecutionFail::Conversion(
                "provide either vk_bytes or commitment_hex".into(),
            ),
        )));
    }
    let backend_tag = match backend.as_str() {
        b if b.contains("halo2") && (b.contains("pasta") || b.contains("ipa")) => {
            BackendTag::Halo2IpaPasta
        }
        b if b.contains("groth16") => BackendTag::Groth16,
        b if b.contains("stark") => BackendTag::Stark,
        _ => BackendTag::Unsupported,
    };
    let schema_hash = parse_hex32_str(&public_inputs_schema_hex, "public_inputs_schema_hex")?;
    let gas_schedule_id = gas_schedule_id.ok_or_else(|| {
        Error::Query(iroha_data_model::ValidationFail::QueryFailed(
            iroha_data_model::query::error::QueryExecutionFail::Conversion(
                "gas_schedule_id is required".into(),
            ),
        ))
    })?;
    if gas_schedule_id.trim().is_empty() {
        return Err(Error::Query(iroha_data_model::ValidationFail::QueryFailed(
            iroha_data_model::query::error::QueryExecutionFail::Conversion(
                "gas_schedule_id must not be empty".into(),
            ),
        )));
    }
    if let (Some(act), Some(withdraw)) = (activation_height, withdraw_height) {
        if act > withdraw {
            return Err(Error::Query(iroha_data_model::ValidationFail::QueryFailed(
                iroha_data_model::query::error::QueryExecutionFail::Conversion(
                    "withdraw_height must be >= activation_height".into(),
                ),
            )));
        }
    }
    let mut record = VerifyingKeyRecord::new_with_owner(
        version,
        circuit_id,
        None,
        "core",
        backend_tag,
        curve.unwrap_or_else(|| "unknown".into()),
        schema_hash,
        commitment,
    );
    record.vk_len = vk_len_value;
    record.max_proof_bytes = max_proof_bytes.unwrap_or(0);
    record.status = status.unwrap_or(ConfidentialStatus::Active);
    record.metadata_uri_cid = metadata_uri_cid;
    record.vk_bytes_cid = vk_bytes_cid;
    record.activation_height = activation_height;
    record.withdraw_height = withdraw_height;
    record.key = key_opt;
    record.gas_schedule_id = Some(gas_schedule_id);
    Ok(record)
}

#[cfg(feature = "app_api")]
fn vk_record_to_json(rec: &iroha_data_model::proof::VerifyingKeyRecord) -> norito::json::Value {
    use iroha_data_model::confidential::ConfidentialStatus;

    use crate::json_value;

    let mut m = norito::json::Map::new();
    m.insert(
        "version".into(),
        norito::json::Value::from(rec.version as u64),
    );
    m.insert(
        "circuit_id".into(),
        norito::json::Value::from(rec.circuit_id.clone()),
    );
    m.insert("backend".into(), json_value(&rec.backend));
    m.insert("curve".into(), norito::json::Value::from(rec.curve.clone()));
    m.insert(
        "public_inputs_schema_hash".into(),
        norito::json::Value::from(hex::encode(rec.public_inputs_schema_hash)),
    );
    m.insert(
        "commitment".into(),
        norito::json::Value::from(hex::encode(rec.commitment)),
    );
    m.insert(
        "vk_len".into(),
        norito::json::Value::from(rec.vk_len as u64),
    );
    m.insert(
        "max_proof_bytes".into(),
        norito::json::Value::from(rec.max_proof_bytes as u64),
    );
    m.insert("gas_schedule_id".into(), json_value(&rec.gas_schedule_id));
    m.insert("metadata_uri_cid".into(), json_value(&rec.metadata_uri_cid));
    m.insert("vk_bytes_cid".into(), json_value(&rec.vk_bytes_cid));
    m.insert(
        "activation_height".into(),
        json_value(&rec.activation_height),
    );
    m.insert("withdraw_height".into(), json_value(&rec.withdraw_height));
    let status_str = match rec.status {
        ConfidentialStatus::Active => "Active",
        ConfidentialStatus::Proposed => "Proposed",
        ConfidentialStatus::Withdrawn => "Withdrawn",
    };
    m.insert("status".into(), norito::json::Value::from(status_str));
    let key_value = if let Some(vk) = rec.key.as_ref() {
        let mut k = norito::json::Map::new();
        k.insert(
            "backend".into(),
            norito::json::Value::from(vk.backend.clone()),
        );
        k.insert(
            "bytes_b64".into(),
            norito::json::Value::from(base64::engine::general_purpose::STANDARD.encode(&vk.bytes)),
        );
        norito::json::Value::Object(k)
    } else {
        norito::json::Value::Null
    };
    m.insert("key".into(), key_value);
    norito::json::Value::Object(m)
}

#[cfg(all(test, feature = "app_api"))]
mod vk_record_input_tests {
    use iroha_data_model::confidential::ConfidentialStatus;

    use super::*;

    fn sample_hex32(fill: u8) -> String {
        hex::encode([fill; 32])
    }

    #[test]
    fn mk_record_from_inputs_sets_optional_fields() {
        let vk_bytes = vec![1, 2, 3, 4];
        let inputs = VkRecordInputs {
            backend: "halo2/ipa".to_string(),
            version: 1,
            status: Some(ConfidentialStatus::Active),
            vk_bytes: Some(vk_bytes.clone()),
            commitment_hex: None,
            circuit_id: "circuit_alpha".to_string(),
            public_inputs_schema_hex: sample_hex32(0xAA),
            curve: Some("pallas".to_string()),
            gas_schedule_id: Some("sched_default".to_string()),
            vk_len: Some(vk_bytes.len() as u32),
            max_proof_bytes: Some(8192),
            metadata_uri_cid: Some("ipfs://metadata".to_string()),
            vk_bytes_cid: Some("ipfs://vk_bytes".to_string()),
            activation_height: Some(100),
            withdraw_height: Some(300),
        };
        let record = mk_record_from_inputs(inputs).expect("record created");
        assert_eq!(record.vk_len, vk_bytes.len() as u32);
        assert_eq!(record.max_proof_bytes, 8192);
        assert_eq!(record.metadata_uri_cid.as_deref(), Some("ipfs://metadata"));
        assert_eq!(record.vk_bytes_cid.as_deref(), Some("ipfs://vk_bytes"));
        assert_eq!(record.activation_height, Some(100));
        assert_eq!(record.withdraw_height, Some(300));
        assert!(record.key.is_some(), "inline vk should be preserved");
        assert_eq!(record.gas_schedule_id.as_deref(), Some("sched_default"));
    }

    #[test]
    fn mk_record_requires_vk_len_without_bytes() {
        let res = mk_record_from_inputs(VkRecordInputs {
            backend: "halo2/ipa".to_string(),
            version: 1,
            status: Some(ConfidentialStatus::Active),
            vk_bytes: None,
            commitment_hex: Some(sample_hex32(0x11)),
            circuit_id: "circuit_alpha".to_string(),
            public_inputs_schema_hex: sample_hex32(0x22),
            curve: Some("pallas".to_string()),
            gas_schedule_id: Some("sched_default".to_string()),
            vk_len: None,
            max_proof_bytes: None,
            metadata_uri_cid: None,
            vk_bytes_cid: None,
            activation_height: None,
            withdraw_height: None,
        });
        assert!(res.is_err());
    }

    #[test]
    fn mk_record_rejects_missing_gas_schedule() {
        let res = mk_record_from_inputs(VkRecordInputs {
            backend: "halo2/ipa".to_string(),
            version: 1,
            status: Some(ConfidentialStatus::Active),
            vk_bytes: Some(vec![1, 2, 3]),
            commitment_hex: None,
            circuit_id: "circuit_alpha".to_string(),
            public_inputs_schema_hex: sample_hex32(0x33),
            curve: Some("pallas".to_string()),
            gas_schedule_id: None,
            vk_len: Some(3),
            max_proof_bytes: None,
            metadata_uri_cid: None,
            vk_bytes_cid: None,
            activation_height: None,
            withdraw_height: None,
        });
        assert!(res.is_err());
    }

    #[test]
    fn mk_record_rejects_invalid_status() {
        let res = mk_record_from_inputs(VkRecordInputs {
            backend: "halo2/ipa".to_string(),
            version: 1,
            status: Some(ConfidentialStatus::Withdrawn),
            vk_bytes: Some(vec![1, 2, 3]),
            commitment_hex: None,
            circuit_id: "circuit_alpha".to_string(),
            public_inputs_schema_hex: sample_hex32(0x44),
            curve: Some("pallas".to_string()),
            gas_schedule_id: Some("sched_default".to_string()),
            vk_len: Some(3),
            max_proof_bytes: None,
            metadata_uri_cid: None,
            vk_bytes_cid: None,
            activation_height: None,
            withdraw_height: None,
        });
        assert!(res.is_err());
    }

    #[test]
    fn mk_record_rejects_inconsistent_heights() {
        let res = mk_record_from_inputs(VkRecordInputs {
            backend: "halo2/ipa".to_string(),
            version: 1,
            status: Some(ConfidentialStatus::Active),
            vk_bytes: Some(vec![1, 2, 3]),
            commitment_hex: None,
            circuit_id: "circuit_alpha".to_string(),
            public_inputs_schema_hex: sample_hex32(0x55),
            curve: Some("pallas".to_string()),
            gas_schedule_id: Some("sched_default".to_string()),
            vk_len: Some(3),
            max_proof_bytes: None,
            metadata_uri_cid: None,
            vk_bytes_cid: None,
            activation_height: Some(200),
            withdraw_height: Some(100),
        });
        assert!(res.is_err());
    }
}

/// POST /v1/zk/vk/register — submit RegisterVerifyingKey as a signed transaction.
#[cfg(feature = "app_api")]
pub async fn handle_post_vk_register(
    chain_id: Arc<ChainId>,
    queue: Arc<Queue>,
    state: Arc<CoreState>,
    telemetry: MaybeTelemetry,
    NoritoJson(req): NoritoJson<ZkVkRegisterDto>,
) -> Result<impl IntoResponse> {
    use iroha_data_model::{isi::verifying_keys, prelude as dm};
    let vk_record = mk_record_from_inputs(VkRecordInputs {
        backend: req.backend.clone(),
        version: req.version,
        status: req.status,
        vk_bytes: req.vk_bytes.clone(),
        commitment_hex: req.commitment_hex.clone(),
        circuit_id: req.circuit_id.clone(),
        public_inputs_schema_hex: req.public_inputs_schema_hex.clone(),
        curve: req.curve.clone(),
        gas_schedule_id: req.gas_schedule_id.clone(),
        vk_len: req.vk_len,
        max_proof_bytes: req.max_proof_bytes,
        metadata_uri_cid: req.metadata_uri_cid.clone(),
        vk_bytes_cid: req.vk_bytes_cid.clone(),
        activation_height: req.activation_height,
        withdraw_height: req.withdraw_height,
    })?;
    let id = VerifyingKeyId::new(req.backend.clone(), req.name.clone());
    let isi = verifying_keys::RegisterVerifyingKey {
        id,
        record: vk_record,
    };
    let tx = dm::TransactionBuilder::new((*chain_id).clone(), req.authority.clone().into())
        .with_instructions(core::iter::once(dm::InstructionBox::from(isi)))
        .sign(&req.private_key.0);
    handle_transaction_with_metrics(chain_id, queue, state, tx, telemetry, "/v1/zk/vk/register")
        .await
        .map(|_| (StatusCode::ACCEPTED, ()))
}

/// POST /v1/zk/vk/update — submit UpdateVerifyingKey as a signed transaction.
#[cfg(feature = "app_api")]
pub async fn handle_post_vk_update(
    chain_id: Arc<ChainId>,
    queue: Arc<Queue>,
    state: Arc<CoreState>,
    telemetry: MaybeTelemetry,
    NoritoJson(req): NoritoJson<ZkVkUpdateDto>,
) -> Result<impl IntoResponse> {
    use iroha_data_model::{isi::verifying_keys, prelude as dm};
    let vk_record = mk_record_from_inputs(VkRecordInputs {
        backend: req.backend.clone(),
        version: req.version,
        status: req.status,
        vk_bytes: req.vk_bytes.clone(),
        commitment_hex: req.commitment_hex.clone(),
        circuit_id: req.circuit_id.clone(),
        public_inputs_schema_hex: req.public_inputs_schema_hex.clone(),
        curve: req.curve.clone(),
        gas_schedule_id: req.gas_schedule_id.clone(),
        vk_len: req.vk_len,
        max_proof_bytes: req.max_proof_bytes,
        metadata_uri_cid: req.metadata_uri_cid.clone(),
        vk_bytes_cid: req.vk_bytes_cid.clone(),
        activation_height: req.activation_height,
        withdraw_height: req.withdraw_height,
    })?;
    let id = VerifyingKeyId::new(req.backend.clone(), req.name.clone());
    let isi = verifying_keys::UpdateVerifyingKey {
        id,
        record: vk_record,
    };
    let tx = dm::TransactionBuilder::new((*chain_id).clone(), req.authority.clone().into())
        .with_instructions(core::iter::once(dm::InstructionBox::from(isi)))
        .sign(&req.private_key.0);
    handle_transaction_with_metrics(chain_id, queue, state, tx, telemetry, "/v1/zk/vk/update")
        .await
        .map(|_| (StatusCode::ACCEPTED, ()))
}

/// GET /v1/zk/vk/{backend}/{name} — read verifying key record.
#[cfg(feature = "app_api")]
pub async fn handle_get_vk(
    state: Arc<CoreState>,
    axum::extract::Path((backend, name)): axum::extract::Path<(String, String)>,
) -> Result<impl IntoResponse> {
    use iroha_data_model::proof::VerifyingKeyId;
    let id = VerifyingKeyId::new(backend, name);
    let world = state.world_view();
    let rec = world.verifying_keys().get(&id).cloned().ok_or_else(|| {
        Error::Query(iroha_data_model::ValidationFail::QueryFailed(
            iroha_data_model::query::error::QueryExecutionFail::NotFound,
        ))
    })?;
    let mut root = norito::json::Map::new();
    let mut id_map = norito::json::Map::new();
    id_map.insert(
        "backend".into(),
        norito::json::Value::from(id.backend.clone()),
    );
    id_map.insert("name".into(), norito::json::Value::from(id.name.clone()));
    root.insert("id".into(), norito::json::Value::Object(id_map));
    root.insert("record".into(), vk_record_to_json(&rec));
    let body = norito::json::to_json_pretty(&root).unwrap_or_else(|_| "{}".into());
    let mut resp = axum::response::Response::new(axum::body::Body::from(body));
    resp.headers_mut().insert(
        axum::http::header::CONTENT_TYPE,
        axum::http::HeaderValue::from_static("application/json"),
    );
    Ok(resp)
}

