#[cfg(feature = "app_api")]
fn repair_task_record_body(record: &RepairTaskRecordV1) -> String {
    let bytes = norito::to_bytes(record).unwrap_or_default();
    let encoded = base64::engine::general_purpose::STANDARD.encode(bytes);
    let wrapper = json_object(vec![("norito_base64", json_value(&encoded))]);
    norito::json::to_json_pretty(&wrapper).unwrap_or_else(|_| "{}".into())
}

#[cfg(feature = "app_api")]
fn repair_task_records_body(records: &[RepairTaskRecordV1]) -> String {
    let entries: Vec<_> = records
        .iter()
        .map(|record| {
            let bytes = norito::to_bytes(record).unwrap_or_default();
            let encoded = base64::engine::general_purpose::STANDARD.encode(bytes);
            json_object(vec![("norito_base64", json_value(&encoded))])
        })
        .collect();
    norito::json::to_json_pretty(&json::Value::Array(entries)).unwrap_or_else(|_| "[]".into())
}

#[cfg(feature = "app_api")]
fn repair_task_snapshots_body(snapshots: &[sorafs_node::RepairTaskSnapshot]) -> String {
    let entries: Vec<_> = snapshots
        .iter()
        .map(|snapshot| {
            let record_bytes = norito::to_bytes(&snapshot.record).unwrap_or_default();
            let record_encoded = base64::engine::general_purpose::STANDARD.encode(record_bytes);
            let events: Vec<_> = snapshot
                .events
                .iter()
                .map(|event| {
                    let event_bytes = norito::to_bytes(event).unwrap_or_default();
                    let event_encoded =
                        base64::engine::general_purpose::STANDARD.encode(event_bytes);
                    json_object(vec![("norito_base64", json_value(&event_encoded))])
                })
                .collect();
            json_object(vec![
                ("norito_base64", json_value(&record_encoded)),
                ("events", json::Value::Array(events)),
            ])
        })
        .collect();
    norito::json::to_json_pretty(&json::Value::Array(entries)).unwrap_or_else(|_| "[]".into())
}

#[iroha_futures::telemetry_future]
#[cfg(feature = "app_api")]
pub async fn handle_post_sorafs_record_replication_failure(
    telemetry: MaybeTelemetry,
    sorafs_node: sorafs_node::NodeHandle,
    NoritoJson(req): NoritoJson<RecordReplicationFailureDto>,
) -> Result<impl IntoResponse> {
    let order_id = parse_hex_array::<32>(&req.order_id_hex, "order_id_hex")?;
    let recorded = sorafs_node.record_replication_failure(order_id);
    observe_sorafs_metering(&telemetry, &sorafs_node);

    let response = RecordReplicationFailureResponseDto {
        status: if recorded {
            "recorded".to_owned()
        } else {
            "ignored".to_owned()
        },
        order_id_hex: hex::encode(order_id),
        recorded,
    };

    let body = norito::json::to_json_pretty(&response).unwrap_or_else(|_| "{}".into());
    let mut resp = axum::response::Response::new(axum::body::Body::from(body));
    resp.headers_mut().insert(
        axum::http::header::CONTENT_TYPE,
        axum::http::HeaderValue::from_static("application/json"),
    );
    Ok(resp)
}

fn parse_hex_array<const N: usize>(value: &str, field: &str) -> Result<[u8; N], Error> {
    let trimmed = value.trim_start_matches("0x");
    let bytes = hex::decode(trimmed).map_err(|err| {
        conversion_error(format!(
            "invalid hex in `{field}` (expected {N} bytes): {err}"
        ))
    })?;
    let len = bytes.len();
    bytes
        .try_into()
        .map_err(|_| conversion_error(format!("`{field}` must be {N} bytes (got {len})")))
}

fn parse_hash_hex(value: &str, field: &str) -> Result<Hash, Error> {
    Hash::from_str(value).map_err(|err| conversion_error(format!("invalid {field}: {err}")))
}

fn missing_field_error(field: &str) -> Error {
    conversion_error(format!("`{field}` is required"))
}

fn proof_request_error(err: OfflineProofRequestError) -> Error {
    conversion_error(format!("failed to build proof request: {err}"))
}

fn json_response<T>(value: &T) -> Result<Response, Error>
where
    T: norito::json::JsonSerialize,
{
    let body = norito::json::to_json_pretty(value).map_err(|e| {
        Error::Query(iroha_data_model::ValidationFail::InternalError(
            e.to_string(),
        ))
    })?;
    let mut resp = Response::new(Body::from(body));
    resp.headers_mut().insert(
        header::CONTENT_TYPE,
        header::HeaderValue::from_static("application/json"),
    );
    Ok(resp)
}

fn dispute_kind_label(kind: sorafs_manifest::capacity::CapacityDisputeKind) -> &'static str {
    use sorafs_manifest::capacity::CapacityDisputeKind::*;
    match kind {
        ReplicationShortfall => "replication_shortfall",
        UptimeBreach => "uptime_breach",
        ProofFailure => "proof_failure",
        FeeDispute => "fee_dispute",
        Other => "other",
    }
}

#[cfg(feature = "app_api")]
fn observe_sorafs_metering(telemetry: &MaybeTelemetry, sorafs_node: &sorafs_node::NodeHandle) {
    let usage = sorafs_node.capacity_usage();
    let provider_id = match usage.provider_id {
        Some(id) => id,
        None => return,
    };
    let provider_hex = hex::encode(provider_id);
    let snapshot = sorafs_node.metering_snapshot();
    let scheduler = sorafs_node.schedulers();
    let storage_snapshot = scheduler.telemetry_snapshot();
    let fee_projection =
        sorafs_node::metering::FeeProjection::from_snapshot(provider_id, &snapshot);
    telemetry.with_metrics(|tel| {
        tel.record_sorafs_metering(
            &provider_hex,
            snapshot.declared_gib,
            snapshot.effective_gib,
            snapshot.utilised_gib,
            snapshot.outstanding_total_gib,
            snapshot.outstanding_orders,
            snapshot.accumulated_gib_hours,
            snapshot.orders_issued,
            snapshot.orders_completed,
            snapshot.orders_failed,
            snapshot.uptime_bps,
            snapshot.por_success_bps,
        );
        if let Some(projection) = &fee_projection {
            tel.record_sorafs_fee_projection(&provider_hex, projection.fee_nanos);
        }
        tel.record_sorafs_storage(
            &provider_hex,
            storage_snapshot.bytes_used,
            storage_snapshot.bytes_capacity,
            storage_snapshot.pin_queue_depth as u64,
            storage_snapshot.fetch_inflight as u64,
            storage_snapshot.fetch_bytes_per_sec,
            storage_snapshot.por_inflight as u64,
            storage_snapshot.por_samples_success,
            storage_snapshot.por_samples_failed,
        );
        for status in sorafs_node.por_ingestion_overview() {
            let manifest_hex = hex::encode(status.manifest_digest);
            let entry_provider_hex = hex::encode(status.provider_id);
            tel.record_sorafs_por_ingestion_backlog(
                &entry_provider_hex,
                &manifest_hex,
                status.pending_challenges,
            );
            tel.record_sorafs_por_ingestion_failures(
                &entry_provider_hex,
                &manifest_hex,
                status.failures_total,
            );
        }
    });
}

fn provider_id_from_hex(value: &str) -> Result<ProviderId, Error> {
    parse_hex_array::<32>(value, "provider_id_hex").map(ProviderId::new)
}

fn metadata_from_entries(entries: Option<Vec<MetadataEntryDto>>) -> Result<Metadata, Error> {
    let mut metadata = Metadata::default();
    let Some(entries) = entries else {
        return Ok(metadata);
    };

    for MetadataEntryDto { key, value } in entries {
        let name = Name::from_str(&key)
            .map_err(|err| conversion_error(format!("invalid metadata key `{key}`: {err}")))?;
        metadata.insert(name, value);
    }
    Ok(metadata)
}

fn capacity_declaration_validation_error(err: CapacityDeclarationValidationError) -> Error {
    conversion_error(format!("capacity declaration validation failed: {err}"))
}

fn replication_order_validation_error(err: ReplicationOrderValidationError) -> Error {
    conversion_error(format!("replication order validation failed: {err}"))
}

fn replication_schedule_error(err: sorafs_node::capacity::CapacityError) -> Error {
    use sorafs_node::capacity::CapacityError::*;
    let message = match err {
        DecodeDeclaration(e) => format!("failed to decode capacity declaration payload: {e}"),
        ValidateDeclaration(e) => format!("capacity declaration validation failed: {e}"),
        ProviderMismatch => "capacity declaration provider id mismatch".to_string(),
        CommittedCapacityMismatch {
            declaration,
            record,
        } => format!(
            "capacity declaration committed GiB mismatch (declaration {declaration}, record {record})"
        ),
        NoActiveDeclaration => {
            "no active SoraFS capacity declaration recorded on this node".to_string()
        }
        UnsupportedChunker { handle } => {
            format!("replication order references unsupported chunker handle `{handle}`")
        }
        OrderAlreadyScheduled { order_id } => {
            format!(
                "replication order {} is already scheduled",
                hex::encode(order_id)
            )
        }
        InsufficientTotalCapacity {
            requested,
            available,
        } => format!(
            "insufficient total capacity: requested {requested} GiB, available {available} GiB"
        ),
        InsufficientChunkerCapacity {
            requested,
            available,
        } => format!(
            "insufficient chunker capacity: requested {requested} GiB, available {available} GiB"
        ),
        InsufficientLaneCapacity {
            requested,
            available,
        } => format!(
            "insufficient lane capacity: requested {requested} GiB, available {available} GiB"
        ),
        UnknownLane { lane } => format!("replication order references unknown lane `{lane}`"),
        OrderNotScheduled { order_id } => format!(
            "replication order {} is not currently scheduled",
            hex::encode(order_id)
        ),
        ZeroSlice => "replication assignment must reserve a positive GiB slice".to_string(),
        AllocationOverflow => "capacity allocation overflowed internal counters".to_string(),
        AllocationUnderflow => "capacity allocation underflowed internal counters".to_string(),
    };
    conversion_error(message)
}

fn decode_por_payload<T>(payload_b64: &str, kind: &str) -> Result<T, Error>
where
    T: for<'de> norito::NoritoDeserialize<'de>,
{
    let bytes = base64::engine::general_purpose::STANDARD
        .decode(payload_b64.as_bytes())
        .map_err(|err| conversion_error(format!("invalid base64 in {kind}_b64: {err}")))?;
    norito::decode_from_bytes(&bytes)
        .map_err(|err| conversion_error(format!("invalid {kind} payload: {err}")))
}

fn por_tracker_error(err: sorafs_node::PorTrackerError) -> Error {
    use iroha_data_model::query::error::QueryExecutionFail;
    use sorafs_node::PorTrackerError::*;
    match err {
        UnknownChallenge => Error::Query(iroha_data_model::ValidationFail::QueryFailed(
            QueryExecutionFail::NotFound,
        )),
        other => conversion_error(other.to_string()),
    }
}

fn por_coordinator_error(err: PorCoordinatorError) -> Error {
    use iroha_data_model::query::error::QueryExecutionFail;
    match err {
        PorCoordinatorError::UnknownChallenge { .. } => Error::Query(
            iroha_data_model::ValidationFail::QueryFailed(QueryExecutionFail::NotFound),
        ),
        other => conversion_error(other.to_string()),
    }
}

fn repair_scheduler_error(err: sorafs_node::RepairSchedulerError) -> Error {
    conversion_error(format!("repair scheduler error: {err}"))
}

#[cfg(feature = "app_api")]
fn repair_filters_from_query(
    manifest_digest: Option<[u8; 32]>,
    query: RepairStatusQueryDto,
) -> Result<RepairTaskFilters, Error> {
    let status = match query.status.as_deref() {
        Some(label) => Some(parse_repair_status(label)?),
        None => None,
    };
    let provider_id = match query.provider.as_deref() {
        Some(value) => Some(parse_hex_array::<32>(value, "provider")?),
        None => None,
    };
    Ok(RepairTaskFilters {
        manifest_digest,
        provider_id,
        status,
    })
}

#[cfg(feature = "app_api")]
fn parse_repair_status(label: &str) -> Result<RepairTaskStatusV1, Error> {
    let normalized = label.trim().to_ascii_lowercase();
    let status = match normalized.as_str() {
        "queued" => RepairTaskStatusV1::Queued,
        "verifying" => RepairTaskStatusV1::Verifying,
        "in_progress" | "in-progress" | "inprogress" => RepairTaskStatusV1::InProgress,
        "completed" => RepairTaskStatusV1::Completed,
        "failed" => RepairTaskStatusV1::Failed,
        "escalated" => RepairTaskStatusV1::Escalated,
        _ => {
            return Err(conversion_error(format!(
                "invalid repair status `{label}` (expected queued, verifying, in_progress, completed, failed, escalated)"
            )));
        }
    };
    Ok(status)
}

#[cfg(all(test, feature = "app_api"))]
mod repair_query_tests {
    use super::*;
    use axum::extract::Path;
    use axum::response::IntoResponse;
    use http_body_util::BodyExt;
    use sorafs_manifest::repair::{
        REPAIR_EVIDENCE_VERSION_V1, REPAIR_REPORT_VERSION_V1, RepairCauseV1, RepairEvidenceV1,
        RepairTicketId,
    };
    use sorafs_node::config::StorageConfig;
    use tokio::runtime::Runtime;

    fn report(
        ticket: &str,
        manifest_digest: [u8; 32],
        provider_id: [u8; 32],
        submitted_at_unix: u64,
    ) -> RepairReportV1 {
        RepairReportV1 {
            version: REPAIR_REPORT_VERSION_V1,
            ticket_id: RepairTicketId(ticket.to_string()),
            auditor_account: "auditor#sora".into(),
            submitted_at_unix,
            evidence: RepairEvidenceV1 {
                version: REPAIR_EVIDENCE_VERSION_V1,
                manifest_digest,
                provider_id,
                por_history_id: None,
                cause: RepairCauseV1::Manual {
                    reason: "test".into(),
                },
                evidence_json: None,
                notes: None,
            },
            notes: None,
        }
    }

    #[test]
    fn parse_repair_status_accepts_known_values() {
        assert_eq!(
            parse_repair_status("queued").unwrap(),
            RepairTaskStatusV1::Queued
        );
        assert_eq!(
            parse_repair_status("IN_PROGRESS").unwrap(),
            RepairTaskStatusV1::InProgress
        );
        assert_eq!(
            parse_repair_status("completed").unwrap(),
            RepairTaskStatusV1::Completed
        );
        assert_eq!(
            parse_repair_status("failed").unwrap(),
            RepairTaskStatusV1::Failed
        );
        assert_eq!(
            parse_repair_status("escalated").unwrap(),
            RepairTaskStatusV1::Escalated
        );
    }

    #[test]
    fn repair_filters_parse_provider_and_status() {
        let provider_id = [0x42; 32];
        let provider_hex = format!("0x{}", hex::encode(provider_id));
        let query = RepairStatusQueryDto {
            status: Some("in_progress".into()),
            provider: Some(provider_hex),
        };
        let filters =
            repair_filters_from_query(Some([0x11; 32]), query).expect("parse repair filters");
        assert_eq!(filters.manifest_digest, Some([0x11; 32]));
        assert_eq!(filters.provider_id, Some(provider_id));
        assert_eq!(filters.status, Some(RepairTaskStatusV1::InProgress));
    }

    #[test]
    fn repair_status_handlers_apply_filters() {
        Runtime::new().expect("runtime").block_on(async {
            let temp_dir = tempfile::tempdir().expect("temp dir");
            let config = StorageConfig::builder()
                .enabled(true)
                .data_dir(temp_dir.path().join("storage"))
                .build();
            let node = sorafs_node::NodeHandle::new(config);
            let manifest_a = [0x10; 32];
            let manifest_b = [0x11; 32];
            let provider_a = [0x22; 32];
            let provider_b = [0x33; 32];

            node.enqueue_repair_report(&report("REP-400", manifest_a, provider_a, 1_700_000_000))
                .expect("enqueue report");
            node.enqueue_repair_report(&report("REP-401", manifest_b, provider_b, 1_700_000_100))
                .expect("enqueue report");

            let query = RepairStatusQueryDto {
                status: Some("queued".into()),
                provider: Some(format!("0x{}", hex::encode(provider_a))),
            };
            let resp = handle_get_sorafs_repair_status_all(node.clone(), crate::NoritoQuery(query))
                .await
                .expect("global repair status");
            let body = resp
                .into_response()
                .into_body()
                .collect()
                .await
                .expect("body");
            let value: norito::json::Value =
                norito::json::from_slice(body.to_bytes().as_ref()).expect("parse json");
            let entries = value.as_array().expect("array response");
            assert_eq!(entries.len(), 1);

            let manifest_hex = hex::encode(manifest_a);
            let manifest_query = RepairStatusQueryDto {
                status: Some("queued".into()),
                provider: None,
            };
            let resp = handle_get_sorafs_repair_status(
                node.clone(),
                Path(manifest_hex),
                crate::NoritoQuery(manifest_query),
            )
            .await
            .expect("manifest repair status");
            let body = resp
                .into_response()
                .into_body()
                .collect()
                .await
                .expect("body");
            let value: norito::json::Value =
                norito::json::from_slice(body.to_bytes().as_ref()).expect("parse json");
            let entries = value.as_array().expect("array response");
            assert_eq!(entries.len(), 1);
        });
    }
}

#[cfg(all(test, feature = "app_api"))]
mod repair_worker_tests {
    use super::*;
    use axum::response::IntoResponse;
    use iroha_crypto::{KeyPair, SignatureOf};
    use sorafs_manifest::repair::{
        REPAIR_EVIDENCE_VERSION_V1, REPAIR_REPORT_VERSION_V1, REPAIR_WORKER_SIGNATURE_VERSION_V1,
        RepairCauseV1, RepairEvidenceV1, RepairTaskStateV1, RepairTicketId, RepairWorkerActionV1,
        RepairWorkerSignaturePayloadV1,
    };
    use sorafs_node::config::StorageConfig;
    use tokio::runtime::Runtime;

    fn report(
        ticket: &str,
        manifest_digest: [u8; 32],
        provider_id: [u8; 32],
        submitted_at_unix: u64,
    ) -> RepairReportV1 {
        RepairReportV1 {
            version: REPAIR_REPORT_VERSION_V1,
            ticket_id: RepairTicketId(ticket.to_string()),
            auditor_account: "auditor#sora".into(),
            submitted_at_unix,
            evidence: RepairEvidenceV1 {
                version: REPAIR_EVIDENCE_VERSION_V1,
                manifest_digest,
                provider_id,
                por_history_id: None,
                cause: RepairCauseV1::Manual {
                    reason: "test".into(),
                },
                evidence_json: None,
                notes: None,
            },
            notes: None,
        }
    }

    fn sign_worker_action(
        keypair: &KeyPair,
        ticket_id: &RepairTicketId,
        manifest_digest: [u8; 32],
        provider_id: [u8; 32],
        worker_id: &str,
        idempotency_key: &str,
        action: RepairWorkerActionV1,
    ) -> SignatureOf<RepairWorkerSignaturePayloadV1> {
        let payload = RepairWorkerSignaturePayloadV1 {
            version: REPAIR_WORKER_SIGNATURE_VERSION_V1,
            ticket_id: ticket_id.clone(),
            manifest_digest,
            provider_id,
            worker_id: worker_id.to_string(),
            idempotency_key: idempotency_key.to_string(),
            action,
        };
        SignatureOf::new(keypair.private_key(), &payload)
    }

    #[test]
    fn repair_worker_handlers_drive_state_transitions() {
        Runtime::new().expect("runtime").block_on(async {
            let temp_dir = tempfile::tempdir().expect("temp dir");
            let config = StorageConfig::builder()
                .enabled(true)
                .data_dir(temp_dir.path().join("storage"))
                .build();
            let node = sorafs_node::NodeHandle::new(config);
            let signer = KeyPair::random();
            let report_a = report("REP-460", [0x10; 32], [0x20; 32], 1_700_500_000);
            let report_b = report("REP-461", [0x11; 32], [0x21; 32], 1_700_500_100);

            node.enqueue_repair_report(&report_a)
                .expect("enqueue report a");
            node.enqueue_repair_report(&report_b)
                .expect("enqueue report b");

            let claim = RepairWorkerClaimDto {
                ticket_id: report_a.ticket_id.clone(),
                manifest_digest_hex: hex::encode(report_a.evidence.manifest_digest),
                worker_id: "worker-a".into(),
                claimed_at_unix: report_a.submitted_at_unix + 10,
                idempotency_key: "claim-a".into(),
                signature: sign_worker_action(
                    &signer,
                    &report_a.ticket_id,
                    report_a.evidence.manifest_digest,
                    report_a.evidence.provider_id,
                    "worker-a",
                    "claim-a",
                    RepairWorkerActionV1::Claim {
                        claimed_at_unix: report_a.submitted_at_unix + 10,
                    },
                ),
            };
            let _ = handle_post_sorafs_repair_claim(
                MaybeTelemetry::disabled(),
                node.clone(),
                NoritoJson(claim),
            )
            .await
            .expect("claim handler")
            .into_response();

            let heartbeat = RepairWorkerHeartbeatDto {
                ticket_id: report_a.ticket_id.clone(),
                manifest_digest_hex: hex::encode(report_a.evidence.manifest_digest),
                worker_id: "worker-a".into(),
                heartbeat_at_unix: report_a.submitted_at_unix + 20,
                idempotency_key: "heartbeat-a".into(),
                signature: sign_worker_action(
                    &signer,
                    &report_a.ticket_id,
                    report_a.evidence.manifest_digest,
                    report_a.evidence.provider_id,
                    "worker-a",
                    "heartbeat-a",
                    RepairWorkerActionV1::Heartbeat {
                        heartbeat_at_unix: report_a.submitted_at_unix + 20,
                    },
                ),
            };
            let _ = handle_post_sorafs_repair_heartbeat(
                MaybeTelemetry::disabled(),
                node.clone(),
                NoritoJson(heartbeat),
            )
            .await
            .expect("heartbeat handler")
            .into_response();

            let complete = RepairWorkerCompleteDto {
                ticket_id: report_a.ticket_id.clone(),
                manifest_digest_hex: hex::encode(report_a.evidence.manifest_digest),
                worker_id: "worker-a".into(),
                completed_at_unix: report_a.submitted_at_unix + 30,
                resolution_notes: Some("done".into()),
                idempotency_key: "complete-a".into(),
                signature: sign_worker_action(
                    &signer,
                    &report_a.ticket_id,
                    report_a.evidence.manifest_digest,
                    report_a.evidence.provider_id,
                    "worker-a",
                    "complete-a",
                    RepairWorkerActionV1::Complete {
                        completed_at_unix: report_a.submitted_at_unix + 30,
                        resolution_notes: Some("done".into()),
                    },
                ),
            };
            let _ = handle_post_sorafs_repair_complete(
                MaybeTelemetry::disabled(),
                node.clone(),
                NoritoJson(complete),
            )
            .await
            .expect("complete handler")
            .into_response();

            let claim_b = RepairWorkerClaimDto {
                ticket_id: report_b.ticket_id.clone(),
                manifest_digest_hex: hex::encode(report_b.evidence.manifest_digest),
                worker_id: "worker-b".into(),
                claimed_at_unix: report_b.submitted_at_unix + 5,
                idempotency_key: "claim-b".into(),
                signature: sign_worker_action(
                    &signer,
                    &report_b.ticket_id,
                    report_b.evidence.manifest_digest,
                    report_b.evidence.provider_id,
                    "worker-b",
                    "claim-b",
                    RepairWorkerActionV1::Claim {
                        claimed_at_unix: report_b.submitted_at_unix + 5,
                    },
                ),
            };
            let _ = handle_post_sorafs_repair_claim(
                MaybeTelemetry::disabled(),
                node.clone(),
                NoritoJson(claim_b),
            )
            .await
            .expect("claim handler b")
            .into_response();

            let fail = RepairWorkerFailDto {
                ticket_id: report_b.ticket_id.clone(),
                manifest_digest_hex: hex::encode(report_b.evidence.manifest_digest),
                worker_id: "worker-b".into(),
                failed_at_unix: report_b.submitted_at_unix + 15,
                reason: "retry".into(),
                idempotency_key: "fail-b".into(),
                signature: sign_worker_action(
                    &signer,
                    &report_b.ticket_id,
                    report_b.evidence.manifest_digest,
                    report_b.evidence.provider_id,
                    "worker-b",
                    "fail-b",
                    RepairWorkerActionV1::Fail {
                        failed_at_unix: report_b.submitted_at_unix + 15,
                        reason: "retry".into(),
                    },
                ),
            };
            let _ = handle_post_sorafs_repair_fail(
                MaybeTelemetry::disabled(),
                node.clone(),
                NoritoJson(fail),
            )
            .await
            .expect("fail handler")
            .into_response();

            let tasks = node.repair_tasks(RepairTaskFilters::default());
            assert_eq!(tasks.len(), 2);
            let mut states = tasks
                .iter()
                .map(|task| (task.ticket_id.0.as_str(), &task.state))
                .collect::<Vec<_>>();
            states.sort_by(|(left, _), (right, _)| left.cmp(right));
            assert!(matches!(states[0].1, RepairTaskStateV1::Completed(..)));
            assert!(matches!(states[1].1, RepairTaskStateV1::Failed(..)));
        });
    }
}

fn manifest_policy_from_dto(dto: &PinPolicyDto) -> ManifestPinPolicy {
    let storage_class = match dto.storage_class {
        PinPolicyStorageClassDto::Hot => ManifestStorageClass::Hot,
        PinPolicyStorageClassDto::Warm => ManifestStorageClass::Warm,
        PinPolicyStorageClassDto::Cold => ManifestStorageClass::Cold,
    };
    ManifestPinPolicy {
        min_replicas: dto.min_replicas,
        storage_class,
        retention_epoch: dto.retention_epoch,
    }
}

fn convert_manifest_policy(
    policy: &ManifestPinPolicy,
) -> iroha_data_model::sorafs::pin_registry::PinPolicy {
    use iroha_data_model::sorafs::pin_registry::StorageClass as DmStorageClass;
    let storage_class = match policy.storage_class {
        ManifestStorageClass::Hot => DmStorageClass::Hot,
        ManifestStorageClass::Warm => DmStorageClass::Warm,
        ManifestStorageClass::Cold => DmStorageClass::Cold,
    };
    iroha_data_model::sorafs::pin_registry::PinPolicy {
        min_replicas: policy.min_replicas,
        storage_class,
        retention_epoch: policy.retention_epoch,
    }
}

#[cfg(feature = "app_api")]
pub fn parse_report_iso_week(label: &str) -> Result<PorReportIsoWeek, Error> {
    let (year_part, week_part) = label
        .split_once("-W")
        .ok_or_else(|| conversion_error("ISO week must be formatted as YYYY-Www".to_string()))?;
    let year: u16 = year_part
        .parse()
        .map_err(|err| conversion_error(format!("invalid ISO week year `{year_part}`: {err}")))?;
    let week: u8 = week_part
        .parse()
        .map_err(|err| conversion_error(format!("invalid ISO week number `{week_part}`: {err}")))?;
    let cycle = PorReportIsoWeek { year, week };
    cycle
        .validate()
        .map_err(|err| conversion_error(format!("invalid ISO week `{label}`: {err}")))?;
    Ok(cycle)
}

fn manifest_validation_error(err: ManifestValidationError) -> Error {
    conversion_error(format!("manifest validation failed: {err}"))
}

#[allow(clippy::redundant_pub_crate)]
pub(crate) fn conversion_error(message: String) -> Error {
    Error::Query(iroha_data_model::ValidationFail::QueryFailed(
        iroha_data_model::query::error::QueryExecutionFail::Conversion(message),
    ))
}

fn deal_engine_error(err: DealEngineError) -> Error {
    use DealEngineError as E;
    match err {
        E::UnknownProvider(provider) => conversion_error(format!(
            "unknown provider {}",
            hex::encode(provider.as_bytes())
        )),
        E::UnknownClient(client) => {
            conversion_error(format!("unknown client {}", hex::encode(client.as_bytes())))
        }
        E::InsufficientBond {
            provider,
            required,
            available,
        } => conversion_error(format!(
            "insufficient bond for provider {} (required {required}, available {available})",
            hex::encode(provider.as_bytes())
        )),
        E::DuplicateDeal(deal) => conversion_error(format!(
            "deal {} already exists",
            hex::encode(deal.as_bytes())
        )),
        E::UnknownDeal(deal) => {
            conversion_error(format!("deal {} not found", hex::encode(deal.as_bytes())))
        }
        E::DealInactive(deal) => conversion_error(format!(
            "deal {} is not active",
            hex::encode(deal.as_bytes())
        )),
        E::ActivationOutOfRange {
            deal_id,
            activation_epoch,
            start,
            end,
        } => conversion_error(format!(
            "activation epoch {activation_epoch} outside [{start}, {end}] for deal {}",
            hex::encode(deal_id.as_bytes())
        )),
        E::UsageEpochOutOfRange {
            deal_id,
            usage_epoch,
            start,
            end,
        } => conversion_error(format!(
            "usage epoch {usage_epoch} outside [{start}, {end}] for deal {}",
            hex::encode(deal_id.as_bytes())
        )),
        E::SettlementWindowMismatch {
            deal_id,
            settlement_epoch,
            window_epochs,
        } => conversion_error(format!(
            "settlement epoch {settlement_epoch} does not satisfy window length {window_epochs} for deal {}",
            hex::encode(deal_id.as_bytes())
        )),
        E::MetadataEncoding(err) => conversion_error(format!("metadata encoding failed: {err}")),
    }
}

fn quota_limit_error(err: QuotaExceeded) -> Error {
    let _ = err;
    Error::Query(iroha_data_model::ValidationFail::QueryFailed(
        iroha_data_model::query::error::QueryExecutionFail::CapacityLimit,
    ))
}

#[cfg(feature = "app_api")]
mod serialization {
    use sorafs_manifest::capacity::CapacityMetadataEntry;

    use super::*;

    pub fn replication_plan_to_value(
        status: &str,
        plan: &sorafs_node::capacity::ReplicationPlan,
    ) -> Result<Value, json::Error> {
        let mut root = Map::new();
        root.insert("status".into(), Value::String(status.to_string()));
        root.insert(
            "order_id_hex".into(),
            Value::String(hex::encode(plan.order_id)),
        );
        root.insert(
            "provider_id_hex".into(),
            Value::String(hex::encode(plan.provider_id)),
        );
        root.insert(
            "chunker_handle".into(),
            Value::String(plan.chunker_handle.clone()),
        );
        root.insert(
            "manifest_cid_hex".into(),
            Value::String(hex::encode(&plan.manifest_cid)),
        );
        root.insert(
            "manifest_digest_hex".into(),
            Value::String(hex::encode(plan.manifest_digest)),
        );
        root.insert(
            "assigned_slice_gib".into(),
            json::to_value(&plan.assigned_slice_gib)?,
        );
        root.insert(
            "remaining_total_gib".into(),
            json::to_value(&plan.remaining_total_gib)?,
        );
        root.insert(
            "remaining_chunker_gib".into(),
            json::to_value(&plan.remaining_chunker_gib)?,
        );
        root.insert(
            "remaining_lane_gib".into(),
            plan.remaining_lane_gib
                .map(|value| json::to_value(&value))
                .transpose()?
                .unwrap_or(Value::Null),
        );
        root.insert(
            "lane".into(),
            plan.lane
                .as_ref()
                .map(|lane| Value::String(lane.clone()))
                .unwrap_or(Value::Null),
        );
        root.insert("deadline_at".into(), json::to_value(&plan.deadline_at)?);
        root.insert("issued_at".into(), json::to_value(&plan.issued_at)?);
        root.insert(
            "sla_ingest_deadline_secs".into(),
            json::to_value(&plan.sla.ingest_deadline_secs)?,
        );
        root.insert(
            "sla_min_availability_percent_milli".into(),
            json::to_value(&plan.sla.min_availability_percent_milli)?,
        );
        root.insert(
            "sla_min_por_success_percent_milli".into(),
            json::to_value(&plan.sla.min_por_success_percent_milli)?,
        );
        root.insert("metadata".into(), metadata_entries_to_array(&plan.metadata));
        Ok(Value::Object(root))
    }

    pub fn replication_plan_ignored_value(
        order: &ReplicationOrderV1,
    ) -> Result<Value, json::Error> {
        let mut root = Map::new();
        root.insert("status".into(), Value::String("ignored".to_string()));
        root.insert(
            "order_id_hex".into(),
            Value::String(hex::encode(order.order_id)),
        );
        root.insert("provider_id_hex".into(), Value::Null);
        root.insert(
            "chunker_handle".into(),
            Value::String(order.chunking_profile.clone()),
        );
        root.insert(
            "manifest_cid_hex".into(),
            Value::String(hex::encode(&order.manifest_cid)),
        );
        root.insert(
            "manifest_digest_hex".into(),
            Value::String(hex::encode(order.manifest_digest)),
        );
        root.insert("assigned_slice_gib".into(), json::to_value(&0u64)?);
        root.insert("remaining_total_gib".into(), json::to_value(&0u64)?);
        root.insert("remaining_chunker_gib".into(), json::to_value(&0u64)?);
        root.insert("remaining_lane_gib".into(), Value::Null);
        root.insert("lane".into(), Value::Null);
        root.insert("deadline_at".into(), json::to_value(&order.deadline_at)?);
        root.insert("issued_at".into(), json::to_value(&order.issued_at)?);
        root.insert(
            "sla_ingest_deadline_secs".into(),
            json::to_value(&order.sla.ingest_deadline_secs)?,
        );
        root.insert(
            "sla_min_availability_percent_milli".into(),
            json::to_value(&order.sla.min_availability_percent_milli)?,
        );
        root.insert(
            "sla_min_por_success_percent_milli".into(),
            json::to_value(&order.sla.min_por_success_percent_milli)?,
        );
        root.insert(
            "metadata".into(),
            metadata_entries_to_array(&order.metadata),
        );
        Ok(Value::Object(root))
    }

    fn metadata_entries_to_array(entries: &[CapacityMetadataEntry]) -> Value {
        let mut out = Vec::with_capacity(entries.len());
        for entry in entries {
            let mut item = Map::new();
            item.insert("key".into(), Value::String(entry.key.clone()));
            item.insert("value".into(), Value::String(entry.value.clone()));
            out.push(Value::Object(item));
        }
        Value::Array(out)
    }

    pub fn replication_release_to_value(
        status: &str,
        release: &sorafs_node::capacity::ReplicationRelease,
    ) -> Result<Value, json::Error> {
        let mut root = Map::new();
        root.insert("status".into(), Value::String(status.to_string()));
        root.insert(
            "order_id_hex".into(),
            Value::String(hex::encode(release.order_id)),
        );
        root.insert(
            "provider_id_hex".into(),
            Value::String(hex::encode(release.provider_id)),
        );
        root.insert(
            "released_gib".into(),
            json::to_value(&release.released_gib)?,
        );
        root.insert(
            "remaining_total_gib".into(),
            json::to_value(&release.remaining_total_gib)?,
        );
        root.insert(
            "remaining_chunker_gib".into(),
            json::to_value(&release.remaining_chunker_gib)?,
        );
        root.insert(
            "remaining_lane_gib".into(),
            release
                .remaining_lane_gib
                .map(|value| json::to_value(&value))
                .transpose()?
                .unwrap_or(Value::Null),
        );
        root.insert(
            "lane".into(),
            release
                .lane
                .as_ref()
                .map(|lane| Value::String(lane.clone()))
                .unwrap_or(Value::Null),
        );
        Ok(Value::Object(root))
    }

    pub fn replication_release_ignored_value(order_id: &[u8; 32]) -> Result<Value, json::Error> {
        let mut root = Map::new();
        root.insert("status".into(), Value::String("ignored".into()));
        root.insert("order_id_hex".into(), Value::String(hex::encode(order_id)));
        root.insert("provider_id_hex".into(), Value::Null);
        root.insert("released_gib".into(), json::to_value(&0u64)?);
        root.insert("remaining_total_gib".into(), json::to_value(&0u64)?);
        root.insert("remaining_chunker_gib".into(), json::to_value(&0u64)?);
        root.insert("remaining_lane_gib".into(), Value::Null);
        root.insert("lane".into(), Value::Null);
        Ok(Value::Object(root))
    }
}

#[cfg(test)]
mod deploy_tests {
    use base64::Engine as _;

    use super::*;

    fn minimal_ivm_program(abi_version: u8) -> Vec<u8> {
        let mut code = Vec::new();
        code.extend_from_slice(&ivm::encoding::wide::encode_halt().to_le_bytes());
        let meta = ivm::ProgramMetadata {
            version_major: 1,
            version_minor: 0,
            mode: 0,
            vector_length: 0,
            max_cycles: 0,
            abi_version,
        };
        let mut out = meta.encode();
        out.extend_from_slice(&code);
        out
    }

    #[tokio::test]
    #[cfg(feature = "app_api")]
    async fn deploy_endpoint_returns_hashes() {
        // Minimal in-memory state and queue
        let kura = iroha_core::kura::Kura::blank_kura_for_testing();
        let query = iroha_core::query::store::LiveQueryStore::start_test();
        let state = std::sync::Arc::new(iroha_core::state::State::new_for_testing(
            iroha_core::state::World::default(),
            kura,
            query,
        ));
        let events: iroha_core::EventsSender = tokio::sync::broadcast::channel(8).0;
        let queue_cfg = iroha_config::parameters::actual::Queue::default();
        let queue = std::sync::Arc::new(iroha_core::queue::Queue::from_config(queue_cfg, events));
        let chain_id = Arc::new("chain".parse().unwrap());

        // Build minimal program and request
        let prog = minimal_ivm_program(1);
        let code_b64 = base64::engine::general_purpose::STANDARD.encode(&prog);
        let kp = iroha_crypto::KeyPair::random();
        let req = DeployContractDto {
            authority: iroha_data_model::account::AccountId::of(kp.public_key().clone()),
            private_key: iroha_data_model::prelude::ExposedPrivateKey(kp.private_key().clone()),
            code_b64,
        };

        #[cfg(feature = "telemetry")]
        let telemetry = MaybeTelemetry::for_tests();
        #[cfg(not(feature = "telemetry"))]
        let telemetry = MaybeTelemetry::disabled();

        let resp = handle_post_contract_deploy(
            Arc::clone(&chain_id),
            queue,
            state,
            telemetry,
            NoritoJson(req),
        )
        .await
        .expect("handler ok")
        .into_response();
        assert_eq!(resp.status(), axum::http::StatusCode::OK);
        let bytes = http_body_util::BodyExt::collect(resp.into_body())
            .await
            .unwrap()
            .to_bytes();
        let v: norito::json::Value = norito::json::from_slice(&bytes).unwrap();
        assert_eq!(
            v.get("ok").and_then(norito::json::Value::as_bool),
            Some(true)
        );
        let ch = v
            .get("code_hash_hex")
            .and_then(norito::json::Value::as_str)
            .unwrap_or("");
        let ah = v
            .get("abi_hash_hex")
            .and_then(norito::json::Value::as_str)
            .unwrap_or("");
        assert_eq!(ch.len(), 64);
        assert_eq!(ah.len(), 64);
    }
}

#[cfg(test)]
mod soradns_tests {
    use std::{str::FromStr, sync::Arc};

    use iroha_core::{
        kura::Kura,
        query::store::LiveQueryStore,
        state::{State, World},
    };
    use iroha_crypto::{KeyPair, Signature};
    use iroha_data_model::{
        block::BlockHeader,
        events::data::{DataEvent, soradns::SoradnsDirectoryEvent},
        ipfs::IpfsPath,
        soradns::{DIRECTORY_RECORD_VERSION_V1, ResolverDirectoryRecordV1},
    };
    use nonzero_ext::nonzero;

    use super::*;

    fn make_state() -> Arc<State> {
        let kura = Kura::blank_kura_for_testing();
        let query = LiveQueryStore::start_test();
        Arc::new(State::new_for_testing(World::new(), kura, query))
    }

    fn block_header() -> BlockHeader {
        BlockHeader::new(nonzero!(1_u64), None, None, None, 0, 0)
    }

    fn sample_record() -> ResolverDirectoryRecordV1 {
        let keys = KeyPair::random();
        ResolverDirectoryRecordV1 {
            root_hash: [0x11; 32],
            record_version: DIRECTORY_RECORD_VERSION_V1,
            created_at_ms: 1_111,
            rad_count: 1,
            directory_json_sha256: [0x22; 32],
            previous_root: None,
            published_at_block: 42,
            published_at_unix: 65,
            proof_manifest_cid: IpfsPath::from_str(
                "/ipfs/bafyreiayresolversnapshotaaaaaaaaaaaaaaa",
            )
            .expect("cid"),
            builder_public_key: keys.public_key().clone(),
            builder_signature: Signature::from_bytes(&[0; 64]),
        }
    }

    #[test]
    #[cfg(feature = "app_api")]
    fn soradns_directory_latest_returns_not_found_when_empty() {
        use iroha_data_model::{ValidationFail, query::error::QueryExecutionFail};

        let state = make_state();
        let err = handle_v1_soradns_directory_latest(Arc::clone(&state)).unwrap_err();
        match err {
            Error::Query(ValidationFail::QueryFailed(QueryExecutionFail::NotFound)) => {}
            other => panic!("unexpected error variant: {other:?}"),
        }
    }

    #[test]
    #[cfg(feature = "app_api")]
    fn soradns_directory_latest_returns_record() {
        let state = make_state();
        let mut block = state.block(block_header());
        let mut tx = block.transaction();

        let record = sample_record();
        {
            let world = tx.world_mut_for_testing();
            world
                .soradns_directory_records_mut_for_testing()
                .insert(record.root_hash, record.clone());
            *world.soradns_directory_latest_mut_for_testing().get_mut() = Some(record.root_hash);
        }

        tx.apply();
        block.commit().expect("commit block");
        let view = state.view();
        assert_eq!(
            *view.world().soradns_directory_latest(),
            Some(record.root_hash)
        );
        assert!(
            view.world()
                .soradns_directory_records()
                .get(&record.root_hash)
                .is_some(),
            "record should be persisted in soradns directory store"
        );
        drop(view);

        let NoritoJsonBody(value) =
            handle_v1_soradns_directory_latest(Arc::clone(&state)).expect("directory record");
        let Value::Object(map) = value else {
            panic!("expected JSON object for directory payload");
        };
        let expected_hex = hex::encode(record.root_hash);
        assert_eq!(
            map.get("directory_id_hex").and_then(Value::as_str),
            Some(expected_hex.as_str())
        );
        let record_value = map
            .get("record")
            .cloned()
            .expect("record field should exist");
        let decoded: ResolverDirectoryRecordV1 =
            norito::json::from_value(record_value).expect("decode record");
        assert_eq!(decoded.root_hash, record.root_hash);
    }

    #[test]
    #[cfg(feature = "app_api")]
    fn convert_soradns_event_encodes_payload() {
        use iroha_data_model::soradns::DirectoryRevokedEventV1;

        let event = SoradnsDirectoryEvent::Revoked(DirectoryRevokedEventV1 {
            resolver_id: [0x44; 32],
            reason: RadRevokeReason::GovernanceAction,
            block_height: 99,
        });
        let data = DataEvent::Soradns(event);
        let shared = SharedDataEvent::from(data);
        let value = super::convert_soradns_event(&EventBox::Data(shared)).expect("converted event");
        let Value::Object(map) = value else {
            panic!("event should be JSON object");
        };
        assert_eq!(map.get("event").and_then(Value::as_str), Some("revoked"));
        let payload = map
            .get("payload")
            .and_then(Value::as_object)
            .expect("payload map");
        assert_eq!(
            payload.get("reason").and_then(Value::as_str),
            Some("governance_action")
        );
        let expected_hex = hex::encode([0x44; 32]);
        assert_eq!(
            payload.get("resolver_id_hex").and_then(Value::as_str),
            Some(expected_hex.as_str())
        );
    }
}

#[cfg(test)]
mod sorafs_pin_tests {
    use iroha_data_model::prelude as dm;

    use super::*;

    fn default_manifest() -> ManifestV1 {
        use sorafs_manifest::{ManifestBuilder, PinPolicy};
        ManifestBuilder::new()
            .root_cid(vec![0x01, 0x55, 0xaa])
            .dag_codec(sorafs_manifest::DagCodecId(
                sorafs_manifest::MANIFEST_DAG_CODEC,
            ))
            .chunking_from_registry(sorafs_manifest::ProfileId(1))
            .content_length(1024)
            .car_digest([0xAB; 32])
            .car_size(4096)
            .pin_policy(PinPolicy {
                min_replicas: 3,
                storage_class: sorafs_manifest::StorageClass::Hot,
                retention_epoch: 42,
            })
            .governance(sorafs_manifest::GovernanceProofs {
                council_signatures: vec![sorafs_manifest::CouncilSignature {
                    signer: [0x11; 32],
                    signature: vec![0x22; 64],
                }],
            })
            .build()
            .expect("manifest")
    }

    #[tokio::test]
    #[cfg(feature = "app_api")]
    async fn register_manifest_handler_accepts_request() {
        let kura = iroha_core::kura::Kura::blank_kura_for_testing();
        let query = iroha_core::query::store::LiveQueryStore::start_test();
        let state = std::sync::Arc::new(iroha_core::state::State::new_for_testing(
            iroha_core::state::World::default(),
            kura,
            query,
        ));
        let events: iroha_core::EventsSender = tokio::sync::broadcast::channel(8).0;
        let queue_cfg = iroha_config::parameters::actual::Queue::default();
        let queue = std::sync::Arc::new(iroha_core::queue::Queue::from_config(queue_cfg, events));
        let chain_id: Arc<iroha_data_model::ChainId> =
            Arc::new("chain".parse().expect("parse chain id"));

        let manifest = default_manifest();
        let manifest_digest = manifest.digest().expect("manifest digest");
        let manifest_digest_hex = hex::encode(manifest_digest.as_bytes());
        let descriptor = sorafs_manifest::chunker_registry::default_descriptor();
        let policy = manifest.pin_policy.clone();
        let pin_policy_dto = PinPolicyDto {
            min_replicas: policy.min_replicas,
            storage_class: match policy.storage_class {
                ManifestStorageClass::Hot => PinPolicyStorageClassDto::Hot,
                ManifestStorageClass::Warm => PinPolicyStorageClassDto::Warm,
                ManifestStorageClass::Cold => PinPolicyStorageClassDto::Cold,
            },
            retention_epoch: policy.retention_epoch,
        };
        let kp = iroha_crypto::KeyPair::random();
        let authority = dm::AccountId::new(kp.public_key().clone());
        let req = RegisterPinManifestDto {
            authority,
            private_key: dm::ExposedPrivateKey(kp.private_key().clone()),
            chunker_profile_id: descriptor.id.0,
            chunker_namespace: descriptor.namespace.to_string(),
            chunker_name: descriptor.name.to_string(),
            chunker_semver: descriptor.semver.to_string(),
            chunker_multihash_code: descriptor.multihash_code,
            pin_policy: pin_policy_dto,
            manifest_digest_hex,
            chunk_digest_sha3_256_hex: hex::encode([0xCD; 32]),
            submitted_epoch: 5,
            alias: None,
            successor_of_hex: None,
        };

        #[cfg(feature = "telemetry")]
        let telemetry = MaybeTelemetry::for_tests();
        #[cfg(not(feature = "telemetry"))]
        let telemetry = MaybeTelemetry::disabled();

        let resp = handle_post_sorafs_register_manifest(
            Arc::clone(&chain_id),
            queue,
            state,
            telemetry,
            NoritoJson(req),
        )
        .await
        .expect("handler ok")
        .into_response();
        assert_eq!(resp.status(), axum::http::StatusCode::OK);
        let bytes = http_body_util::BodyExt::collect(resp.into_body())
            .await
            .unwrap()
            .to_bytes();
        let v: norito::json::Value = norito::json::from_slice(&bytes).unwrap();
        assert!(v.get("manifest_digest_hex").is_some());
        assert_eq!(
            v.get("submitted_epoch")
                .and_then(norito::json::Value::as_u64),
            Some(5)
        );
    }

    #[tokio::test]
    async fn register_manifest_accepts_alias_binding() {
        use crate::{mk_app_state_for_tests, routing::PinPolicyStorageClassDto};

        let app = mk_app_state_for_tests();
        let chain_id = Arc::clone(&app.chain_id);
        let queue = Arc::clone(&app.queue);
        let state = Arc::clone(&app.state);
        let manifest = default_manifest();
        let manifest_digest = manifest.digest().expect("manifest digest");
        let manifest_digest_hex = hex::encode(manifest_digest.as_bytes());
        let descriptor = sorafs_manifest::chunker_registry::default_descriptor();
        let policy = manifest.pin_policy.clone();
        let pin_policy_dto = PinPolicyDto {
            min_replicas: policy.min_replicas,
            storage_class: match policy.storage_class {
                ManifestStorageClass::Hot => PinPolicyStorageClassDto::Hot,
                ManifestStorageClass::Warm => PinPolicyStorageClassDto::Warm,
                ManifestStorageClass::Cold => PinPolicyStorageClassDto::Cold,
            },
            retention_epoch: policy.retention_epoch,
        };
        let kp = iroha_crypto::KeyPair::random();
        let authority = dm::AccountId::new(kp.public_key().clone());
        let proof_bytes = b"alias-proof";
        let req = RegisterPinManifestDto {
            authority,
            private_key: dm::ExposedPrivateKey(kp.private_key().clone()),
            chunker_profile_id: descriptor.id.0,
            chunker_namespace: descriptor.namespace.to_string(),
            chunker_name: descriptor.name.to_string(),
            chunker_semver: descriptor.semver.to_string(),
            chunker_multihash_code: descriptor.multihash_code,
            pin_policy: pin_policy_dto,
            manifest_digest_hex,
            chunk_digest_sha3_256_hex: hex::encode([0xCD; 32]),
            submitted_epoch: 5,
            alias: Some(PinAliasDto {
                namespace: "sora".into(),
                name: "docs".into(),
                proof_base64: base64::engine::general_purpose::STANDARD
                    .encode(proof_bytes.as_slice()),
            }),
            successor_of_hex: None,
        };

        #[cfg(feature = "telemetry")]
        let telemetry = app.telemetry.clone();
        #[cfg(not(feature = "telemetry"))]
        let telemetry = app.telemetry.clone();

        let resp = handle_post_sorafs_register_manifest(
            Arc::clone(&chain_id),
            queue,
            state,
            telemetry,
            NoritoJson(req),
        )
        .await
        .expect("handler ok")
        .into_response();
        assert_eq!(resp.status(), axum::http::StatusCode::OK);
        let bytes = http_body_util::BodyExt::collect(resp.into_body())
            .await
            .unwrap()
            .to_bytes();
        let v: norito::json::Value = norito::json::from_slice(&bytes).unwrap();
        let alias = v
            .get("alias")
            .and_then(|value| value.as_object())
            .expect("alias response present");
        assert_eq!(
            alias.get("namespace").and_then(norito::json::Value::as_str),
            Some("sora")
        );
        assert_eq!(
            alias.get("name").and_then(norito::json::Value::as_str),
            Some("docs")
        );
        let expected_proof_b64 =
            base64::engine::general_purpose::STANDARD.encode(proof_bytes.as_slice());
        assert_eq!(
            alias
                .get("proof_base64")
                .and_then(norito::json::Value::as_str),
            Some(expected_proof_b64.as_str())
        );
    }
}

