    fn sample_por_artifacts() -> (PorChallengeV1, PorProofV1, AuditVerdictV1) {
        let descriptor = sorafs_manifest::chunker_registry::default_descriptor();
        let chunker_handle = format!(
            "{}.{}@{}",
            descriptor.namespace, descriptor.name, descriptor.semver
        );
        let manifest_digest = [0xB2; 32];
        let provider_id = [0xC3; 32];
        let epoch_id = 222;
        let drand_round = 333;
        let drand_randomness = [0xDD; 32];
        let vrf_output = [0xEE; 32];
        let seed = derive_challenge_seed(
            &drand_randomness,
            Some(&vrf_output),
            &manifest_digest,
            epoch_id,
        );
        let challenge_id =
            derive_challenge_id(&seed, &manifest_digest, &provider_id, epoch_id, drand_round);

        let challenge = PorChallengeV1 {
            version: POR_CHALLENGE_VERSION_V1,
            challenge_id,
            manifest_digest,
            provider_id,
            epoch_id,
            drand_round,
            drand_randomness,
            drand_signature: vec![0xF1; 96],
            vrf_output: Some(vrf_output),
            vrf_proof: Some(vec![0xF2; 80]),
            forced: false,
            chunking_profile: chunker_handle,
            seed,
            sample_tier: 1,
            sample_count: 1,
            sample_indices: vec![0],
            issued_at: 1_700_000_000,
            deadline_at: 1_700_000_600,
        };

        let proof = PorProofV1 {
            version: POR_PROOF_VERSION_V1,
            challenge_id: challenge.challenge_id,
            manifest_digest: challenge.manifest_digest,
            provider_id: challenge.provider_id,
            samples: vec![PorProofSampleV1 {
                sample_index: 0,
                chunk_offset: 0,
                chunk_size: 65_536,
                chunk_digest: [0x11; 32],
                leaf_digest: [0x22; 32],
            }],
            auth_path: vec![[0x33; 32]],
            signature: sorafs_manifest::provider_advert::AdvertSignature {
                algorithm: sorafs_manifest::provider_advert::SignatureAlgorithm::Ed25519,
                public_key: vec![0x44; 32],
                signature: vec![0x55; 64],
            },
            submitted_at: 1_700_000_100,
        };

        let verdict = AuditVerdictV1 {
            version: AUDIT_VERDICT_VERSION_V1,
            manifest_digest: challenge.manifest_digest,
            provider_id: challenge.provider_id,
            challenge_id: challenge.challenge_id,
            proof_digest: Some(proof.proof_digest()),
            outcome: AuditOutcomeV1::Success,
            failure_reason: None,
            decided_at: 1_700_000_200,
            auditor_signatures: vec![sorafs_manifest::provider_advert::AdvertSignature {
                algorithm: sorafs_manifest::provider_advert::SignatureAlgorithm::Ed25519,
                public_key: vec![0x66; 32],
                signature: vec![0x77; 64],
            }],
            metadata: Vec::new(),
        };

        (challenge, proof, verdict)
    }

    pub(super) fn build_por_challenge(
        salt: u8,
        provider_id: [u8; 32],
        epoch_id: u64,
        issued_at: u64,
    ) -> PorChallengeV1 {
        let descriptor = sorafs_manifest::chunker_registry::default_descriptor();
        let chunker_handle = format!(
            "{}.{}@{}",
            descriptor.namespace, descriptor.name, descriptor.semver
        );
        let manifest_digest = [salt; 32];
        let drand_randomness = [salt.wrapping_add(1); 32];
        let vrf_output = [salt.wrapping_add(2); 32];
        let drand_round = epoch_id + u64::from(salt);
        let seed = derive_challenge_seed(
            &drand_randomness,
            Some(&vrf_output),
            &manifest_digest,
            epoch_id,
        );
        let challenge_id =
            derive_challenge_id(&seed, &manifest_digest, &provider_id, epoch_id, drand_round);
        PorChallengeV1 {
            version: POR_CHALLENGE_VERSION_V1,
            challenge_id,
            manifest_digest,
            provider_id,
            epoch_id,
            drand_round,
            drand_randomness,
            drand_signature: vec![salt.wrapping_add(3); 96],
            vrf_output: Some(vrf_output),
            vrf_proof: Some(vec![salt.wrapping_add(4); 80]),
            forced: false,
            chunking_profile: chunker_handle,
            seed,
            sample_tier: 1,
            sample_count: 1,
            sample_indices: vec![0],
            issued_at,
            deadline_at: issued_at + 600,
        }
    }

