    fn seed_capacity_declaration(node: &sorafs_node::NodeHandle) {
        let declaration = sample_capacity_declaration();
        let payload = to_bytes(&declaration).expect("encode declaration");
        let record = CapacityDeclarationRecord::new(
            ProviderId::new(declaration.provider_id),
            payload,
            declaration.committed_capacity_gib,
            1,
            declaration.valid_from,
            declaration.valid_until,
            Metadata::default(),
        );
        node.record_capacity_declaration(&record)
            .expect("record declaration");
    }

    fn sorafs_node_with_temp_storage() -> (sorafs_node::NodeHandle, TempDir) {
        let temp_dir = tempfile::tempdir().expect("create temp dir");
        let cfg = StorageConfig::builder()
            .enabled(true)
            .data_dir(temp_dir.path().join("storage"))
            .build();
        (sorafs_node::NodeHandle::new(cfg), temp_dir)
    }

    fn seed_sample_deal(node: &sorafs_node::NodeHandle) -> (DealId, u64) {
        let provider = ProviderId::new([0xAA; 32]);
        let client = ClientId::new([0xBB; 32]);
        node.deposit_provider_bond(provider, 5_000_000_000);
        node.deposit_client_credit(client, 3_000_000_000);

        let activation_epoch = 1_700_000_000;
        let proposal = DealProposal {
            provider_id: provider,
            client_id: client,
            storage_class: StorageClass::Hot,
            capacity_gib: 4,
            start_epoch: activation_epoch,
            end_epoch: activation_epoch + 14,
            terms: DealTerms {
                storage_price_nano_per_gib_month: 200_000_000,
                egress_price_nano_per_gib: 50_000_000,
                settlement_window_epochs: 7,
                micropayment_probability_bps: 10_000,
                micropayment_payout_nano: 50_000_000,
            },
            metadata: Metadata::default(),
        };

        let record = node
            .open_deal(proposal, activation_epoch)
            .expect("open deal");
        (record.deal_id, activation_epoch)
    }

    #[tokio::test]
    async fn transaction_signature_limit_rejects_and_records_metrics() {
        let (state, queue, chain_id, telemetry) = test_state_components();

        #[cfg(feature = "telemetry")]
        let before = telemetry.metrics().await.torii_signature_limit_total.get();

        // Build a multisig transaction with more signatures than the default cap (16).
        let domain: dm::DomainId = "wonderland".parse().unwrap();
        let signers: Vec<_> = (0..17).map(|_| iroha_crypto::KeyPair::random()).collect();
        let members = signers
            .iter()
            .map(|kp| dm::MultisigMember::new(kp.public_key().clone(), 1).expect("member is valid"))
            .collect::<Vec<_>>();
        let policy = dm::MultisigPolicy::new(1, members).expect("policy");
        let authority = dm::ScopedAccountId::new_multisig(domain, policy);

        let tx = dm::TransactionBuilder::new((*chain_id).clone(), authority.into())
            .with_instructions([dm::Log::new(dm::Level::INFO, "too many signatures".into())])
            .sign_multisig(signers.iter().map(KeyPair::private_key));

        let result = handle_transaction_with_metrics(
            Arc::clone(&chain_id),
            Arc::clone(&queue),
            Arc::clone(&state),
            tx,
            telemetry.clone(),
            iroha_torii_shared::uri::TRANSACTION,
        )
        .await;

        assert!(
            matches!(
                result,
                Err(Error::AcceptTransaction(
                    AcceptTransactionFail::TransactionLimit(_)
                ))
            ),
            "expected signature-limit rejection, got {result:?}"
        );

        #[cfg(feature = "telemetry")]
        {
            let after = telemetry.metrics().await.torii_signature_limit_total.get();
            assert_eq!(
                after,
                before + 1,
                "signature-limit counter should increment on rejection"
            );
        }
    }

