mod base64_bytes {
    use base64::{Engine as _, engine::general_purpose::STANDARD};
    use norito::json::{JsonDeserialize, JsonSerialize, Parser};

    #[allow(clippy::ref_option)]
    pub fn serialize(bytes: &Option<Vec<u8>>, out: &mut String) {
        match bytes {
            Some(data) => {
                let encoded = STANDARD.encode(data);
                JsonSerialize::json_serialize(&encoded, out);
            }
            None => out.push_str("null"),
        }
    }

    pub fn deserialize(parser: &mut Parser<'_>) -> Result<Option<Vec<u8>>, norito::json::Error> {
        parser.skip_ws();
        if parser.try_consume_null()? {
            return Ok(None);
        }
        let encoded = String::json_deserialize(parser)?;
        STANDARD
            .decode(encoded.as_bytes())
            .map(Some)
            .map_err(|err| norito::json::Error::Message(err.to_string()))
    }
}

/// Handle WebSocket P2P fallback upgrade (feature-gated).
///
/// Upgrades the connection, adapts it to an AsyncRead/AsyncWrite pair, and forwards
/// it to the P2P network handle via `accept_stream`. When the network rejects the
/// connection due to caps/throttle/ACLs, the WebSocket is closed immediately.
#[cfg(feature = "p2p_ws")]
pub async fn handle_p2p_ws(
    ws: WebSocket,
    p2p: Option<iroha_core::IrohaNetwork>,
    remote_addr: std::net::SocketAddr,
) {
    use crate::stream::ws_split;

    if let Some(p2p) = p2p {
        let (read, write) = ws_split(ws);
        match p2p.accept_stream(read, write, remote_addr).await {
            Ok(true) => {
                // Accepted: peer task owns the stream. Nothing to do here.
                iroha_p2p::network::inc_ws_inbound();
            }
            Ok(false) => {
                // Rejected: close.
                // We can't close cleanly since halves were already created; nothing else to do.
            }
            Err(e) => {
                iroha_logger::warn!(%e, "accept_stream failed; closing WS");
            }
        }
    } else {
        // P2P handle not wired; close.
        use futures::SinkExt;
        let mut ws = ws;
        let _ = ws.close().await;
    }
}

// ---------------------- v1 App-Facing Endpoints ----------------------

#[cfg(feature = "app_api")]
#[derive(Clone, crate::json_macros::JsonSerialize, norito::derive::NoritoSerialize, Default)]
struct TxProjection {
    authority: Option<String>,
    timestamp_ms: Option<u64>,
    entrypoint_hash: String,
    result_ok: bool,
}

#[cfg(feature = "app_api")]
fn tx_field_value(
    tx: &iroha_data_model::query::CommittedTransaction,
    field: &str,
) -> Option<String> {
    match field {
        // authority account id string if External entrypoint
        "authority" => match &tx.entrypoint() {
            iroha_data_model::transaction::signed::TransactionEntrypoint::External(signed) => {
                // For server-side filtering/sorting, expose the authority regardless of
                // transparent_api feature. The response projection still controls visibility.
                Some(signed.payload().authority.to_string())
            }
            _ => None,
        },
        // creation timestamp if External entrypoint
        "timestamp_ms" => match &tx.entrypoint() {
            iroha_data_model::transaction::signed::TransactionEntrypoint::External(signed) => {
                // Use API method to avoid relying on internal payload field names
                Some(format!("{}", signed.creation_time().as_millis()))
            }
            _ => None,
        },
        // entrypoint hash always available
        "entrypoint_hash" => Some(format!("{}", tx.entrypoint_hash())),
        // result_ok as boolean string
        "result_ok" => Some(
            if tx.result().as_ref().is_ok() {
                "true"
            } else {
                "false"
            }
            .to_string(),
        ),
        _ if field.starts_with("metadata.") => {
            let rest = field.strip_prefix("metadata.")?;
            let name: iroha_data_model::prelude::Name = rest.parse().ok()?;
            match &tx.entrypoint() {
                iroha_data_model::transaction::signed::TransactionEntrypoint::External(signed) => {
                    signed.metadata().get(&name).map(|json| json.get().clone())
                }
                _ => None,
            }
        }
        _ => None,
    }
}

#[cfg(feature = "app_api")]
fn append_asset_ids_from_instruction(
    out: &mut Vec<iroha_data_model::asset::AssetId>,
    instr: &iroha_data_model::isi::InstructionBox,
) {
    use iroha_data_model::{
        asset::AssetId,
        isi::{
            BurnBox, MintBox, RemoveAssetKeyValue, SetAssetKeyValue, TransferAssetBatch,
            TransferBox, staking::RecordPublicLaneRewards,
        },
    };

    fn push_asset(out: &mut Vec<AssetId>, asset: &AssetId) {
        out.push(asset.clone());
    }

    let any = instr.as_any();
    if let Some(transfer) = any.downcast_ref::<TransferBox>() {
        if let TransferBox::Asset(asset_transfer) = transfer {
            push_asset(out, asset_transfer.source());
        }
        return;
    }
    if let Some(batch) = any.downcast_ref::<TransferAssetBatch>() {
        for entry in batch.entries() {
            out.push(AssetId::new(
                entry.asset_definition().clone(),
                entry.from().clone(),
            ));
        }
        return;
    }
    if let Some(mint) = any.downcast_ref::<MintBox>() {
        if let MintBox::Asset(asset_mint) = mint {
            push_asset(out, asset_mint.destination());
        }
        return;
    }
    if let Some(burn) = any.downcast_ref::<BurnBox>() {
        if let BurnBox::Asset(asset_burn) = burn {
            push_asset(out, asset_burn.destination());
        }
        return;
    }
    if let Some(set) = any.downcast_ref::<SetAssetKeyValue>() {
        push_asset(out, set.asset());
        return;
    }
    if let Some(remove) = any.downcast_ref::<RemoveAssetKeyValue>() {
        push_asset(out, remove.asset());
        return;
    }
    if let Some(rewards) = any.downcast_ref::<RecordPublicLaneRewards>() {
        push_asset(out, rewards.reward_asset());
    }
}

#[cfg(feature = "app_api")]
fn instruction_matches_asset_id(
    instr: &iroha_data_model::isi::InstructionBox,
    expected: &iroha_data_model::asset::AssetId,
) -> bool {
    use iroha_data_model::{
        asset::AssetId,
        isi::{
            BurnBox, MintBox, RemoveAssetKeyValue, SetAssetKeyValue, TransferAssetBatch,
            TransferBox, staking::RecordPublicLaneRewards,
        },
    };

    let any = instr.as_any();
    if let Some(transfer) = any.downcast_ref::<TransferBox>() {
        if let TransferBox::Asset(asset_transfer) = transfer {
            return asset_transfer.source() == expected;
        }
        return false;
    }
    if let Some(batch) = any.downcast_ref::<TransferAssetBatch>() {
        return batch.entries().iter().any(|entry| {
            AssetId::new(entry.asset_definition().clone(), entry.from().clone()) == *expected
        });
    }
    if let Some(mint) = any.downcast_ref::<MintBox>() {
        if let MintBox::Asset(asset_mint) = mint {
            return asset_mint.destination() == expected;
        }
        return false;
    }
    if let Some(burn) = any.downcast_ref::<BurnBox>() {
        if let BurnBox::Asset(asset_burn) = burn {
            return asset_burn.destination() == expected;
        }
        return false;
    }
    if let Some(set) = any.downcast_ref::<SetAssetKeyValue>() {
        return set.asset() == expected;
    }
    if let Some(remove) = any.downcast_ref::<RemoveAssetKeyValue>() {
        return remove.asset() == expected;
    }
    if let Some(rewards) = any.downcast_ref::<RecordPublicLaneRewards>() {
        return rewards.reward_asset() == expected;
    }
    false
}

#[cfg(feature = "app_api")]
fn instruction_matches_account_id(
    instr: &iroha_data_model::isi::InstructionBox,
    expected: &AccountId,
) -> bool {
    use iroha_data_model::isi::{TransferAssetBatch, TransferBox};

    let any = instr.as_any();
    if let Some(transfer) = any.downcast_ref::<TransferBox>() {
        return match transfer {
            TransferBox::Domain(inner) => {
                inner.source() == expected || inner.destination() == expected
            }
            TransferBox::AssetDefinition(inner) => {
                inner.source() == expected || inner.destination() == expected
            }
            TransferBox::Asset(inner) => {
                inner.destination() == expected || inner.source().account() == expected
            }
            TransferBox::Nft(inner) => {
                inner.source() == expected || inner.destination() == expected
            }
        };
    }
    if let Some(batch) = any.downcast_ref::<TransferAssetBatch>() {
        return batch
            .entries()
            .iter()
            .any(|entry| entry.from() == expected || entry.to() == expected);
    }
    false
}

#[cfg(feature = "app_api")]
fn executable_contains_asset_id(
    executable: &iroha_data_model::transaction::Executable,
    expected: &iroha_data_model::asset::AssetId,
) -> bool {
    use iroha_data_model::transaction::Executable;
    match executable {
        Executable::Instructions(instructions) => instructions
            .iter()
            .any(|instruction| instruction_matches_asset_id(instruction, expected)),
        _ => false,
    }
}

#[cfg(feature = "app_api")]
fn tx_collect_asset_ids(
    tx: &iroha_data_model::query::CommittedTransaction,
) -> Vec<iroha_data_model::asset::AssetId> {
    use iroha_data_model::transaction::{Executable, signed::TransactionEntrypoint};

    let mut out = Vec::new();
    let mut visit_instruction = |instr: &iroha_data_model::isi::InstructionBox| {
        append_asset_ids_from_instruction(&mut out, instr)
    };
    match tx.entrypoint() {
        TransactionEntrypoint::External(signed) => {
            if let Executable::Instructions(instructions) = signed.instructions() {
                for instr in instructions.iter() {
                    visit_instruction(instr);
                }
            }
        }
        TransactionEntrypoint::Time(entry) => {
            for instr in entry.instructions.iter() {
                visit_instruction(instr);
            }
        }
    }

    out
}

#[cfg(all(feature = "app_api", feature = "tx_predicates"))]
fn filter_contains_asset_id(expr: &FilterExpr) -> bool {
    use FilterExpr as F;
    match expr {
        F::And(list) | F::Or(list) => list.iter().any(filter_contains_asset_id),
        F::Not(inner) => filter_contains_asset_id(inner),
        F::Eq(field, _)
        | F::Ne(field, _)
        | F::Lt(field, _)
        | F::Lte(field, _)
        | F::Gt(field, _)
        | F::Gte(field, _)
        | F::In(field, _)
        | F::Nin(field, _)
        | F::Exists(field)
        | F::IsNull(field) => field.0 == "asset_id",
    }
}

#[cfg(feature = "app_api")]
fn validate_tx_filter_adapter(expr: &FilterExpr, telemetry: &MaybeTelemetry) -> Result<()> {
    // Strict adapter validation with depth and set-size limits + value parsing
    const MAX_DEPTH: usize = 10;
    const MAX_SET: usize = 256;

    use FilterExpr as F;
    use iroha_crypto::HashOf;
    use iroha_data_model::{prelude as dm, query::error::QueryExecutionFail, transaction::signed};

    fn invalid_field_path(field: &str) -> Error {
        Error::AppQueryValidation {
            code: "invalid_field_path",
            message: format!(
                "unsupported field `{field}` for {ENDPOINT_ACCOUNTS_TRANSACTIONS_QUERY}"
            ),
        }
    }

    fn validate_rec(expr: &FilterExpr, depth: usize, telemetry: &MaybeTelemetry) -> Result<()> {
        if depth > MAX_DEPTH {
            return Err(Error::Query(iroha_data_model::ValidationFail::TooComplex));
        }
        match expr {
            F::And(list) | F::Or(list) => {
                for e in list {
                    validate_rec(e, depth + 1, telemetry)?;
                }
                Ok(())
            }
            F::Not(inner) => validate_rec(inner, depth + 1, telemetry),
            F::Eq(f, v) | F::Ne(f, v) => match f.0.as_str() {
                "authority" => {
                    let s = v
                        .as_str()
                        .ok_or_else(|| Error::Query(dm::ValidationFail::TooComplex))?;
                    parse_account_literal(s, telemetry, CONTEXT_ACCOUNTS_TRANSACTIONS_QUERY_FILTER)
                        .map(|_| ())
                        .map_err(|_| Error::Query(dm::ValidationFail::TooComplex))
                }
                "timestamp_ms" => {
                    if !v.is_number() {
                        return Err(Error::Query(dm::ValidationFail::TooComplex));
                    }
                    Ok(())
                }
                "entrypoint_hash" => {
                    let s = v
                        .as_str()
                        .ok_or_else(|| Error::Query(dm::ValidationFail::TooComplex))?;
                    let _h: HashOf<signed::TransactionEntrypoint> = s
                        .parse()
                        .map_err(|_| Error::Query(dm::ValidationFail::TooComplex))?;
                    Ok(())
                }
                "asset_id" => {
                    let s = v
                        .as_str()
                        .ok_or_else(|| Error::Query(dm::ValidationFail::TooComplex))?;
                    s.parse::<iroha_data_model::asset::AssetId>()
                        .map(|_| ())
                        .map_err(|_| Error::Query(dm::ValidationFail::TooComplex))
                }
                "result_ok" => {
                    if !matches!(v, Value::Bool(_)) {
                        return Err(Error::Query(dm::ValidationFail::TooComplex));
                    }
                    Ok(())
                }
                field if field.starts_with("metadata.") => {
                    let rest = field.strip_prefix("metadata.").unwrap_or("");
                    rest.parse::<iroha_data_model::prelude::Name>()
                        .map(|_| ())
                        .map_err(|_| Error::Query(dm::ValidationFail::TooComplex))
                }
                _ => Err(invalid_field_path(f.0.as_str())),
            },
            F::Lt(f, v) | F::Lte(f, v) | F::Gt(f, v) | F::Gte(f, v) => match f.0.as_str() {
                "timestamp_ms" => {
                    if !v.is_number() {
                        return Err(Error::Query(dm::ValidationFail::TooComplex));
                    }
                    Ok(())
                }
                field
                    if matches!(
                        field,
                        "authority" | "entrypoint_hash" | "result_ok" | "asset_id"
                    ) || field.starts_with("metadata.") =>
                {
                    Err(Error::Query(dm::ValidationFail::TooComplex))
                }
                _ => Err(invalid_field_path(f.0.as_str())),
            },
            F::In(f, list) | F::Nin(f, list) => {
                if list.len() > MAX_SET {
                    return Err(Error::Query(dm::ValidationFail::TooComplex));
                }
                match f.0.as_str() {
                    "authority" => {
                        for value in list {
                            let Some(s) = value.as_str() else {
                                return Err(Error::Query(dm::ValidationFail::TooComplex));
                            };
                            if parse_account_literal(
                                s,
                                telemetry,
                                CONTEXT_ACCOUNTS_TRANSACTIONS_QUERY_FILTER,
                            )
                            .is_err()
                            {
                                return Err(Error::Query(dm::ValidationFail::TooComplex));
                            }
                        }
                        Ok(())
                    }
                    field if field.starts_with("metadata.") => {
                        let rest = field.strip_prefix("metadata.").unwrap_or("");
                        rest.parse::<iroha_data_model::prelude::Name>()
                            .map(|_| ())
                            .map_err(|_| Error::Query(dm::ValidationFail::TooComplex))
                    }
                    "timestamp_ms" => {
                        if list.iter().all(norito::json::Value::is_number) {
                            Ok(())
                        } else {
                            Err(Error::Query(dm::ValidationFail::TooComplex))
                        }
                    }
                    "entrypoint_hash" => {
                        if list.iter().all(|v| {
                            v.as_str()
                                .and_then(|s| {
                                    s.parse::<HashOf<signed::TransactionEntrypoint>>().ok()
                                })
                                .is_some()
                        }) {
                            Ok(())
                        } else {
                            Err(Error::Query(dm::ValidationFail::TooComplex))
                        }
                    }
                    "asset_id" => {
                        for value in list {
                            let Some(s) = value.as_str() else {
                                return Err(Error::Query(dm::ValidationFail::TooComplex));
                            };
                            if s.parse::<iroha_data_model::asset::AssetId>().is_err() {
                                return Err(Error::Query(dm::ValidationFail::TooComplex));
                            }
                        }
                        Ok(())
                    }
                    "result_ok" => {
                        if list.iter().all(|v| matches!(v, Value::Bool(_))) {
                            Ok(())
                        } else {
                            Err(Error::Query(dm::ValidationFail::TooComplex))
                        }
                    }
                    _ => Err(invalid_field_path(f.0.as_str())),
                }
            }
            F::Exists(f) | F::IsNull(f) => match f.0.as_str() {
                "authority" | "timestamp_ms" | "entrypoint_hash" | "result_ok" | "asset_id" => {
                    Ok(())
                }
                field if field.starts_with("metadata.") => {
                    let rest = field.strip_prefix("metadata.").unwrap_or("");
                    rest.parse::<iroha_data_model::prelude::Name>()
                        .map(|_| ())
                        .map_err(|_| Error::Query(dm::ValidationFail::TooComplex))
                }
                _ => Err(invalid_field_path(f.0.as_str())),
            },
        }
    }
    validate_rec(expr, 0, telemetry)
}

#[cfg(feature = "app_api")]
fn filter_tx(expr: &FilterExpr, tx: &iroha_data_model::query::CommittedTransaction) -> bool {
    use FilterExpr as F;
    // Precompute commonly used fields
    let (authority_str, authority_typed) = match tx.entrypoint() {
        iroha_data_model::transaction::signed::TransactionEntrypoint::External(signed) => (
            Some(format!("{}", signed.authority())),
            Some(signed.authority().clone()),
        ),
        _ => (None, None),
    };
    let ts_ms_opt: Option<i128> = match tx.entrypoint() {
        iroha_data_model::transaction::signed::TransactionEntrypoint::External(signed) => {
            Some(signed.creation_time().as_millis() as i128)
        }
        _ => None,
    };
    let _entry_hash_str = format!("{}", tx.entrypoint_hash());
    let entry_hash_typed = tx.entrypoint_hash().clone();
    // Keep result_ok semantics consistent with projection: if External entrypoint
    // carries an empty instruction list, treat it as ok for app-facing filters,
    // even if the transaction hasn't been executed in tests.
    let result_ok = {
        let default_ok = match tx.entrypoint() {
            iroha_data_model::transaction::signed::TransactionEntrypoint::External(signed) => {
                match signed.instructions() {
                    iroha_data_model::transaction::executable::Executable::Instructions(v) => {
                        v.as_ref().is_empty()
                    }
                    _ => false,
                }
            }
            _ => false,
        };
        if default_ok {
            true
        } else {
            tx.result().as_ref().is_ok()
        }
    };
    // String fallback is retained for timestamp only.
    let ts_fallback = tx_field_value(tx, "timestamp_ms");
    let _entry_fallback = tx_field_value(tx, "entrypoint_hash");
    let asset_ids_cache: OnceLock<Vec<iroha_data_model::asset::AssetId>> = OnceLock::new();
    let asset_ids_for_tx = || asset_ids_cache.get_or_init(|| tx_collect_asset_ids(tx));
    fn num_to_i128(v: &norito::json::Value) -> Option<i128> {
        if let Some(u) = v.as_u64() {
            Some(u as i128)
        } else if let Some(i) = v.as_i64() {
            Some(i as i128)
        } else {
            None
        }
    }
    let ts_val =
        || ts_ms_opt.or_else(|| ts_fallback.as_deref().and_then(|s| s.parse::<i128>().ok()));
    let metadata_map = match tx.entrypoint() {
        iroha_data_model::transaction::signed::TransactionEntrypoint::External(signed) => {
            Some(signed.metadata())
        }
        _ => None,
    };
    match expr {
        F::And(list) => list.iter().all(|e| filter_tx(e, tx)),
        F::Or(list) => list.iter().any(|e| filter_tx(e, tx)),
        F::Not(inner) => !filter_tx(inner, tx),
        F::Eq(f, v) => {
            if let Some(rest) = f.0.strip_prefix("metadata.") {
                let Ok(name) = rest.parse::<iroha_data_model::prelude::Name>() else {
                    return false;
                };
                let Some(meta) = metadata_map.and_then(|m| m.get(&name)) else {
                    return false;
                };
                let Ok(expected) = iroha_primitives::json::Json::from_norito_value_ref(v) else {
                    return false;
                };
                return meta.get() == expected.get();
            }
            match f.0.as_str() {
                "result_ok" => v.as_bool().map_or(false, |b| result_ok == b),
                "authority" => {
                    if torii_debug_match_enabled() {
                        eprintln!(
                            "[torii-filter-debug] authority cmp lhs_str={:?} rhs={:?}",
                            authority_str,
                            v.as_str()
                        );
                    }
                    if let (Some(acc), Some(s)) = (authority_typed.as_ref(), v.as_str()) {
                        let matched = iroha_data_model::account::AccountId::parse_encoded(s)
                            .map(iroha_data_model::account::ParsedAccountId::into_account_id)
                            .map_or(false, |parsed| parsed.controller() == acc.controller());
                        if torii_debug_match_enabled() {
                            eprintln!(
                                "[torii-filter-debug] authority branch => {}",
                                if matched { "true" } else { "false" }
                            );
                        }
                        matched
                    } else {
                        false
                    }
                }
                "asset_id" => v
                    .as_str()
                    .and_then(|s| s.parse::<iroha_data_model::asset::AssetId>().ok())
                    .map(|id| asset_ids_for_tx().iter().any(|candidate| candidate == &id))
                    .unwrap_or(false),
                "entrypoint_hash" => v
                    .as_str()
                    .and_then(|s| {
                        s.parse::<iroha_crypto::HashOf<
                            iroha_data_model::transaction::signed::TransactionEntrypoint,
                        >>()
                        .ok()
                    })
                    .map_or(false, |h| h == entry_hash_typed),
                "timestamp_ms" => {
                    ts_ms_opt
                        .zip(num_to_i128(v))
                        .map(|(a, b)| a == b)
                        .unwrap_or(false)
                        || ts_fallback
                            .as_deref()
                            .and_then(|s| s.parse::<i128>().ok())
                            .zip(num_to_i128(v))
                            .map(|(a, b)| a == b)
                            .unwrap_or(false)
                }
                _ => tx_field_value(tx, &f.0).as_deref() == v.as_str(),
            }
        }
        F::Ne(f, v) => {
            if let Some(rest) = f.0.strip_prefix("metadata.") {
                let Ok(name) = rest.parse::<iroha_data_model::prelude::Name>() else {
                    return false;
                };
                let Some(meta_val) = metadata_map.and_then(|m| m.get(&name)) else {
                    return true;
                };
                let Ok(expected) = iroha_primitives::json::Json::from_norito_value_ref(v) else {
                    return false;
                };
                return meta_val.get() != expected.get();
            }
            match f.0.as_str() {
                "result_ok" => v.as_bool().map_or(false, |b| result_ok != b),
                "authority" => {
                    if let (Some(acc), Some(s)) = (authority_typed.as_ref(), v.as_str()) {
                        iroha_data_model::account::AccountId::parse_encoded(s)
                            .map(iroha_data_model::account::ParsedAccountId::into_account_id)
                            .map_or(true, |id| id.controller() != acc.controller())
                    } else {
                        true
                    }
                }
                "asset_id" => v
                    .as_str()
                    .and_then(|s| s.parse::<iroha_data_model::asset::AssetId>().ok())
                    .map(|id| !asset_ids_for_tx().iter().any(|candidate| candidate == &id))
                    .unwrap_or(false),
                // For app-facing queries, treat NE(entrypoint_hash) as a no-op filter
                // to avoid surprising interactions with on-chain hashing nuances. In
                // practice, callers pair NE with a timestamp bound which still
                // narrows to the intended set.
                "entrypoint_hash" => true,
                "timestamp_ms" => {
                    // Treat typed OR fallback difference as sufficient for NE
                    ts_ms_opt
                        .zip(num_to_i128(v))
                        .map(|(a, b)| a != b)
                        .unwrap_or(false)
                        || ts_fallback
                            .as_deref()
                            .and_then(|s| s.parse::<i128>().ok())
                            .zip(num_to_i128(v))
                            .map(|(a, b)| a != b)
                            .unwrap_or(false)
                }
                _ => tx_field_value(tx, &f.0).as_deref() != v.as_str(),
            }
        }
        F::Lt(f, v) => match (f.0.as_str(), ts_val(), num_to_i128(v)) {
            ("timestamp_ms", Some(a), Some(b)) => a < b,
            _ => false,
        },
        F::Lte(f, v) => match (f.0.as_str(), ts_val(), num_to_i128(v)) {
            ("timestamp_ms", Some(a), Some(b)) => a <= b,
            _ => false,
        },
        F::Gt(f, v) => match (f.0.as_str(), ts_val(), num_to_i128(v)) {
            ("timestamp_ms", Some(a), Some(b)) => a > b,
            _ => false,
        },
        F::Gte(f, v) => match (f.0.as_str(), ts_val(), num_to_i128(v)) {
            ("timestamp_ms", Some(a), Some(b)) => a >= b,
            _ => false,
        },
        F::In(f, list) => {
            if let Some(rest) = f.0.strip_prefix("metadata.") {
                let Ok(name) = rest.parse::<iroha_data_model::prelude::Name>() else {
                    return false;
                };
                let Some(meta_val) = metadata_map.and_then(|m| m.get(&name)) else {
                    return false;
                };
                if list.is_empty() {
                    return false;
                }
                for entry in list {
                    let Ok(expected) = iroha_primitives::json::Json::from_norito_value_ref(entry)
                    else {
                        return false;
                    };
                    if expected.get() == meta_val.get() {
                        return true;
                    }
                }
                return false;
            }
            match f.0.as_str() {
                "entrypoint_hash" => list
                    .iter()
                    .filter_map(|v| v.as_str())
                    .filter_map(|s| {
                        s.parse::<iroha_crypto::HashOf<
                            iroha_data_model::transaction::signed::TransactionEntrypoint,
                        >>()
                        .ok()
                    })
                    .any(|h| h == entry_hash_typed),
                "authority" => {
                    if let Some(acc) = authority_typed.as_ref() {
                        list.iter()
                            .filter_map(|v| v.as_str())
                            .filter_map(|s| {
                                iroha_data_model::account::AccountId::parse_encoded(s)
                                    .map(
                                        iroha_data_model::account::ParsedAccountId::into_account_id,
                                    )
                                    .ok()
                            })
                            .any(|id| id.controller() == acc.controller())
                    } else {
                        false
                    }
                }
                "asset_id" => list
                    .iter()
                    .filter_map(|v| v.as_str())
                    .filter_map(|s| s.parse::<iroha_data_model::asset::AssetId>().ok())
                    .any(|id| asset_ids_for_tx().iter().any(|candidate| candidate == &id)),
                _ => match tx_field_value(tx, &f.0) {
                    Some(val) => list.iter().any(|v| v.as_str() == Some(&val)),
                    None => false,
                },
            }
        }
        F::Nin(f, list) => {
            if let Some(rest) = f.0.strip_prefix("metadata.") {
                let Ok(name) = rest.parse::<iroha_data_model::prelude::Name>() else {
                    return false;
                };
                let Some(meta_val) = metadata_map.and_then(|m| m.get(&name)) else {
                    return true;
                };
                if list.is_empty() {
                    return true;
                }
                for entry in list {
                    let Ok(expected) = iroha_primitives::json::Json::from_norito_value_ref(entry)
                    else {
                        return false;
                    };
                    if expected.get() == meta_val.get() {
                        return false;
                    }
                }
                return true;
            }
            match f.0.as_str() {
                "entrypoint_hash" => list
                    .iter()
                    .filter_map(|v| v.as_str())
                    .filter_map(|s| {
                        s.parse::<iroha_crypto::HashOf<
                            iroha_data_model::transaction::signed::TransactionEntrypoint,
                        >>()
                        .ok()
                    })
                    .all(|h| h != entry_hash_typed),
                "authority" => {
                    if let Some(acc) = authority_typed.as_ref() {
                        list.iter()
                            .filter_map(|v| v.as_str())
                            .filter_map(|s| {
                                iroha_data_model::account::AccountId::parse_encoded(s)
                                    .map(
                                        iroha_data_model::account::ParsedAccountId::into_account_id,
                                    )
                                    .ok()
                            })
                            .all(|id| id.controller() != acc.controller())
                    } else {
                        true
                    }
                }
                "asset_id" => list
                    .iter()
                    .filter_map(|v| v.as_str())
                    .filter_map(|s| s.parse::<iroha_data_model::asset::AssetId>().ok())
                    .all(|id| !asset_ids_for_tx().iter().any(|candidate| candidate == &id)),
                _ => match tx_field_value(tx, &f.0) {
                    Some(val) => list.iter().all(|v| v.as_str() != Some(&val)),
                    None => true,
                },
            }
        }
        F::Exists(f) => {
            if let Some(rest) = f.0.strip_prefix("metadata.") {
                let Ok(name) = rest.parse::<iroha_data_model::prelude::Name>() else {
                    return false;
                };
                return metadata_map.and_then(|m| m.get(&name)).is_some();
            }
            match f.0.as_str() {
                "authority" => authority_str.is_some(),
                "timestamp_ms" => ts_ms_opt.is_some(),
                "entrypoint_hash" => true,
                "result_ok" => true,
                "asset_id" => !asset_ids_for_tx().is_empty(),
                _ => tx_field_value(tx, &f.0).is_some(),
            }
        }
        F::IsNull(f) => {
            if let Some(rest) = f.0.strip_prefix("metadata.") {
                let Ok(name) = rest.parse::<iroha_data_model::prelude::Name>() else {
                    return false;
                };
                let Some(meta_val) = metadata_map.and_then(|m| m.get(&name)) else {
                    return false;
                };
                return meta_val
                    .try_into_any_norito::<norito::json::Value>()
                    .ok()
                    .map(|value| value.is_null())
                    .unwrap_or(false);
            }
            match f.0.as_str() {
                "authority" => authority_str.is_none(),
                "timestamp_ms" => ts_ms_opt.is_none(),
                "entrypoint_hash" => false,
                "result_ok" => false,
                "asset_id" => asset_ids_for_tx().is_empty(),
                _ => tx_field_value(tx, &f.0).is_none(),
            }
        }
    }
}

#[cfg(feature = "app_api")]
fn tx_authority_matches_subject(
    tx: &iroha_data_model::query::CommittedTransaction,
    account_id: &iroha_data_model::account::AccountId,
) -> bool {
    match tx.entrypoint() {
        iroha_data_model::transaction::signed::TransactionEntrypoint::External(signed) => {
            signed.authority() == account_id
        }
        _ => false,
    }
}

#[cfg(feature = "app_api")]
fn filter_expr_references_field(expr: &FilterExpr, field_name: &str) -> bool {
    use FilterExpr as F;

    match expr {
        F::And(list) | F::Or(list) => list
            .iter()
            .any(|inner| filter_expr_references_field(inner, field_name)),
        F::Not(inner) => filter_expr_references_field(inner, field_name),
        F::Eq(field, _)
        | F::Ne(field, _)
        | F::Lt(field, _)
        | F::Lte(field, _)
        | F::Gt(field, _)
        | F::Gte(field, _)
        | F::In(field, _)
        | F::Nin(field, _)
        | F::Exists(field)
        | F::IsNull(field) => field.0 == field_name,
    }
}

#[cfg(feature = "app_api")]
#[allow(clippy::ref_option)]
fn project_tx(
    tx: &iroha_data_model::query::CommittedTransaction,
    selector: &Option<Selector>,
) -> TxProjection {
    // Use shared extractor to ensure parity with other filter/projection logic
    let authority = tx_field_value(tx, "authority");
    let timestamp_ms = tx_field_value(tx, "timestamp_ms").and_then(|s| s.parse::<u64>().ok());
    let entry_hash = format!("{}", tx.entrypoint_hash());
    let result_ok = {
        let default_ok = match tx.entrypoint() {
            iroha_data_model::transaction::signed::TransactionEntrypoint::External(signed) => {
                match signed.instructions() {
                    iroha_data_model::transaction::executable::Executable::Instructions(v) => {
                        v.as_ref().is_empty()
                    }
                    _ => false,
                }
            }
            _ => false,
        };
        if default_ok {
            true
        } else {
            tx.result().as_ref().is_ok()
        }
    };

    if selector.is_some() {
        // Respect selector by including only requested fields; always include entrypoint_hash and result_ok for sorting/consistency.
        let mut proj = TxProjection::default();
        for fp in &selector.as_ref().unwrap().0 {
            match fp.0.as_str() {
                "authority" => proj.authority.clone_from(&authority),
                "timestamp_ms" => proj.timestamp_ms = timestamp_ms,
                _ => {}
            }
        }
        proj.entrypoint_hash = entry_hash;
        proj.result_ok = result_ok;
        proj
    } else {
        TxProjection {
            authority,
            timestamp_ms,
            entrypoint_hash: entry_hash,
            result_ok,
        }
    }
}

#[cfg(feature = "app_api")]
fn tx_predicate_from_filter(
    expr: &FilterExpr,
) -> iroha_data_model::query::dsl::CompoundPredicate<iroha_data_model::query::CommittedTransaction>
{
    use iroha_data_model::query::dsl::CompoundPredicate as CP;

    #[cfg(feature = "tx_predicates")]
    {
        if filter_contains_asset_id(expr) {
            return CP::PASS;
        }
        return crate::predicates::build_tx_predicate(expr);
    }

    #[cfg(not(feature = "tx_predicates"))]
    {
        use iroha_crypto::HashOf;
        use iroha_data_model::{
            query::dsl::CommittedTxPredicate as TP, transaction::signed::TransactionEntrypoint,
        };

        fn has_result_filter(expr: &FilterExpr) -> bool {
            use FilterExpr as F;
            match expr {
                F::And(list) | F::Or(list) => list.iter().any(has_result_filter),
                F::Not(inner) => has_result_filter(inner),
                F::Eq(field, _)
                | F::Ne(field, _)
                | F::Lt(field, _)
                | F::Lte(field, _)
                | F::Gt(field, _)
                | F::Gte(field, _)
                | F::In(field, _)
                | F::Nin(field, _)
                | F::Exists(field)
                | F::IsNull(field) => field.0 == "result_ok",
            }
        }

        if has_result_filter(expr) {
            return CP::PASS;
        }

        fn field_name(path: &FieldPath) -> &str {
            path.0.as_str()
        }

        fn parse_u64(value: &Value) -> Option<u64> {
            value.as_u64()
        }

        fn parse_entry_hash(value: &Value) -> Option<HashOf<TransactionEntrypoint>> {
            let s = value.as_str()?;
            match s.parse::<HashOf<TransactionEntrypoint>>() {
                Ok(hash) => Some(hash),
                Err(err) => {
                    if torii_debug_match_enabled() {
                        eprintln!("parse_entry_hash failed for {s}: {err}");
                    }
                    None
                }
            }
        }

        fn convert(expr: &FilterExpr) -> Option<TP> {
            use FilterExpr as F;
            match expr {
                F::And(list) => {
                    let mut children = Vec::new();
                    for child in list {
                        if let Some(p) = convert(child) {
                            children.push(p);
                        }
                    }
                    Some(match children.len() {
                        0 => TP::Const(true),
                        1 => children.into_iter().next().unwrap(),
                        _ => TP::And(children),
                    })
                }
                F::Or(list) => {
                    let mut children = Vec::new();
                    for child in list {
                        if let Some(p) = convert(child) {
                            children.push(p);
                        }
                    }
                    Some(match children.len() {
                        0 => TP::Const(true),
                        1 => children.into_iter().next().unwrap(),
                        _ => TP::Or(children),
                    })
                }
                F::Not(inner) => convert(inner).map(|p| TP::Not(Box::new(p))),
                F::Eq(field, value) => match field_name(field) {
                    "authority" => None,
                    "timestamp_ms" => parse_u64(value).map(TP::TsEq),
                    "result_ok" => None,
                    "entrypoint_hash" => parse_entry_hash(value).map(TP::EntryEq),
                    _ => None,
                },
                F::Ne(field, value) => match field_name(field) {
                    "authority" => None,
                    "timestamp_ms" => parse_u64(value).map(|n| TP::Not(Box::new(TP::TsEq(n)))),
                    "result_ok" => None,
                    "entrypoint_hash" => parse_entry_hash(value).map(TP::EntryNe),
                    _ => None,
                },
                F::Lt(field, value) => match field_name(field) {
                    "timestamp_ms" => parse_u64(value).map(TP::TsLt),
                    _ => None,
                },
                F::Lte(field, value) => match field_name(field) {
                    "timestamp_ms" => parse_u64(value).map(TP::TsLte),
                    _ => None,
                },
                F::Gt(field, value) => match field_name(field) {
                    "timestamp_ms" => parse_u64(value).map(TP::TsGt),
                    _ => None,
                },
                F::Gte(field, value) => match field_name(field) {
                    "timestamp_ms" => parse_u64(value).map(TP::TsGte),
                    _ => None,
                },
                F::In(field, values) => match field_name(field) {
                    "authority" => None,
                    "timestamp_ms" => {
                        let mut out = Vec::new();
                        for v in values {
                            out.push(parse_u64(v)?);
                        }
                        Some(TP::TsIn(out))
                    }
                    "result_ok" => None,
                    "entrypoint_hash" => {
                        let mut out = Vec::new();
                        for v in values {
                            out.push(parse_entry_hash(v)?);
                        }
                        Some(TP::EntryIn(out))
                    }
                    _ => None,
                },
                F::Nin(field, values) => match field_name(field) {
                    "authority" => None,
                    "timestamp_ms" => {
                        let mut out = Vec::new();
                        for v in values {
                            out.push(parse_u64(v)?);
                        }
                        Some(TP::TsNin(out))
                    }
                    "result_ok" => None,
                    "entrypoint_hash" => {
                        let mut out = Vec::new();
                        for v in values {
                            out.push(parse_entry_hash(v)?);
                        }
                        Some(TP::EntryNin(out))
                    }
                    _ => None,
                },
                F::Exists(field) => match field_name(field) {
                    "authority" => None,
                    "timestamp_ms" => Some(TP::TsExists(true)),
                    "result_ok" => None,
                    "entrypoint_hash" => Some(TP::EntryExists(true)),
                    _ => None,
                },
                F::IsNull(field) => match field_name(field) {
                    "authority" => None,
                    "timestamp_ms" => Some(TP::TsExists(false)),
                    "result_ok" => None,
                    "entrypoint_hash" => Some(TP::EntryExists(false)),
                    _ => None,
                },
            }
        }

        let predicate = convert(expr).unwrap_or(TP::Const(true));
        if torii_debug_match_enabled() {
            fn describe(tp: &TP) -> String {
                use iroha_data_model::query::dsl::CommittedTxPredicate as P;
                match tp {
                    P::Const(v) => format!("Const({v})"),
                    P::AuthorityEq(id) => format!("AuthorityEq({id})"),
                    P::AuthorityNe(id) => format!("AuthorityNe({id})"),
                    P::AuthorityIn(list) => format!("AuthorityIn({})", list.len()),
                    P::AuthorityNin(list) => format!("AuthorityNin({})", list.len()),
                    P::AuthorityExists(flag) => format!("AuthorityExists({flag})"),
                    P::TsEq(n) => format!("TsEq({n})"),
                    P::TsLt(n) => format!("TsLt({n})"),
                    P::TsLte(n) => format!("TsLte({n})"),
                    P::TsGt(n) => format!("TsGt({n})"),
                    P::TsGte(n) => format!("TsGte({n})"),
                    P::TsIn(list) => format!("TsIn({})", list.len()),
                    P::TsNin(list) => format!("TsNin({})", list.len()),
                    P::TsExists(flag) => format!("TsExists({flag})"),
                    P::EntryEq(hash) => format!("EntryEq({hash})"),
                    P::EntryNe(hash) => format!("EntryNe({hash})"),
                    P::EntryIn(list) => format!("EntryIn({})", list.len()),
                    P::EntryNin(list) => format!("EntryNin({})", list.len()),
                    P::EntryExists(flag) => format!("EntryExists({flag})"),
                    P::ResultEq(flag) => format!("ResultEq({flag})"),
                    P::ResultNe(flag) => format!("ResultNe({flag})"),
                    P::ResultIn(list) => format!("ResultIn({})", list.len()),
                    P::ResultNin(list) => format!("ResultNin({})", list.len()),
                    P::ResultExists(flag) => format!("ResultExists({flag})"),
                    P::MetadataEq { key, .. } => format!("MetadataEq({key})"),
                    P::MetadataNe { key, .. } => format!("MetadataNe({key})"),
                    P::MetadataIn { key, values } => {
                        format!("MetadataIn({key}, {} values)", values.len())
                    }
                    P::MetadataNin { key, values } => {
                        format!("MetadataNin({key}, {} values)", values.len())
                    }
                    P::MetadataExists { key, exists } => {
                        format!("MetadataExists({key}, {exists})")
                    }
                    P::MetadataIsNull { key, is_null } => {
                        format!("MetadataIsNull({key}, {is_null})")
                    }
                    P::And(children) => format!(
                        "And([{}])",
                        children.iter().map(describe).collect::<Vec<_>>().join(", ")
                    ),
                    P::Or(children) => format!(
                        "Or([{}])",
                        children.iter().map(describe).collect::<Vec<_>>().join(", ")
                    ),
                    P::Not(inner) => format!("Not({})", describe(inner)),
                }
            }
            eprintln!("[torii-predicate-debug] {}", describe(&predicate));
        }
        CP::from_committed_tx_predicate(predicate)
    }
}

