/// GET /v1/sumeragi/rbc/sessions — RBC session snapshot
#[iroha_futures::telemetry_future]
pub async fn handle_v1_sumeragi_rbc_sessions() -> Result<impl IntoResponse> {
    let items = rbc_status::snapshot();
    let arr: Vec<norito::json::Value> = items
        .into_iter()
        .map(|s| {
            crate::json_object(vec![
                json_entry("block_hash", hash_to_hex(s.block_hash)),
                json_entry("height", s.height),
                json_entry("view", s.view),
                json_entry("total_chunks", s.total_chunks),
                json_entry("received_chunks", s.received_chunks),
                json_entry("ready_count", s.ready_count),
                json_entry("delivered", s.delivered),
                json_entry(
                    "payload_hash",
                    s.payload_hash.map(|h| hex::encode(h.as_ref())),
                ),
                json_entry("recovered", s.recovered_from_disk),
                json_entry("invalid", s.invalid),
                json_entry(
                    "lane_backlog",
                    norito::json::Value::Array(
                        s.lane_backlog
                            .iter()
                            .map(|entry| {
                                crate::json_object(vec![
                                    json_entry("lane_id", u64::from(entry.lane_id)),
                                    json_entry("tx_count", entry.tx_count),
                                    json_entry("total_chunks", entry.total_chunks),
                                    json_entry("pending_chunks", entry.pending_chunks),
                                    json_entry("rbc_bytes_total", entry.rbc_bytes_total),
                                ])
                            })
                            .collect(),
                    ),
                ),
                json_entry(
                    "dataspace_backlog",
                    norito::json::Value::Array(
                        s.dataspace_backlog
                            .iter()
                            .map(|entry| {
                                crate::json_object(vec![
                                    json_entry("lane_id", u64::from(entry.lane_id)),
                                    json_entry("dataspace_id", entry.dataspace_id),
                                    json_entry("tx_count", entry.tx_count),
                                    json_entry("total_chunks", entry.total_chunks),
                                    json_entry("pending_chunks", entry.pending_chunks),
                                    json_entry("rbc_bytes_total", entry.rbc_bytes_total),
                                ])
                            })
                            .collect(),
                    ),
                ),
            ])
        })
        .collect();
    let payload = crate::json_object(vec![
        json_entry("sessions_active", rbc_status::sessions_active()),
        json_entry("items", arr),
    ]);
    let body = norito::json::to_json_pretty(&payload).map_err(|e| {
        Error::Query(iroha_data_model::ValidationFail::InternalError(
            e.to_string(),
        ))
    })?;
    let mut resp = axum::response::Response::new(axum::body::Body::from(body));
    resp.headers_mut().insert(
        axum::http::header::CONTENT_TYPE,
        axum::http::HeaderValue::from_static("application/json"),
    );
    Ok(resp)
}

/// GET /v1/sumeragi/rbc — RBC session/throughput counters
#[cfg(feature = "telemetry")]
#[iroha_futures::telemetry_future]
pub async fn handle_v1_sumeragi_rbc_status(
    telemetry: &MaybeTelemetry,
) -> Result<impl IntoResponse + use<'_>> {
    if !telemetry.allows_developer_outputs() {
        return Err(Error::telemetry_profile_forbidden(
            "sumeragi_rbc_status",
            telemetry.profile(),
        ));
    }

    let m = telemetry.metrics().await;
    let payload = crate::json_object(vec![
        json_entry("sessions_active", m.sumeragi_rbc_sessions_active.get()),
        json_entry(
            "sessions_pruned_total",
            m.sumeragi_rbc_sessions_pruned_total.get(),
        ),
        json_entry(
            "ready_broadcasts_total",
            m.sumeragi_rbc_ready_broadcasts_total.get(),
        ),
        json_entry(
            "ready_rebroadcasts_skipped_total",
            m.sumeragi_rbc_rebroadcast_skipped_total
                .with_label_values(&["ready"])
                .get(),
        ),
        json_entry(
            "deliver_broadcasts_total",
            m.sumeragi_rbc_deliver_broadcasts_total.get(),
        ),
        json_entry(
            "payload_bytes_delivered_total",
            m.sumeragi_rbc_payload_bytes_delivered_total.get(),
        ),
        json_entry(
            "payload_rebroadcasts_skipped_total",
            m.sumeragi_rbc_rebroadcast_skipped_total
                .with_label_values(&["payload"])
                .get(),
        ),
    ]);
    let body = norito::json::to_json_pretty(&payload).map_err(|e| {
        Error::Query(iroha_data_model::ValidationFail::InternalError(
            e.to_string(),
        ))
    })?;
    let mut resp = axum::response::Response::new(axum::body::Body::from(body));
    resp.headers_mut().insert(
        axum::http::header::CONTENT_TYPE,
        axum::http::HeaderValue::from_static("application/json"),
    );
    Ok(resp)
}

/// GET /v1/sumeragi/rbc/delivered/{height}/{view} — delivery status for a specific (height, view)
/// Returns a compact JSON with `delivered` boolean and a minimal summary when a session exists.
#[iroha_futures::telemetry_future]
pub async fn handle_v1_sumeragi_rbc_delivered_height_view(
    height_view: axum::extract::Path<(u64, u64)>,
) -> Result<impl IntoResponse> {
    let (height, view) = height_view.0;
    let items = rbc_status::snapshot();
    let mut matches: Vec<_> = items
        .into_iter()
        .filter(|s| s.height == height && s.view == view)
        .collect();
    // Default payload when no session is present
    if matches.is_empty() {
        let payload = crate::json_object(vec![
            json_entry("height", height),
            json_entry("view", view),
            json_entry("delivered", false),
            json_entry("present", false),
            json_entry("block_hash", Value::Null),
            json_entry("ready_count", 0u64),
            json_entry("received_chunks", 0u64),
            json_entry("total_chunks", 0u64),
        ]);
        let body = norito::json::to_json_pretty(&payload).map_err(|e| {
            Error::Query(iroha_data_model::ValidationFail::InternalError(
                e.to_string(),
            ))
        })?;
        let mut resp = axum::response::Response::new(axum::body::Body::from(body));
        resp.headers_mut().insert(
            axum::http::header::CONTENT_TYPE,
            axum::http::HeaderValue::from_static("application/json"),
        );
        return Ok(resp);
    }

    // If multiple sessions exist (conflicting proposals), report delivery as true if any reached DELIVER
    let delivered_any = matches.iter().any(|s| s.delivered);
    // Prefer a delivered session to report details; otherwise the first entry
    matches.sort_by_key(|s| (!s.delivered, s.total_chunks));
    let pick = &matches[0];
    let payload = crate::json_object(vec![
        json_entry("height", height),
        json_entry("view", view),
        json_entry("delivered", delivered_any),
        json_entry("present", true),
        json_entry("block_hash", hash_to_hex(pick.block_hash)),
        json_entry("ready_count", pick.ready_count),
        json_entry("received_chunks", pick.received_chunks),
        json_entry("total_chunks", pick.total_chunks),
    ]);
    let body = norito::json::to_json_pretty(&payload).map_err(|e| {
        Error::Query(iroha_data_model::ValidationFail::InternalError(
            e.to_string(),
        ))
    })?;
    let mut resp = axum::response::Response::new(axum::body::Body::from(body));
    resp.headers_mut().insert(
        axum::http::header::CONTENT_TYPE,
        axum::http::HeaderValue::from_static("application/json"),
    );
    Ok(resp)
}

/// GET /v1/sumeragi/commit_qc/{hash} — return full commit QC record for a block hash (if present)
#[iroha_futures::telemetry_future]
pub async fn handle_v1_sumeragi_commit_qc(
    State(state): State<std::sync::Arc<CoreState>>,
    axum::extract::Path(hash_hex): axum::extract::Path<String>,
    accept: Option<axum::http::HeaderValue>,
) -> Result<Response> {
    use core::str::FromStr as _;
    let parsed = iroha_crypto::Hash::from_str(&hash_hex).map_err(|e| {
        Error::Query(iroha_data_model::ValidationFail::InternalError(format!(
            "invalid hash: {}",
            e
        )))
    })?;
    let typed = iroha_crypto::HashOf::<BlockHeader>::from_untyped_unchecked(parsed);
    let world = state.world_view();
    let qc_opt = world.commit_qcs().get(&typed).cloned();
    let format = match crate::utils::negotiate_response_format(accept.as_ref()) {
        Ok(fmt) => fmt,
        Err(resp) => return Ok(resp),
    };

    if matches!(format, crate::utils::ResponseFormat::Norito) {
        return Ok(crate::NoritoBody(qc_opt).into_response());
    }
    let payload = match qc_opt.as_ref() {
        Some(qc) => {
            let validator_set = norito::json::Value::Array(
                qc.validator_set
                    .iter()
                    .map(|peer| norito::json::Value::from(peer.to_string()))
                    .collect(),
            );
            let commit_qc = crate::json_object(vec![
                json_entry("phase", format!("{:?}", qc.phase)),
                json_entry("parent_state_root", format!("{}", qc.parent_state_root)),
                json_entry("post_state_root", format!("{}", qc.post_state_root)),
                json_entry("height", qc.height),
                json_entry("view", qc.view),
                json_entry("epoch", qc.epoch),
                json_entry("mode_tag", qc.mode_tag.clone()),
                json_entry("validator_set_hash", format!("{}", qc.validator_set_hash)),
                json_entry("validator_set_hash_version", qc.validator_set_hash_version),
                json_entry("validator_set", validator_set),
                json_entry("signers_bitmap", hex::encode(&qc.aggregate.signers_bitmap)),
                json_entry(
                    "bls_aggregate_signature",
                    hex::encode(&qc.aggregate.bls_aggregate_signature),
                ),
            ]);
            crate::json_object(vec![
                json_entry("subject_block_hash", hash_hex.clone()),
                json_entry("commit_qc", commit_qc),
            ])
        }
        None => crate::json_object(vec![
            json_entry("subject_block_hash", hash_hex.clone()),
            json_entry("commit_qc", norito::json::Value::Null),
        ]),
    };
    let body = norito::json::to_json_pretty(&payload).map_err(|e| {
        Error::Query(iroha_data_model::ValidationFail::InternalError(
            e.to_string(),
        ))
    })?;
    let mut resp = axum::response::Response::new(axum::body::Body::from(body));
    resp.headers_mut().insert(
        axum::http::header::CONTENT_TYPE,
        axum::http::HeaderValue::from_static("application/json"),
    );
    Ok(resp)
}

/// Map an `EventBox` into a compact JSON object used by SSE/WS tests.
pub fn event_to_json_value(ev: &iroha_data_model::events::EventBox) -> norito::json::Value {
    use iroha_data_model::events::pipeline::PipelineEventBox;
    use norito::json::{Map, Value};
    let pipeline_event_json = |p: &PipelineEventBox| match p {
        PipelineEventBox::Transaction(t) => {
            let mut m = Map::new();
            m.insert("category".into(), Value::from("Pipeline"));
            m.insert("event".into(), Value::from("Transaction"));
            m.insert("hash".into(), Value::from(format!("{}", t.hash)));
            m.insert("lane_id".into(), Value::from(u64::from(t.lane_id.as_u32())));
            m.insert("dataspace_id".into(), Value::from(t.dataspace_id.as_u64()));
            if let Some(h) = t.block_height {
                m.insert("block_height".into(), Value::from(h.get()));
            } else {
                m.insert("block_height".into(), Value::Null);
            }
            m.insert("status".into(), Value::from(format!("{:?}", t.status)));
            Value::Object(m)
        }
        PipelineEventBox::Block(b) => {
            let mut m = Map::new();
            m.insert("category".into(), Value::from("Pipeline"));
            m.insert("event".into(), Value::from("Block"));
            m.insert("status".into(), Value::from(format!("{:?}", b.status)));
            Value::Object(m)
        }
        PipelineEventBox::Warning(w) => {
            let mut m = Map::new();
            m.insert("category".into(), Value::from("Pipeline"));
            m.insert("event".into(), Value::from("Warning"));
            m.insert("kind".into(), Value::from(w.kind.clone()));
            m.insert("details".into(), Value::from(w.details.clone()));
            // include minimal header info
            m.insert("height".into(), Value::from(w.header.height().get()));
            Value::Object(m)
        }
        PipelineEventBox::Merge(m) => {
            let mut map = Map::new();
            map.insert("category".into(), Value::from("Pipeline"));
            map.insert("event".into(), Value::from("MergeLedger"));
            map.insert("epoch_id".into(), Value::from(m.entry.epoch_id));
            map.insert(
                "global_state_root".into(),
                Value::from(m.entry.global_state_root.to_string()),
            );
            Value::Object(map)
        }
        PipelineEventBox::Witness(w) => {
            let mut map = Map::new();
            map.insert("category".into(), Value::from("Pipeline"));
            map.insert("event".into(), Value::from("Witness"));
            map.insert(
                "block_hash".into(),
                Value::from(format!("{}", w.block_hash)),
            );
            map.insert("height".into(), Value::from(w.height));
            map.insert("view".into(), Value::from(w.view));
            map.insert("epoch".into(), Value::from(w.epoch));
            map.insert(
                "read_count".into(),
                Value::from(w.witness.reads.len() as u64),
            );
            map.insert(
                "write_count".into(),
                Value::from(w.witness.writes.len() as u64),
            );
            Value::Object(map)
        }
    };

    match ev {
        iroha_data_model::events::EventBox::Pipeline(p) => pipeline_event_json(p),
        iroha_data_model::events::EventBox::PipelineBatch(batch) => {
            Value::Array(batch.iter().map(pipeline_event_json).collect())
        }
        iroha_data_model::events::EventBox::Data(d) => {
            use iroha_data_model::prelude as de;
            match d.as_ref() {
                de::DataEvent::Proof(pe) => match pe {
                    iroha_data_model::events::data::proof::ProofEvent::Verified(v) => {
                        let mut m = Map::new();
                        m.insert("category".into(), Value::from("Data"));
                        m.insert("event".into(), Value::from("ProofVerified"));
                        m.insert("backend".into(), Value::from(format!("{}", v.id.backend)));
                        m.insert(
                            "proof_hash".into(),
                            Value::from(hex::encode(v.id.proof_hash)),
                        );
                        if let Some(ch) = v.call_hash {
                            m.insert("call_hash".into(), Value::from(hex::encode(ch)));
                        } else {
                            m.insert("call_hash".into(), Value::Null);
                        }
                        if let Some(eh) = v.envelope_hash {
                            m.insert("envelope_hash".into(), Value::from(hex::encode(eh)));
                        } else {
                            m.insert("envelope_hash".into(), Value::Null);
                        }
                        // Optional vk_ref (backend::name) and vk_commitment (hex)
                        if let Some(vk) = &v.vk_ref {
                            m.insert(
                                "vk_ref".into(),
                                Value::from(format!("{}::{}", vk.backend, vk.name)),
                            );
                        } else {
                            m.insert("vk_ref".into(), Value::Null);
                        }
                        if let Some(comm) = v.vk_commitment {
                            m.insert("vk_commitment".into(), Value::from(hex::encode(comm)));
                        } else {
                            m.insert("vk_commitment".into(), Value::Null);
                        }
                        Value::Object(m)
                    }
                    iroha_data_model::events::data::proof::ProofEvent::Rejected(r) => {
                        let mut m = Map::new();
                        m.insert("category".into(), Value::from("Data"));
                        m.insert("event".into(), Value::from("ProofRejected"));
                        m.insert("backend".into(), Value::from(format!("{}", r.id.backend)));
                        m.insert(
                            "proof_hash".into(),
                            Value::from(hex::encode(r.id.proof_hash)),
                        );
                        if let Some(ch) = r.call_hash {
                            m.insert("call_hash".into(), Value::from(hex::encode(ch)));
                        } else {
                            m.insert("call_hash".into(), Value::Null);
                        }
                        if let Some(eh) = r.envelope_hash {
                            m.insert("envelope_hash".into(), Value::from(hex::encode(eh)));
                        } else {
                            m.insert("envelope_hash".into(), Value::Null);
                        }
                        if let Some(vk) = &r.vk_ref {
                            m.insert(
                                "vk_ref".into(),
                                Value::from(format!("{}::{}", vk.backend, vk.name)),
                            );
                        } else {
                            m.insert("vk_ref".into(), Value::Null);
                        }
                        if let Some(comm) = r.vk_commitment {
                            m.insert("vk_commitment".into(), Value::from(hex::encode(comm)));
                        } else {
                            m.insert("vk_commitment".into(), Value::Null);
                        }
                        Value::Object(m)
                    }
                    iroha_data_model::events::data::proof::ProofEvent::Pruned(p) => {
                        let mut m = Map::new();
                        m.insert("category".into(), Value::from("Data"));
                        m.insert("event".into(), Value::from("ProofPruned"));
                        m.insert("backend".into(), Value::from(p.backend.clone()));
                        m.insert("removed_count".into(), Value::from(p.removed.len() as u64));
                        m.insert("remaining".into(), Value::from(p.remaining));
                        m.insert("cap".into(), Value::from(p.cap));
                        m.insert("grace_blocks".into(), Value::from(p.grace_blocks));
                        m.insert("prune_batch".into(), Value::from(p.prune_batch));
                        m.insert("pruned_at_height".into(), Value::from(p.pruned_at_height));
                        m.insert("pruned_by".into(), Value::from(format!("{}", p.pruned_by)));
                        m.insert("origin".into(), Value::from(format!("{:?}", p.origin)));
                        let removed: Vec<Value> = p
                            .removed
                            .iter()
                            .map(|pid| {
                                let mut e = Map::new();
                                e.insert("backend".into(), Value::from(pid.backend.clone()));
                                e.insert(
                                    "proof_hash".into(),
                                    Value::from(hex::encode(pid.proof_hash)),
                                );
                                Value::Object(e)
                            })
                            .collect();
                        m.insert("removed".into(), Value::Array(removed));
                        Value::Object(m)
                    }
                },
                _ => {
                    let mut m = Map::new();
                    m.insert("category".into(), Value::from("Data"));
                    m.insert("summary".into(), Value::from(format!("{:?}", d)));
                    Value::Object(m)
                }
            }
        }
        _ => {
            let mut m = Map::new();
            m.insert("category".into(), Value::from("Other"));
            m.insert("summary".into(), Value::from(format!("{:?}", ev)));
            Value::Object(m)
        }
    }
}

#[cfg(feature = "app_api")]
fn event_filters_from_expr(expr: &FilterExpr) -> Vec<EventFilterBox> {
    // Build filters for SSE using available typed filter boxes.
    // Supported fields/operators:
    // - tx_status == {Queued|Expired|Approved|Rejected}
    // - tx_hash == <hex>
    // - tx_block_height == <u64> (non-zero)
    // - block_status == {Created|Approved|Rejected|Committed|Applied}
    // - block_height == <u64> (non-zero)
    // - IsNull(tx_block_height) → only transactions without a block height
    // AND combines compatible fields into a single typed filter; OR unions filters.
    use FilterExpr as F;

    #[derive(Clone, Default)]
    struct OfflineFilterSpec {
        platform_policy: Option<AndroidIntegrityPolicy>,
    }

    impl OfflineFilterSpec {
        fn for_platform_policy(mut self, policy: AndroidIntegrityPolicy) -> Self {
            self.platform_policy = Some(policy);
            self
        }

        fn merge(self, other: Self) -> Option<Self> {
            let mut merged = self;
            if let Some(policy) = other.platform_policy {
                match merged.platform_policy {
                    None => merged.platform_policy = Some(policy),
                    Some(existing) if existing == policy => {}
                    Some(_) => return None,
                }
            }
            Some(merged)
        }

        fn into_filter(self) -> OfflineTransferEventFilter {
            let mut filter = OfflineTransferEventFilter::new();
            if let Some(policy) = self.platform_policy {
                filter = filter.for_platform_policy(policy);
            }
            filter
        }
    }

    #[derive(Clone)]
    enum PF {
        Tx(TransactionEventFilter),
        Block(BlockEventFilter),
        Offline(OfflineFilterSpec),
    }

    fn merge(a: PF, b: PF) -> Option<PF> {
        match (a, b) {
            (PF::Tx(mut x), PF::Tx(y)) => {
                if let Some(st) = y.status() {
                    x = x.for_status(st.clone());
                }
                if let Some(h) = y.block_height {
                    x = x.for_block_height(h);
                }
                if let Some(hash) = y.hash() {
                    x = x.for_hash(hash.clone());
                }
                Some(PF::Tx(x))
            }
            (PF::Block(mut x), PF::Block(y)) => {
                if let Some(st) = y.status() {
                    x = x.for_status(st.clone());
                }
                if let Some(h) = y.height() {
                    x = x.for_height(h);
                }
                Some(PF::Block(x))
            }
            (PF::Offline(x), PF::Offline(y)) => x.merge(y).map(PF::Offline),
            _ => None, // incompatible types in AND => no single event can satisfy
        }
    }

    fn to_event_boxes(pfs: Vec<PF>) -> Vec<EventFilterBox> {
        pfs.into_iter()
            .map(|pf| match pf {
                PF::Tx(f) => EventFilterBox::Pipeline(f.into()),
                PF::Block(f) => EventFilterBox::Pipeline(f.into()),
                PF::Offline(spec) => {
                    EventFilterBox::Data(DataEventFilter::Offline(spec.into_filter()))
                }
            })
            .collect()
    }

    fn build(expr: &FilterExpr) -> Vec<PF> {
        match expr {
            F::Eq(field, value) => match field.0.as_str() {
                // Transaction fields
                "tx_status" => value
                    .as_str()
                    .and_then(parse_tx_status)
                    .map(|st| vec![PF::Tx(TransactionEventFilter::new().for_status(st))])
                    .unwrap_or_default(),
                "tx_hash" => value
                    .as_str()
                    .and_then(|s| {
                        s.parse::<iroha_crypto::HashOf<
                            iroha_data_model::transaction::signed::SignedTransaction,
                        >>()
                        .ok()
                    })
                    .map(|h| vec![PF::Tx(TransactionEventFilter::new().for_hash(h))])
                    .unwrap_or_default(),
                "tx_block_height" => value
                    .as_u64()
                    .and_then(NonZeroU64::new)
                    .map(|h| {
                        vec![PF::Tx(
                            TransactionEventFilter::new().for_block_height(Some(h)),
                        )]
                    })
                    .unwrap_or_default(),
                "tx_lane_id" => {
                    let lane_raw = value
                        .as_u64()
                        .and_then(|raw| u32::try_from(raw).ok())
                        .or_else(|| value.as_str().and_then(|s| s.parse::<u32>().ok()));
                    lane_raw
                        .map(|raw| {
                            vec![PF::Tx(
                                TransactionEventFilter::new().for_lane_id(LaneId::new(raw)),
                            )]
                        })
                        .unwrap_or_default()
                }
                "tx_dataspace_id" => {
                    let dataspace_raw = value
                        .as_u64()
                        .or_else(|| value.as_str().and_then(|s| s.parse::<u64>().ok()));
                    dataspace_raw
                        .map(|raw| {
                            vec![PF::Tx(
                                TransactionEventFilter::new()
                                    .for_dataspace_id(DataSpaceId::new(raw)),
                            )]
                        })
                        .unwrap_or_default()
                }

                // Block fields
                "block_status" => value
                    .as_str()
                    .and_then(parse_block_status)
                    .map(|st| vec![PF::Block(BlockEventFilter::new().for_status(st))])
                    .unwrap_or_default(),
                "block_height" => value
                    .as_u64()
                    .and_then(NonZeroU64::new)
                    .map(|h| vec![PF::Block(BlockEventFilter::new().for_height(h))])
                    .unwrap_or_default(),
                "platform_policy" => value
                    .as_str()
                    .and_then(parse_offline_platform_policy)
                    .map(|policy| {
                        vec![PF::Offline(
                            OfflineFilterSpec::default().for_platform_policy(policy),
                        )]
                    })
                    .unwrap_or_default(),
                _ => Vec::new(),
            },
            F::IsNull(field) if field.0.as_str() == "tx_block_height" => {
                vec![PF::Tx(TransactionEventFilter::new().for_block_height(None))]
            }
            F::In(field, list) if field.0.as_str() == "tx_status" => {
                let mut acc = Vec::new();
                for v in list {
                    if let Some(st) = v.as_str().and_then(parse_tx_status) {
                        acc.push(PF::Tx(TransactionEventFilter::new().for_status(st)));
                    }
                }
                acc
            }
            F::In(field, list) if field.0.as_str() == "platform_policy" => {
                let mut acc = Vec::new();
                for v in list {
                    if let Some(policy) = v.as_str().and_then(parse_offline_platform_policy) {
                        acc.push(PF::Offline(
                            OfflineFilterSpec::default().for_platform_policy(policy),
                        ));
                    }
                }
                acc
            }
            // Combine all children with AND semantics for compatible types
            F::And(children) => {
                let mut acc: Vec<PF> = vec![];
                for c in children {
                    let next = build(c);
                    if acc.is_empty() {
                        acc = next;
                    } else {
                        let mut merged = Vec::new();
                        for a in &acc {
                            for b in &next {
                                if let Some(m) = merge(a.clone(), b.clone()) {
                                    merged.push(m);
                                }
                            }
                        }
                        acc = merged;
                    }
                }
                acc
            }
            // OR = union (list treated as any-of)
            F::Or(children) => {
                let mut acc = Vec::new();
                for c in children {
                    acc.extend(build(c));
                }
                acc
            }
            // Limited NOT support: negate simple status equals by expanding to all other statuses
            F::Not(inner) => match &**inner {
                F::Eq(f, v) if f.0.as_str() == "tx_status" => {
                    let mut acc = Vec::new();
                    if let Some(target) = v.as_str().and_then(parse_tx_status) {
                        use iroha_data_model::events::pipeline::TransactionStatus as TS;
                        let rejected = TS::Rejected(Box::new(
                            iroha_data_model::transaction::error::TransactionRejectionReason::Validation(
                                iroha_data_model::ValidationFail::InternalError("filtered".into()),
                            ),
                        ));
                        let all = [TS::Queued, TS::Expired, TS::Approved, rejected];
                        for st in all.into_iter() {
                            if core::mem::discriminant(&st) != core::mem::discriminant(&target) {
                                acc.push(PF::Tx(TransactionEventFilter::new().for_status(st)));
                            }
                        }
                    }
                    acc
                }
                F::Eq(f, v) if f.0.as_str() == "block_status" => {
                    let mut acc = Vec::new();
                    if let Some(target) = v.as_str().and_then(parse_block_status) {
                        use iroha_data_model::events::pipeline::BlockStatus as BS;
                        let all = [
                            BS::Created,
                            BS::Approved,
                            BS::Rejected(
                                iroha_data_model::block::error::BlockRejectionReason::ConsensusBlockRejection,
                            ),
                            BS::Committed,
                            BS::Applied,
                        ];
                        for st in all.into_iter() {
                            if core::mem::discriminant(&st) != core::mem::discriminant(&target) {
                                acc.push(PF::Block(BlockEventFilter::new().for_status(st)));
                            }
                        }
                    }
                    acc
                }
                _ => Vec::new(),
            },
            _ => Vec::new(),
        }
    }

    to_event_boxes(build(expr))
}

#[cfg(feature = "app_api")]
#[derive(Debug, Default, Clone)]
struct SseFilterSpec {
    filters: Option<Arc<Vec<EventFilterBox>>>,
    proof_backend: Option<Vec<String>>,
    proof_call_hash: Option<Vec<[u8; 32]>>,
    proof_envelope_hash: Option<Vec<[u8; 32]>>,
}

#[cfg(feature = "app_api")]
fn sse_filter_error(msg: impl Into<String>) -> crate::Error {
    crate::Error::Query(iroha_data_model::ValidationFail::QueryFailed(
        iroha_data_model::query::error::QueryExecutionFail::Conversion(msg.into()),
    ))
}

#[cfg(feature = "app_api")]
fn parse_sse_filter_params(raw: Option<&str>) -> Result<SseFilterSpec, crate::Error> {
    let Some(raw) = raw else {
        return Ok(SseFilterSpec::default());
    };
    let expr = norito::json::from_str::<FilterExpr>(raw)
        .map_err(|_| sse_filter_error("invalid filter expression"))?;
    parse_sse_filters(&expr).map_err(sse_filter_error)
}

#[cfg(feature = "app_api")]
fn parse_sse_filters(expr: &FilterExpr) -> Result<SseFilterSpec, String> {
    #[derive(Default)]
    struct SseFilterUsage {
        event_filter_seen: bool,
        proof_backend: Vec<String>,
        proof_call_hash: Vec<[u8; 32]>,
        proof_envelope_hash: Vec<[u8; 32]>,
    }

    fn parse_u64_value(value: &norito::json::Value) -> Option<u64> {
        value
            .as_u64()
            .or_else(|| value.as_str().and_then(|s| s.parse::<u64>().ok()))
    }

    fn parse_hex_32(field: &str, value: &norito::json::Value) -> Result<[u8; 32], String> {
        let s = value
            .as_str()
            .ok_or_else(|| format!("{field} must be a hex string"))?;
        if s.len() != 64 {
            return Err(format!("{field} must be 64 hex characters"));
        }
        let bytes = hex::decode(s).map_err(|_| format!("{field} must be valid hex"))?;
        if bytes.len() != 32 {
            return Err(format!("{field} must decode to 32 bytes"));
        }
        let mut arr = [0u8; 32];
        arr.copy_from_slice(&bytes);
        Ok(arr)
    }

    fn validate_eq(
        field: &str,
        value: &norito::json::Value,
        usage: &mut SseFilterUsage,
    ) -> Result<(), String> {
        match field {
            "tx_status" => {
                let raw = value
                    .as_str()
                    .ok_or_else(|| "tx_status must be a string".to_string())?;
                if parse_tx_status(raw).is_none() {
                    return Err("tx_status is not a valid status".to_string());
                }
                usage.event_filter_seen = true;
            }
            "tx_hash" => {
                let raw = value
                    .as_str()
                    .ok_or_else(|| "tx_hash must be a string".to_string())?;
                let parsed =
                    raw.parse::<iroha_crypto::HashOf<
                        iroha_data_model::transaction::signed::SignedTransaction,
                    >>();
                if parsed.is_err() {
                    return Err("tx_hash must be a valid hex hash".to_string());
                }
                usage.event_filter_seen = true;
            }
            "tx_block_height" => {
                let raw = parse_u64_value(value)
                    .ok_or_else(|| "tx_block_height must be an unsigned integer".to_string())?;
                if NonZeroU64::new(raw).is_none() {
                    return Err("tx_block_height must be > 0".to_string());
                }
                usage.event_filter_seen = true;
            }
            "tx_lane_id" => {
                let raw = parse_u64_value(value)
                    .ok_or_else(|| "tx_lane_id must be an unsigned integer".to_string())?;
                u32::try_from(raw).map_err(|_| "tx_lane_id must fit in u32".to_string())?;
                usage.event_filter_seen = true;
            }
            "tx_dataspace_id" => {
                let raw = parse_u64_value(value)
                    .ok_or_else(|| "tx_dataspace_id must be an unsigned integer".to_string())?;
                let _ = raw;
                usage.event_filter_seen = true;
            }
            "block_status" => {
                let raw = value
                    .as_str()
                    .ok_or_else(|| "block_status must be a string".to_string())?;
                if parse_block_status(raw).is_none() {
                    return Err("block_status is not a valid status".to_string());
                }
                usage.event_filter_seen = true;
            }
            "block_height" => {
                let raw = parse_u64_value(value)
                    .ok_or_else(|| "block_height must be an unsigned integer".to_string())?;
                if NonZeroU64::new(raw).is_none() {
                    return Err("block_height must be > 0".to_string());
                }
                usage.event_filter_seen = true;
            }
            "platform_policy" => {
                let raw = value
                    .as_str()
                    .ok_or_else(|| "platform_policy must be a string".to_string())?;
                if parse_offline_platform_policy(raw).is_none() {
                    return Err("platform_policy is not a valid policy".to_string());
                }
                usage.event_filter_seen = true;
            }
            "proof_backend" => {
                let raw = value
                    .as_str()
                    .ok_or_else(|| "proof_backend must be a string".to_string())?;
                if raw.trim().is_empty() {
                    return Err("proof_backend must be non-empty".to_string());
                }
                usage.proof_backend.push(raw.to_string());
            }
            "proof_call_hash" => {
                let arr = parse_hex_32("proof_call_hash", value)?;
                usage.proof_call_hash.push(arr);
            }
            "proof_envelope_hash" => {
                let arr = parse_hex_32("proof_envelope_hash", value)?;
                usage.proof_envelope_hash.push(arr);
            }
            _ => return Err(format!("unsupported filter field: {field}")),
        }
        Ok(())
    }

    fn validate_in(
        field: &str,
        values: &[norito::json::Value],
        usage: &mut SseFilterUsage,
    ) -> Result<(), String> {
        if values.is_empty() {
            return Err(format!("{field} IN must not be empty"));
        }
        for value in values {
            validate_eq(field, value, usage)?;
        }
        Ok(())
    }

    fn validate_expr(expr: &FilterExpr, usage: &mut SseFilterUsage) -> Result<(), String> {
        match expr {
            FilterExpr::And(list) | FilterExpr::Or(list) => {
                if list.is_empty() {
                    return Err("filter expression must not be empty".to_string());
                }
                for sub in list {
                    validate_expr(sub, usage)?;
                }
            }
            FilterExpr::Not(inner) => match inner.as_ref() {
                FilterExpr::Eq(field, value)
                    if field.0 == "tx_status" || field.0 == "block_status" =>
                {
                    validate_eq(&field.0, value, usage)?;
                }
                _ => {
                    return Err("not only supports tx_status or block_status".to_string());
                }
            },
            FilterExpr::Eq(field, value) => validate_eq(&field.0, value, usage)?,
            FilterExpr::In(field, values) => validate_in(&field.0, values, usage)?,
            FilterExpr::IsNull(field) => {
                if field.0.as_str() != "tx_block_height" {
                    return Err("isnull only supports tx_block_height".to_string());
                }
                usage.event_filter_seen = true;
            }
            _ => return Err("unsupported filter operator".to_string()),
        }
        Ok(())
    }

    let mut usage = SseFilterUsage::default();
    validate_expr(expr, &mut usage)?;

    let filters = event_filters_from_expr(expr);
    if usage.event_filter_seen && filters.is_empty() {
        return Err("filter does not match any SSE events".to_string());
    }

    let filters = if filters.is_empty() {
        None
    } else {
        Some(Arc::new(filters))
    };
    let proof_backend = if usage.proof_backend.is_empty() {
        None
    } else {
        Some(usage.proof_backend)
    };
    let proof_call_hash = if usage.proof_call_hash.is_empty() {
        None
    } else {
        Some(usage.proof_call_hash)
    };
    let proof_envelope_hash = if usage.proof_envelope_hash.is_empty() {
        None
    } else {
        Some(usage.proof_envelope_hash)
    };

    Ok(SseFilterSpec {
        filters,
        proof_backend,
        proof_call_hash,
        proof_envelope_hash,
    })
}

#[cfg(all(test, feature = "app_api"))]
mod sse_filter_validation_tests {
    use super::*;
    use crate::filter::{FieldPath, FilterExpr};

    #[test]
    fn sse_filter_rejects_unknown_field() {
        let expr = FilterExpr::Eq(
            FieldPath("unknown_field".into()),
            norito::json::Value::String("nope".into()),
        );
        let err = parse_sse_filters(&expr).expect_err("unknown field should be rejected");
        assert!(err.contains("unsupported filter field"));
    }

    #[test]
    fn sse_filter_rejects_invalid_proof_hash() {
        let expr = FilterExpr::Eq(
            FieldPath("proof_call_hash".into()),
            norito::json::Value::String("deadbeef".into()),
        );
        let err = parse_sse_filters(&expr).expect_err("invalid proof hash should be rejected");
        assert!(err.contains("proof_call_hash"));
    }

    #[test]
    fn sse_filter_rejects_incompatible_and() {
        let expr = FilterExpr::And(vec![
            FilterExpr::Eq(
                FieldPath("tx_status".into()),
                norito::json::Value::String("Queued".into()),
            ),
            FilterExpr::Eq(
                FieldPath("block_status".into()),
                norito::json::Value::String("Committed".into()),
            ),
        ]);
        let err = parse_sse_filters(&expr).expect_err("incompatible AND should be rejected");
        assert_eq!(err, "filter does not match any SSE events");
    }

    #[test]
    fn sse_filter_accepts_proof_only_filter() {
        let expr = FilterExpr::Eq(
            FieldPath("proof_backend".into()),
            norito::json::Value::String("halo2/ipa".into()),
        );
        let spec = parse_sse_filters(&expr).expect("proof-only filter should parse");
        assert!(spec.filters.is_none());
        assert_eq!(spec.proof_backend.unwrap(), vec!["halo2/ipa".to_string()]);
    }

    #[test]
    fn sse_filter_params_rejects_invalid_json() {
        let err = parse_sse_filter_params(Some("not-json")).expect_err("invalid json rejected");
        let _ = err;
    }

    #[test]
    fn sse_handler_rejects_invalid_filter() {
        let events: iroha_core::EventsSender = tokio::sync::broadcast::channel(1).0;
        let params = EventsSseParams {
            filter: Some("not-json".to_string()),
        };
        let res = handle_v1_events_sse(events, crate::NoritoQuery(params));
        assert!(res.is_err());
    }
}

#[cfg(all(test, feature = "app_api"))]
mod sse_stream_tests {
    use axum::response::IntoResponse as _;
    use http_body_util::BodyExt as _;
    use iroha_crypto::{Hash, HashOf};
    use iroha_data_model::{
        events::{
            EventBox,
            pipeline::{PipelineEventBox, TransactionEvent, TransactionStatus},
        },
        nexus::{DataSpaceId, LaneId},
        transaction::SignedTransaction,
    };
    use tokio::time::{Duration, timeout};

    use super::*;

    #[tokio::test]
    async fn sse_stream_expands_pipeline_batches() {
        let events: EventsSender = tokio::sync::broadcast::channel(8).0;
        let params = EventsSseParams { filter: None };
        let sse = handle_v1_events_sse(events.clone(), crate::NoritoQuery(params))
            .expect("create SSE stream");
        let response = sse.into_response();
        let mut body = response.into_body();

        let hash = HashOf::<SignedTransaction>::from_untyped_unchecked(Hash::prehashed(
            [0x11; Hash::LENGTH],
        ));
        let batch =
            EventBox::PipelineBatch(vec![PipelineEventBox::Transaction(TransactionEvent {
                hash,
                block_height: None,
                lane_id: LaneId::new(0),
                dataspace_id: DataSpaceId::new(0),
                status: TransactionStatus::Queued,
            })]);
        events.send(batch).expect("send batch event");

        let frame = timeout(Duration::from_secs(1), body.frame())
            .await
            .expect("timeout waiting for SSE frame")
            .expect("frame")
            .expect("frame data");
        let data = frame.into_data().expect("data frame");
        let payload = std::str::from_utf8(&data).expect("utf8");
        let data_line = payload
            .lines()
            .find(|line| line.starts_with("data: "))
            .expect("data line");
        let json = data_line.trim_start_matches("data: ").trim();
        let value: norito::json::Value = norito::json::from_str(json).expect("json payload");
        assert!(matches!(value, norito::json::Value::Object(_)));
    }
}

#[cfg(test)]
mod cursor_mode_tests {
    use std::sync::Arc;

    use iroha_core::{
        kura::Kura,
        query::store::LiveQueryStore,
        smartcontracts::isi::query::{QueryLimits, apply_query_postprocessing},
        state::{State, World},
    };
    use iroha_data_model::prelude::*;
    use iroha_data_model::query::parameters::{FetchSize, QueryParams};
    use nonzero_ext::nonzero;

    use super::*;

    fn make_minimal_state() -> State {
        let kura = Kura::blank_kura_for_testing();
        let query = LiveQueryStore::start_test();
        State::new_for_testing(World::new(), kura, query)
    }

    fn seed_stored_cursor(
        live_query_store: &iroha_core::query::store::LiveQueryStoreHandle,
        authority: &AccountId,
        gas_budget: u64,
    ) -> iroha_data_model::query::parameters::ForwardCursor {
        let query_output = (0..3).map(|i| {
            Permission::new(
                format!("p{i}"),
                iroha_data_model::prelude::Json::from(false),
            )
        });
        let query_params = QueryParams {
            fetch_size: FetchSize {
                fetch_size: Some(nonzero!(1_u64)),
            },
            ..QueryParams::default()
        };
        let iter = apply_query_postprocessing(
            query_output,
            SelectorTuple::default(),
            &query_params,
            QueryLimits::default(),
        )
        .expect("build query output");
        let response = live_query_store
            .handle_iter_start(iter, authority, Some(gas_budget))
            .expect("start query");
        let (_batch, _remaining, cursor) = response.into_parts();
        cursor.expect("cursor should be stored")
    }

    fn signed_singular_find_active_abi(
        authority: &AccountId,
        signer: &iroha_crypto::KeyPair,
    ) -> iroha_data_model::query::SignedQuery {
        use iroha_data_model::query::QueryRequest;
        let req = QueryRequest::Singular(
            iroha_data_model::query::prelude::SingularQueryBox::FindActiveAbiVersions(
                iroha_data_model::query::runtime::prelude::FindActiveAbiVersions,
            ),
        )
        .with_authority(authority.clone());
        req.sign(signer)
    }

    #[tokio::test]
    async fn stored_mode_insufficient_gas_rejected() {
        let mut s = make_minimal_state();
        s.pipeline.query_default_cursor_mode =
            iroha_config::parameters::actual::QueryCursorMode::Stored;
        s.pipeline.query_stored_min_gas_units = 200;
        let state = Arc::new(s);

        let kp = iroha_crypto::KeyPair::random();
        let authority = AccountId::new(kp.public_key().clone());
        let signed = signed_singular_find_active_abi(&authority, &kp);

        let opts = QueryOptions {
            cursor_mode: Some("stored".to_string()),
            gas_units: Some(100),
        };
        #[cfg(feature = "telemetry")]
        let tel = MaybeTelemetry::for_tests();
        #[cfg(not(feature = "telemetry"))]
        let tel = MaybeTelemetry::disabled();
        let live = state.query_handle.clone();
        let res = handle_queries_with_opts(
            live,
            state,
            signed,
            tel,
            crate::NoritoQuery(opts),
            crate::utils::ResponseFormat::Json,
        )
        .await;
        assert!(matches!(
            res,
            Err(crate::Error::Query(ValidationFail::NotPermitted(_)))
        ));
    }

    #[tokio::test]
    async fn stored_mode_sufficient_gas_ok() {
        let mut s = make_minimal_state();
        s.pipeline.query_default_cursor_mode =
            iroha_config::parameters::actual::QueryCursorMode::Stored;
        s.pipeline.query_stored_min_gas_units = 200;
        let state = Arc::new(s);

        let kp = iroha_crypto::KeyPair::random();
        let authority = AccountId::new(kp.public_key().clone());
        let signed = signed_singular_find_active_abi(&authority, &kp);

        let opts = QueryOptions {
            cursor_mode: Some("stored".to_string()),
            gas_units: Some(250),
        };
        #[cfg(feature = "telemetry")]
        let tel = MaybeTelemetry::for_tests();
        #[cfg(not(feature = "telemetry"))]
        let tel = MaybeTelemetry::disabled();
        let live = state.query_handle.clone();
        let res = handle_queries_with_opts(
            live,
            state,
            signed,
            tel,
            crate::NoritoQuery(opts),
            crate::utils::ResponseFormat::Json,
        )
        .await;
        assert!(res.is_ok());
    }

    #[tokio::test]
    async fn stored_mode_continue_uses_cursor_gas_budget() {
        let mut s = make_minimal_state();
        s.pipeline.query_default_cursor_mode =
            iroha_config::parameters::actual::QueryCursorMode::Stored;
        s.pipeline.query_stored_min_gas_units = 200;
        let state = Arc::new(s);

        let kp = iroha_crypto::KeyPair::random();
        let authority = AccountId::new(kp.public_key().clone());
        let cursor = seed_stored_cursor(&state.query_handle, &authority, 250);
        let signed = iroha_data_model::query::QueryRequest::Continue(cursor)
            .with_authority(authority)
            .sign(&kp);

        let opts = QueryOptions {
            cursor_mode: Some("stored".to_string()),
            gas_units: None,
        };
        #[cfg(feature = "telemetry")]
        let tel = MaybeTelemetry::for_tests();
        #[cfg(not(feature = "telemetry"))]
        let tel = MaybeTelemetry::disabled();
        let live = state.query_handle.clone();
        let res = handle_queries_with_opts(
            live,
            state,
            signed,
            tel,
            crate::NoritoQuery(opts),
            crate::utils::ResponseFormat::Json,
        )
        .await;
        assert!(res.is_ok());
    }

    #[tokio::test]
    async fn ephemeral_mode_unaffected_without_gas() {
        let mut s = make_minimal_state();
        s.pipeline.query_default_cursor_mode =
            iroha_config::parameters::actual::QueryCursorMode::Ephemeral;
        s.pipeline.query_stored_min_gas_units = 200;
        let state = Arc::new(s);

        let kp = iroha_crypto::KeyPair::random();
        let authority = AccountId::new(kp.public_key().clone());
        let signed = signed_singular_find_active_abi(&authority, &kp);

        // No override and no gas_units → should pass in ephemeral mode
        let opts = QueryOptions::default();
        #[cfg(feature = "telemetry")]
        let tel = MaybeTelemetry::for_tests();
        #[cfg(not(feature = "telemetry"))]
        let tel = MaybeTelemetry::disabled();
        let live = state.query_handle.clone();
        let res = handle_queries_with_opts(
            live,
            state,
            signed,
            tel,
            crate::NoritoQuery(opts),
            crate::utils::ResponseFormat::Json,
        )
        .await;
        assert!(res.is_ok());
    }
}

#[cfg(all(test, feature = "telemetry"))]
mod lane_admission_metrics_tests {
    use std::sync::Arc;

    use iroha_core::{
        kura::Kura,
        query::store::LiveQueryStore,
        queue::Queue,
        state::{State, World},
    };
    use iroha_data_model::prelude::*;
    use iroha_logger::Level;

    use super::*;

    #[tokio::test]
    async fn transaction_ingress_records_latency_histogram() {
        let kura = Kura::blank_kura_for_testing();
        let query = LiveQueryStore::start_test();
        let state = Arc::new(iroha_core::state::State::new_for_testing(
            World::default(),
            kura,
            query,
        ));
        let events: iroha_core::EventsSender = tokio::sync::broadcast::channel(8).0;
        let queue_cfg = iroha_config::parameters::actual::Queue::default();
        let queue = Arc::new(Queue::from_config(queue_cfg, events));
        let chain_id: Arc<ChainId> = Arc::new("metrics_chain".parse().expect("valid chain id"));
        let telemetry = MaybeTelemetry::for_tests();

        let key_pair = iroha_crypto::KeyPair::random();
        let account_id = AccountId::new(key_pair.public_key().clone());
        let instruction = Log::new(Level::INFO, "ingress-metric".to_string());
        let tx = TransactionBuilder::new(chain_id.as_ref().clone(), account_id)
            .with_instructions([InstructionBox::from(instruction)])
            .sign(key_pair.private_key());

        handle_transaction_with_metrics(
            Arc::clone(&chain_id),
            queue,
            state,
            tx,
            telemetry.clone(),
            iroha_torii_shared::uri::TRANSACTION,
        )
        .await
        .expect("ingress succeeds");

        let metrics = telemetry.metrics().await;
        let histogram = metrics
            .torii_lane_admission_latency_seconds
            .with_label_values(&["0", iroha_torii_shared::uri::TRANSACTION]);
        assert!(
            histogram.get_sample_count() >= 1,
            "expected at least one latency observation"
        );
    }
}

#[cfg(feature = "app_api")]
fn parse_tx_status(s: &str) -> Option<TransactionStatus> {
    match s {
        "Queued" => Some(TransactionStatus::Queued),
        "Expired" => Some(TransactionStatus::Expired),
        "Approved" => Some(TransactionStatus::Approved),
        "Rejected" => Some(TransactionStatus::Rejected(Box::new(
            iroha_data_model::transaction::error::TransactionRejectionReason::Validation(
                iroha_data_model::ValidationFail::InternalError("filtered".into()),
            ),
        ))),
        _ => None,
    }
}

#[cfg(feature = "app_api")]
fn parse_block_status(s: &str) -> Option<BlockStatus> {
    match s {
        "Created" => Some(BlockStatus::Created),
        "Approved" => Some(BlockStatus::Approved),
        "Rejected" => Some(BlockStatus::Rejected(
            iroha_data_model::block::error::BlockRejectionReason::ConsensusBlockRejection,
        )),
        "Committed" => Some(BlockStatus::Committed),
        "Applied" => Some(BlockStatus::Applied),
        _ => None,
    }
}

#[cfg(feature = "app_api")]
fn parse_offline_platform_policy(s: &str) -> Option<AndroidIntegrityPolicy> {
    AndroidIntegrityPolicy::from_str(s)
        .ok()
        .and_then(|policy| match policy {
            AndroidIntegrityPolicy::PlayIntegrity | AndroidIntegrityPolicy::HmsSafetyDetect => {
                Some(policy)
            }
            _ => None,
        })
}

