/// Summary of the optional aggregate proof payload attached to offline bundles.
#[cfg(feature = "app_api")]
#[derive(crate::json_macros::JsonSerialize, norito::derive::NoritoSerialize, Debug, Clone)]
pub struct OfflineBundleProofSummary {
    /// Aggregate proof envelope version.
    pub version: u16,
    /// Sum proof size in bytes.
    #[norito(default)]
    pub proof_sum_bytes: Option<u64>,
    /// Counter proof size in bytes.
    #[norito(default)]
    pub proof_counter_bytes: Option<u64>,
    /// Replay proof size in bytes.
    #[norito(default)]
    pub proof_replay_bytes: Option<u64>,
    /// Metadata keys present in the aggregate envelope.
    pub metadata_keys: Vec<String>,
}

#[cfg(feature = "app_api")]
impl OfflineBundleProofSummary {
    fn from_envelope(envelope: &AggregateProofEnvelope) -> Self {
        let mut metadata_keys: Vec<String> = envelope
            .metadata
            .iter()
            .map(|(key, _)| key.to_string())
            .collect();
        metadata_keys.sort_unstable();

        Self {
            version: envelope.version,
            proof_sum_bytes: envelope.proof_sum.as_ref().map(|bytes| bytes.len() as u64),
            proof_counter_bytes: envelope
                .proof_counter
                .as_ref()
                .map(|bytes| bytes.len() as u64),
            proof_replay_bytes: envelope
                .proof_replay
                .as_ref()
                .map(|bytes| bytes.len() as u64),
            metadata_keys,
        }
    }
}

