#[cfg(all(test, feature = "app_api"))]
struct RepoTestFixture {
    state: Arc<CoreState>,
    agreements: Vec<(String, u64)>,
    initiator_id: AccountId,
    counterparty_id: AccountId,
}

#[cfg(all(test, feature = "app_api"))]
fn build_repo_state_for_tests() -> RepoTestFixture {
    use std::time::{SystemTime, UNIX_EPOCH};

    use iroha_core::{
        kura::Kura,
        query::store::LiveQueryStore,
        smartcontracts::Execute,
        state::{State, World},
    };
    use iroha_crypto::KeyPair;
    use iroha_data_model::prelude::*;
    use nonzero_ext::nonzero;

    let state = Arc::new(State::new_for_testing(
        World::new(),
        Kura::blank_kura_for_testing(),
        LiveQueryStore::start_test(),
    ));

    let initiator_keys = KeyPair::random();
    let counterparty_keys = KeyPair::random();
    let initiator_id: AccountId = AccountId::new(initiator_keys.public_key().clone());
    let counterparty_id: AccountId = AccountId::new(counterparty_keys.public_key().clone());
    let authority_id = initiator_id.clone();
    let cash_def_id: AssetDefinitionId = "usd#wonderland".parse().unwrap();
    let collateral_def_id: AssetDefinitionId = "bond#wonderland".parse().unwrap();

    let latest_block = state.view().latest_block();
    let header = iroha_data_model::block::BlockHeader::new(nonzero!(1_u64), None, None, None, 0, 0);
    let mut sblock = state.block(header);
    let mut stx = sblock.transaction();

    Register::domain(Domain::new("wonderland".parse().unwrap()))
        .execute(&authority_id, &mut stx)
        .unwrap();
    Register::account(Account::new(
        initiator_id.to_account_id("wonderland".parse().unwrap()),
    ))
    .execute(&authority_id, &mut stx)
    .unwrap();
    Register::account(Account::new(
        counterparty_id.to_account_id("wonderland".parse().unwrap()),
    ))
    .execute(&authority_id, &mut stx)
    .unwrap();
    Register::asset_definition(AssetDefinition::numeric(cash_def_id.clone()))
        .execute(&authority_id, &mut stx)
        .unwrap();
    Register::asset_definition(AssetDefinition::numeric(collateral_def_id.clone()))
        .execute(&authority_id, &mut stx)
        .unwrap();

    Mint::asset_numeric(
        numeric!(5000),
        AssetId::new(cash_def_id.clone(), counterparty_id.clone()),
    )
    .execute(&authority_id, &mut stx)
    .unwrap();
    Mint::asset_numeric(
        numeric!(6000),
        AssetId::new(collateral_def_id.clone(), initiator_id.clone()),
    )
    .execute(&authority_id, &mut stx)
    .unwrap();

    let now_ms = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap()
        .as_millis() as u64;
    let agreements = vec![
        ("alpha_repo".to_owned(), now_ms + 86_400_000),
        ("beta_repo".to_owned(), now_ms + 2 * 86_400_000),
    ];

    for (id, maturity) in &agreements {
        let agreement_id: RepoAgreementId = id.parse().unwrap();
        let instruction = RepoIsi::new(
            agreement_id,
            initiator_id.clone(),
            counterparty_id.clone(),
            None,
            RepoCashLeg {
                asset_definition_id: cash_def_id.clone(),
                quantity: numeric!(1000),
            },
            RepoCollateralLeg::new(collateral_def_id.clone(), numeric!(1100)),
            150,
            *maturity,
            RepoGovernance::with_defaults(1_500, 86_400),
        );
        instruction.execute(&authority_id, &mut stx).unwrap();
    }

    stx.apply();
    let leader = KeyPair::random();
    let _topology = iroha_core::sumeragi::network_topology::Topology::new(vec![
        iroha_data_model::peer::PeerId::new(leader.public_key().clone()),
    ]);
    let unverified = iroha_core::block::BlockBuilder::new(vec![dummy_accepted_transaction()])
        .chain(0, latest_block.as_deref())
        .sign(leader.private_key())
        .unpack(|_| {});
    let valid = unverified
        .clone()
        .validate_and_record_transactions(&mut sblock)
        .unpack(|_| {});
    let committed = valid.clone().commit_unchecked().unpack(|_| {});
    crate::test_utils::finalize_committed_block(&state, sblock, committed);

    RepoTestFixture {
        state,
        agreements,
        initiator_id,
        counterparty_id,
    }
}

