// ---------------------- Accounts listing ----------------------

#[cfg(feature = "app_api")]
#[derive(Clone)]
struct AccountListItem {
    canonical_id: String,
    display_id: String,
}

#[cfg(feature = "app_api")]
#[derive(Clone)]
enum AccountSortField {
    Id,
    Metadata(Option<iroha_data_model::prelude::Name>),
    Unsupported,
}

#[cfg(feature = "app_api")]
#[derive(Clone)]
struct AccountSortSelector {
    ascending: bool,
    field: AccountSortField,
}

#[cfg(feature = "app_api")]
fn metadata_json_to_string(j: &iroha_primitives::json::Json) -> String {
    j.get().clone()
}

#[cfg(feature = "app_api")]
fn compile_account_sort_spec(spec: &[crate::filter::SortKey]) -> Vec<AccountSortSelector> {
    let mut selectors = Vec::new();
    for sk in spec {
        let ascending = matches!(sk.order, crate::filter::Order::Asc);
        let field = if sk.key.0.as_str() == "id" {
            AccountSortField::Id
        } else if let Some(rest) = sk.key.0.strip_prefix("metadata.") {
            AccountSortField::Metadata(rest.parse().ok())
        } else {
            AccountSortField::Unsupported
        };
        selectors.push(AccountSortSelector { ascending, field });
    }
    if selectors.is_empty() {
        selectors.push(AccountSortSelector {
            ascending: true,
            field: AccountSortField::Id,
        });
    }
    selectors
}

#[cfg(feature = "app_api")]
fn account_sort_key(
    account: &iroha_data_model::account::Account,
    selectors: &[AccountSortSelector],
) -> MultiSortKey {
    let mut components = Vec::with_capacity(selectors.len());
    for selector in selectors {
        let value = match selector.field {
            AccountSortField::Id => account.id().to_string(),
            AccountSortField::Metadata(Some(ref name)) => account
                .metadata()
                .get(name)
                .map(metadata_json_to_string)
                .unwrap_or_default(),
            AccountSortField::Metadata(None) | AccountSortField::Unsupported => String::new(),
        };
        if selector.ascending {
            components.push(SortKeyComponent::asc(value));
        } else {
            components.push(SortKeyComponent::desc(value));
        }
    }
    MultiSortKey::new(components)
}

#[cfg(feature = "app_api")]
fn account_filter_object(expr: &FilterExpr, acc: &iroha_data_model::account::Account) -> bool {
    use FilterExpr as F;
    match expr {
        F::And(list) => list.iter().all(|e| account_filter_object(e, acc)),
        F::Or(list) => list.iter().any(|e| account_filter_object(e, acc)),
        F::Not(inner) => !account_filter_object(inner, acc),
        F::Eq(f, v) => {
            if f.0 == "id" {
                v.as_str().is_some_and(|s| s == acc.id().to_string())
            } else if let Some(k) = f.0.strip_prefix("metadata.") {
                if let Ok(name) = k.parse::<iroha_data_model::prelude::Name>() {
                    acc.metadata().get(&name).is_some_and(|j| {
                        j.try_into_any_norito::<norito::json::Value>().ok().as_ref() == Some(v)
                    })
                } else {
                    false
                }
            } else {
                false
            }
        }
        F::Ne(f, v) => {
            if f.0 == "id" {
                v.as_str()
                    .map(|s| s != acc.id().to_string())
                    .unwrap_or(true)
            } else if let Some(k) = f.0.strip_prefix("metadata.") {
                if let Ok(name) = k.parse::<iroha_data_model::prelude::Name>() {
                    match acc.metadata().get(&name) {
                        Some(j) => j
                            .try_into_any_norito::<norito::json::Value>()
                            .ok()
                            .map(|nv| nv != *v)
                            .unwrap_or(true),
                        None => true,
                    }
                } else {
                    true
                }
            } else {
                false
            }
        }
        F::Lt(f, v) | F::Lte(f, v) | F::Gt(f, v) | F::Gte(f, v) => {
            if let Some(k) = f.0.strip_prefix("metadata.") {
                if let (Some(vn), Ok(name)) =
                    (v.as_u64(), k.parse::<iroha_data_model::prelude::Name>())
                {
                    if let Some(j) = acc.metadata().get(&name) {
                        if let Ok(nv) = j.try_into_any_norito::<norito::json::Value>() {
                            if let Some(mn) = nv.as_u64() {
                                return match expr {
                                    F::Lt(_, _) => mn < vn,
                                    F::Lte(_, _) => mn <= vn,
                                    F::Gt(_, _) => mn > vn,
                                    F::Gte(_, _) => mn >= vn,
                                    _ => false,
                                };
                            }
                        }
                    }
                }
            }
            false
        }
        F::In(f, list) => {
            if f.0 == "id" {
                let id = acc.id().to_string();
                list.iter().filter_map(|v| v.as_str()).any(|s| s == id)
            } else if let Some(k) = f.0.strip_prefix("metadata.") {
                if let Ok(name) = k.parse::<iroha_data_model::prelude::Name>() {
                    if let Some(j) = acc.metadata().get(&name) {
                        if let Ok(nv) = j.try_into_any_norito::<norito::json::Value>() {
                            return list.iter().any(|v| v == &nv);
                        }
                    }
                }
                false
            } else {
                false
            }
        }
        F::Nin(f, list) => {
            if f.0 == "id" {
                let id = acc.id().to_string();
                list.iter().filter_map(|v| v.as_str()).all(|s| s != id)
            } else if let Some(k) = f.0.strip_prefix("metadata.") {
                if let Ok(name) = k.parse::<iroha_data_model::prelude::Name>() {
                    if let Some(j) = acc.metadata().get(&name) {
                        if let Ok(nv) = j.try_into_any_norito::<norito::json::Value>() {
                            return list.iter().all(|v| v != &nv);
                        }
                    } else {
                        return true;
                    }
                }
                true
            } else {
                false
            }
        }
        F::Exists(f) => {
            if f.0 == "id" {
                true
            } else if let Some(k) = f.0.strip_prefix("metadata.") {
                if let Ok(name) = k.parse::<iroha_data_model::prelude::Name>() {
                    acc.metadata().get(&name).is_some()
                } else {
                    false
                }
            } else {
                false
            }
        }
        F::IsNull(f) => {
            if let Some(k) = f.0.strip_prefix("metadata.") {
                if let Ok(name) = k.parse::<iroha_data_model::prelude::Name>() {
                    acc.metadata().get(&name).is_some_and(|j| {
                        j.try_into_any_norito::<norito::json::Value>()
                            .ok()
                            .is_some_and(|v| v.is_null())
                    })
                } else {
                    false
                }
            } else {
                false
            }
        }
    }
}

#[cfg(feature = "app_api")]
fn account_filter_projection(expr: &FilterExpr, proj: &AccountListItem) -> bool {
    use FilterExpr as F;
    match expr {
        F::And(list) => list.iter().all(|e| account_filter_projection(e, proj)),
        F::Or(list) => list.iter().any(|e| account_filter_projection(e, proj)),
        F::Not(inner) => !account_filter_projection(inner, proj),
        F::Eq(f, v) => match f.0.as_str() {
            "id" => v.as_str().is_some_and(|s| s == proj.canonical_id),
            _ => false,
        },
        F::Ne(f, v) => match f.0.as_str() {
            "id" => v.as_str().is_some_and(|s| s != proj.canonical_id),
            _ => false,
        },
        F::In(f, list) => match f.0.as_str() {
            "id" => list
                .iter()
                .filter_map(|v| v.as_str())
                .any(|s| s == proj.canonical_id),
            _ => false,
        },
        F::Nin(f, list) => match f.0.as_str() {
            "id" => list
                .iter()
                .filter_map(|v| v.as_str())
                .all(|s| s != proj.canonical_id),
            _ => false,
        },
        F::Exists(f) => matches!(f.0.as_str(), "id"),
        F::IsNull(_) | F::Lt(_, _) | F::Lte(_, _) | F::Gt(_, _) | F::Gte(_, _) => false,
    }
}

#[cfg(feature = "app_api")]
fn account_from_world_entry(
    entry: iroha_data_model::account::AccountEntry<'_>,
) -> iroha_data_model::account::Account {
    let details = entry.value().clone().into_inner();
    iroha_data_model::account::Account {
        id: entry.id().clone(),
        metadata: details.metadata,
        label: details.label,
        uaid: details.uaid,
        opaque_ids: details.opaque_ids,
    }
}

#[cfg(feature = "app_api")]
fn collect_subject_accounts(world: &impl WorldReadOnly) -> Vec<iroha_data_model::account::Account> {
    use std::collections::{BTreeMap, btree_map::Entry};

    let mut by_subject = BTreeMap::new();
    for entry in world.accounts_iter() {
        let account = account_from_world_entry(entry);
        let subject = account.id().subject_id();
        match by_subject.entry(subject) {
            Entry::Vacant(slot) => {
                slot.insert(account);
            }
            Entry::Occupied(_) => {}
        }
    }

    by_subject.into_values().collect()
}

#[cfg(feature = "app_api")]
fn uaid_parse_error(reason: &'static str) -> Error {
    iroha_logger::warn!(
        target: "torii.uaid.parse",
        reason,
        "invalid UAID literal rejected"
    );
    Error::Query(iroha_data_model::ValidationFail::QueryFailed(
        iroha_data_model::query::error::QueryExecutionFail::InvalidSingularParameters,
    ))
}

#[cfg(feature = "app_api")]
fn canonicalize_uaid_literal(raw: &str) -> Result<String> {
    let trimmed = raw.trim();
    if trimmed.is_empty() {
        return Err(uaid_parse_error("empty_literal"));
    }
    let hex_portion = match trimmed.get(..5) {
        Some(prefix) if prefix.eq_ignore_ascii_case("uaid:") => trimmed[5..].trim(),
        _ => trimmed,
    };
    if hex_portion.len() != 64 {
        return Err(uaid_parse_error("invalid_length"));
    }
    if !hex_portion.chars().all(|c| c.is_ascii_hexdigit()) {
        return Err(uaid_parse_error("non_hex_character"));
    }
    Ok(hex_portion.to_ascii_lowercase())
}

#[cfg(feature = "app_api")]
fn parse_uaid_literal(raw: &str) -> Result<UniversalAccountId> {
    let canonical_hex = canonicalize_uaid_literal(raw)?;
    let hash = Hash::from_str(&canonical_hex).map_err(|_| uaid_parse_error("hash_decode"))?;
    Ok(UniversalAccountId::from_hash(hash))
}

#[cfg(all(test, feature = "app_api"))]
mod uaid_parsing_tests {
    use core::str::FromStr;

    use iroha_crypto::Hash;

    use super::*;

    const SAMPLE_UAID_HEX: &str =
        "00112233445566778899aabbccddeeff00112233445566778899aabbccddeeff";

    #[test]
    fn parses_trimmed_prefixed_literal() {
        let literal = format!("  UAID:{}  ", SAMPLE_UAID_HEX.to_uppercase());
        let parsed = parse_uaid_literal(&literal).expect("parse UAID literal");
        let expected_hash = Hash::from_str(SAMPLE_UAID_HEX).expect("decode UAID hash");
        let expected = UniversalAccountId::from_hash(expected_hash);
        assert_eq!(parsed, expected);
    }

    #[test]
    fn parses_mixed_case_prefix() {
        let literal = format!("  UaId:  {}  ", SAMPLE_UAID_HEX.to_uppercase());
        let parsed = parse_uaid_literal(&literal).expect("parse UAID literal");
        let expected_hash = Hash::from_str(SAMPLE_UAID_HEX).expect("decode UAID hash");
        let expected = UniversalAccountId::from_hash(expected_hash);
        assert_eq!(parsed, expected);
    }

    #[test]
    fn rejects_invalid_inputs() {
        assert!(parse_uaid_literal("uaid:1234").is_err());
        let invalid_hex = format!("{}g", "0".repeat(63));
        assert!(parse_uaid_literal(&invalid_hex).is_err());
    }
}

