#[derive(Debug, Clone, Copy, PartialEq, Eq, Default)]
pub enum SpaceDirectoryManifestStatus {
    Active,
    Inactive,
    #[default]
    All,
}

impl core::str::FromStr for SpaceDirectoryManifestStatus {
    type Err = &'static str;

    fn from_str(s: &str) -> Result<Self, Self::Err> {
        match s.to_ascii_lowercase().as_str() {
            "active" => Ok(Self::Active),
            "inactive" => Ok(Self::Inactive),
            "all" => Ok(Self::All),
            _ => Err("status must be one of: active, inactive, all"),
        }
    }
}

struct DataspaceAliasLookup {
    aliases: BTreeMap<DataSpaceId, String>,
}

#[cfg(feature = "app_api")]
#[derive(Clone, Copy)]
struct ManifestProjection<'a> {
    dataspace_id: DataSpaceId,
    record: &'a SpaceDirectoryManifestRecord,
}

impl DataspaceAliasLookup {
    fn new(catalog: DataSpaceCatalog) -> Self {
        let aliases = catalog
            .entries()
            .iter()
            .map(|entry| (entry.id, entry.alias.clone()))
            .collect();
        Self { aliases }
    }

    fn alias_for(&self, id: DataSpaceId) -> Option<&str> {
        self.aliases.get(&id).map(String::as_str)
    }
}

/// GET /v1/space-directory/uaids/{uaid} — UAID dataspace bindings snapshot.
#[iroha_futures::telemetry_future]
#[cfg(feature = "app_api")]
pub async fn handle_v1_space_directory_bindings(
    state: Arc<CoreState>,
    axum::extract::Path(raw_uaid): axum::extract::Path<String>,
    crate::NoritoQuery(_query): crate::NoritoQuery<SpaceDirectoryBindingsQuery>,
    telemetry: MaybeTelemetry,
) -> Result<impl IntoResponse> {
    let uaid = parse_uaid_literal(&raw_uaid)?;
    record_account_literal_selection(&telemetry, ENDPOINT_SPACE_DIRECTORY_BINDINGS);
    let world = state.world_view();
    let nexus = state.nexus_snapshot();
    let alias_lookup = DataspaceAliasLookup::new(nexus.dataspace_catalog.clone());

    let mut dataspaces = Vec::new();
    if let Some(bindings) = world.uaid_dataspaces().get(&uaid) {
        for (dataspace_id, accounts) in bindings.iter() {
            let mut entry = Map::new();
            entry.insert("dataspace_id".into(), Value::from(dataspace_id.as_u64()));
            match alias_lookup.alias_for(*dataspace_id) {
                Some(alias) => entry.insert("dataspace_alias".into(), Value::from(alias)),
                None => entry.insert("dataspace_alias".into(), Value::Null),
            };
            let account_values: Vec<_> = accounts
                .iter()
                .map(|account_id| Value::from(crate::account_literal::display_literal(account_id)))
                .collect();
            entry.insert("accounts".into(), Value::Array(account_values));
            dataspaces.push(Value::Object(entry));
        }
    }

    let mut root = Map::new();
    root.insert("uaid".into(), Value::from(uaid.to_string()));
    root.insert("dataspaces".into(), Value::Array(dataspaces));

    let body = norito::json::to_json_pretty(&Value::Object(root)).map_err(|err| {
        Error::Query(iroha_data_model::ValidationFail::InternalError(
            err.to_string(),
        ))
    })?;

    let mut resp = Response::new(Body::from(body));
    resp.headers_mut().insert(
        header::CONTENT_TYPE,
        header::HeaderValue::from_static("application/json"),
    );
    Ok(resp)
}

/// GET /v1/space-directory/uaids/{uaid}/manifests — UAID manifest inventory.
#[iroha_futures::telemetry_future]
#[cfg(feature = "app_api")]
pub async fn handle_v1_space_directory_manifests(
    state: Arc<CoreState>,
    axum::extract::Path(raw_uaid): axum::extract::Path<String>,
    crate::NoritoQuery(query): crate::NoritoQuery<SpaceDirectoryManifestQuery>,
    telemetry: MaybeTelemetry,
) -> Result<impl IntoResponse> {
    let uaid = parse_uaid_literal(&raw_uaid)?;
    let filter = query.dataspace.map(DataSpaceId::new);
    let world = state.world_view();
    let nexus = state.nexus_snapshot();
    let alias_lookup = DataspaceAliasLookup::new(nexus.dataspace_catalog.clone());
    let bindings = world.uaid_dataspaces().get(&uaid);
    record_account_literal_selection(&telemetry, ENDPOINT_SPACE_DIRECTORY_MANIFESTS);
    let mut manifests = Vec::new();
    let status_filter = match query.status.as_deref() {
        Some(raw) => raw.parse().map_err(|_| {
            Error::Query(iroha_data_model::ValidationFail::QueryFailed(
                iroha_data_model::query::error::QueryExecutionFail::InvalidSingularParameters,
            ))
        })?,
        None => SpaceDirectoryManifestStatus::default(),
    };

    let offset = query.offset.unwrap_or(0);
    let limit = query.limit.filter(|&lim| lim > 0);
    let (projections, total) = if let Some(set) = world.space_directory_manifests().get(&uaid) {
        let dataspace_filter = filter;
        let total = set
            .iter()
            .filter(|&(dataspace_id, _)| match dataspace_filter {
                Some(target) => *dataspace_id == target,
                None => true,
            })
            .count();
        let status_filter = status_filter;
        let iter_filter = dataspace_filter;
        let iter = set.iter().filter_map(move |(dataspace_id, record)| {
            if let Some(target) = iter_filter {
                if *dataspace_id != target {
                    return None;
                }
            }
            if !manifest_status_matches(record, status_filter) {
                return None;
            }
            Some((
                dataspace_id.as_u64(),
                ManifestProjection {
                    dataspace_id: *dataspace_id,
                    record,
                },
            ))
        });
        let (items, _) = collect_page_streaming(iter, offset, limit, None);
        (items, total)
    } else {
        (Vec::new(), 0)
    };

    for projection in projections {
        let entry = manifest_entry_to_json(
            projection.dataspace_id,
            projection.record,
            &alias_lookup,
            bindings,
        )?;
        manifests.push(entry);
    }

    let mut root = Map::new();
    root.insert("uaid".into(), Value::from(uaid.to_string()));
    root.insert("total".into(), Value::from(total as u64));
    root.insert("manifests".into(), Value::Array(manifests));
    let body = norito::json::to_json_pretty(&Value::Object(root)).map_err(|err| {
        Error::Query(iroha_data_model::ValidationFail::InternalError(
            err.to_string(),
        ))
    })?;

    let mut resp = Response::new(Body::from(body));
    resp.headers_mut().insert(
        header::CONTENT_TYPE,
        header::HeaderValue::from_static("application/json"),
    );
    Ok(resp)
}

/// POST /v1/space-directory/manifests — enqueue a manifest publication.
#[iroha_futures::telemetry_future]
#[cfg(feature = "app_api")]
pub async fn handle_post_space_directory_manifest_publish(
    chain_id: Arc<ChainId>,
    queue: Arc<Queue>,
    state: Arc<CoreState>,
    telemetry: MaybeTelemetry,
    crate::NoritoJson(payload): crate::NoritoJson<SpaceDirectoryManifestPublishDto>,
) -> Result<impl IntoResponse> {
    use iroha_data_model::{
        isi::space_directory::PublishSpaceDirectoryManifest,
        prelude::{InstructionBox, TransactionBuilder},
    };

    let SpaceDirectoryManifestPublishDto {
        authority,
        private_key,
        mut manifest,
        reason,
    } = payload;

    if let Some(reason) = reason {
        manifest.entries.iter_mut().for_each(|entry| {
            if entry.notes.is_none() {
                entry.notes = Some(reason.clone());
            }
        });
    }

    let isi = PublishSpaceDirectoryManifest { manifest };
    let tx = TransactionBuilder::new((*chain_id).clone(), authority.into())
        .with_instructions([InstructionBox::from(isi)])
        .sign(&private_key.0);

    handle_transaction_with_metrics(
        chain_id,
        queue,
        state,
        tx,
        telemetry,
        ENDPOINT_SPACE_DIRECTORY_MANIFEST_PUBLISH,
    )
    .await
    .map(|_| (StatusCode::ACCEPTED, ()))
}

/// POST /v1/space-directory/manifests/revoke — enqueue a manifest revocation.
#[iroha_futures::telemetry_future]
#[cfg(feature = "app_api")]
pub async fn handle_post_space_directory_manifest_revoke(
    chain_id: Arc<ChainId>,
    queue: Arc<Queue>,
    state: Arc<CoreState>,
    telemetry: MaybeTelemetry,
    crate::NoritoJson(payload): crate::NoritoJson<SpaceDirectoryManifestRevokeDto>,
) -> Result<impl IntoResponse> {
    use iroha_data_model::{
        isi::space_directory::RevokeSpaceDirectoryManifest,
        prelude::{InstructionBox, TransactionBuilder},
    };

    let SpaceDirectoryManifestRevokeDto {
        authority,
        private_key,
        uaid,
        dataspace,
        revoked_epoch,
        reason,
    } = payload;
    let uaid = parse_uaid_literal(&uaid)?;
    let dataspace = DataSpaceId::new(dataspace);
    let isi = RevokeSpaceDirectoryManifest {
        uaid,
        dataspace,
        revoked_epoch,
        reason,
    };
    let tx = TransactionBuilder::new((*chain_id).clone(), authority.into())
        .with_instructions([InstructionBox::from(isi)])
        .sign(&private_key.0);

    handle_transaction_with_metrics(
        chain_id,
        queue,
        state,
        tx,
        telemetry,
        ENDPOINT_SPACE_DIRECTORY_MANIFEST_REVOKE,
    )
    .await
    .map(|_| (StatusCode::ACCEPTED, ()))
}

#[cfg(feature = "app_api")]
fn manifest_entry_to_json(
    dataspace_id: DataSpaceId,
    record: &SpaceDirectoryManifestRecord,
    alias_lookup: &DataspaceAliasLookup,
    bindings: Option<&UaidDataspaceBindings>,
) -> Result<Value> {
    let mut entry = Map::new();
    entry.insert("dataspace_id".into(), Value::from(dataspace_id.as_u64()));
    entry.insert(
        "dataspace_alias".into(),
        alias_lookup
            .alias_for(dataspace_id)
            .map(Value::from)
            .unwrap_or(Value::Null),
    );
    let manifest_value = norito::json::to_value(&record.manifest).map_err(|err| {
        Error::Query(iroha_data_model::ValidationFail::InternalError(
            err.to_string(),
        ))
    })?;
    entry.insert("manifest".into(), manifest_value);
    entry.insert(
        "manifest_hash".into(),
        Value::from(record.manifest_hash.as_ref().encode_hex::<String>()),
    );
    entry.insert("status".into(), Value::from(manifest_status(record)));
    entry.insert(
        "lifecycle".into(),
        manifest_lifecycle_json(&record.lifecycle),
    );
    entry.insert(
        "accounts".into(),
        bindings_for_dataspace(bindings, dataspace_id),
    );

    Ok(Value::Object(entry))
}

#[cfg(feature = "app_api")]
fn manifest_status(record: &SpaceDirectoryManifestRecord) -> &'static str {
    if record.lifecycle.revocation.is_some() {
        "Revoked"
    } else if record.lifecycle.expired_epoch.is_some() {
        "Expired"
    } else if record.lifecycle.activated_epoch.is_some() {
        "Active"
    } else {
        "Pending"
    }
}

#[cfg(feature = "app_api")]
fn manifest_status_matches(
    record: &SpaceDirectoryManifestRecord,
    filter: SpaceDirectoryManifestStatus,
) -> bool {
    match filter {
        SpaceDirectoryManifestStatus::All => true,
        SpaceDirectoryManifestStatus::Active => record.is_active(),
        SpaceDirectoryManifestStatus::Inactive => !record.is_active(),
    }
}

#[cfg(feature = "app_api")]
fn manifest_lifecycle_json(lifecycle: &SpaceDirectoryManifestLifecycle) -> Value {
    let mut obj = Map::new();
    match lifecycle.activated_epoch {
        Some(epoch) => obj.insert("activated_epoch".into(), Value::from(epoch)),
        None => obj.insert("activated_epoch".into(), Value::Null),
    };
    match lifecycle.expired_epoch {
        Some(epoch) => obj.insert("expired_epoch".into(), Value::from(epoch)),
        None => obj.insert("expired_epoch".into(), Value::Null),
    };
    let revocation_value = lifecycle
        .revocation
        .as_ref()
        .map(|rev| {
            let mut rev_map = Map::new();
            rev_map.insert("epoch".into(), Value::from(rev.epoch));
            match &rev.reason {
                Some(reason) => rev_map.insert("reason".into(), Value::from(reason.as_str())),
                None => rev_map.insert("reason".into(), Value::Null),
            };
            Value::Object(rev_map)
        })
        .unwrap_or(Value::Null);
    obj.insert("revocation".into(), revocation_value);
    Value::Object(obj)
}

#[cfg(feature = "app_api")]
fn bindings_for_dataspace(
    bindings: Option<&UaidDataspaceBindings>,
    dataspace_id: DataSpaceId,
) -> Value {
    if let Some(directory) = bindings {
        if let Some(accounts) = directory.iter().find_map(|(id, accounts)| {
            if *id == dataspace_id {
                Some(accounts)
            } else {
                None
            }
        }) {
            let list: Vec<Value> = accounts
                .iter()
                .map(|account_id| Value::from(crate::account_literal::display_literal(account_id)))
                .collect();
            return Value::Array(list);
        }
    }

    Value::Array(Vec::new())
}
#[cfg(all(test, feature = "app_api"))]
mod accounts_query_tests {
    use std::sync::Arc;

    use axum::http::StatusCode;
    use http_body_util::BodyExt as _;
    use iroha_core::{
        block::{BlockBuilder, ValidBlock},
        kura::Kura,
        query::store::LiveQueryStore,
        smartcontracts::Execute as _,
        state::{State, World},
        sumeragi::network_topology::Topology,
    };
    use iroha_crypto::{Algorithm, KeyPair};
    use iroha_data_model::prelude as dm;

    use super::*;

    #[tokio::test]
    async fn accounts_query_streams_without_sort() {
        let kura = Kura::blank_kura_for_testing();
        let query = LiveQueryStore::start_test();
        let state = Arc::new(State::new_for_testing(
            World::default(),
            kura.clone(),
            query,
        ));

        // Register a domain with five accounts
        let leader = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
        let _topology = Topology::new(vec![dm::PeerId::new(leader.public_key().clone())]);
        let unverified = BlockBuilder::new(vec![dummy_accepted_transaction()])
            .chain(0, state.view().latest_block().as_deref())
            .sign(leader.private_key())
            .unpack(|_| {});
        let mut st_block = state.block(unverified.header());
        let mut stx = st_block.transaction();
        let domain_id: dm::DomainId = "wonderland".parse().unwrap();
        let kp_exec = KeyPair::random_with_algorithm(Algorithm::Ed25519);
        let exec_id = dm::ScopedAccountId::new(domain_id.clone(), kp_exec.public_key().clone());
        dm::Register::domain(dm::Domain::new(domain_id.clone()))
            .execute(exec_id.account(), &mut stx)
            .unwrap();
        dm::Register::account(dm::Account::new(exec_id.clone()))
            .execute(exec_id.account(), &mut stx)
            .unwrap();
        for _ in 0..5 {
            let kp = KeyPair::random_with_algorithm(Algorithm::Ed25519);
            let acct = dm::ScopedAccountId::new(domain_id.clone(), kp.public_key().clone());
            dm::Register::account(dm::Account::new(acct))
                .execute(exec_id.account(), &mut stx)
                .unwrap();
        }
        stx.apply();
        let valid: ValidBlock = unverified
            .clone()
            .validate_and_record_transactions(&mut st_block)
            .unpack(|_| {});
        let committed = valid.clone().commit_unchecked().unpack(|_| {});
        crate::test_utils::finalize_committed_block(&state, st_block, committed);

        // Query with limit + fetch_size smaller than number of accounts.
        let env = crate::filter::QueryEnvelope {
            query: None,
            filter: None,
            select: None,
            sort: Vec::new(),
            pagination: crate::filter::Pagination {
                limit: Some(2),
                offset: 0,
            },
            fetch_size: Some(2),
        };
        let resp = handle_v1_accounts_query(
            state,
            crate::utils::extractors::NoritoJson(env),
            crate::routing::MaybeTelemetry::for_tests(),
        )
        .await
        .expect("handler ok")
        .into_response();
        assert_eq!(resp.status(), StatusCode::OK);
        let body = resp.into_body().collect().await.unwrap().to_bytes();
        let doc: norito::json::Value = norito::json::from_slice(&body).unwrap();
        assert_eq!(doc["items"].as_array().unwrap().len(), 2);
        assert_eq!(doc["total"].as_u64(), Some(4));
    }

    #[tokio::test]
    async fn accounts_query_filter_accepts_canonical_and_rejects_alias_and_non_canonical_i105_literals()
     {
        let kura = Kura::blank_kura_for_testing();
        let query = LiveQueryStore::start_test();
        let state = Arc::new(State::new_for_testing(
            World::default(),
            kura.clone(),
            query,
        ));

        let leader = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
        let _topology = Topology::new(vec![dm::PeerId::new(leader.public_key().clone())]);
        let unverified = BlockBuilder::new(vec![dummy_accepted_transaction()])
            .chain(0, state.view().latest_block().as_deref())
            .sign(leader.private_key())
            .unpack(|_| {});
        let mut st_block = state.block(unverified.header());
        let mut stx = st_block.transaction();
        let domain_id: dm::DomainId = "aliases".parse().expect("valid domain");
        let kp_exec = KeyPair::random_with_algorithm(Algorithm::Ed25519);
        let exec_id = dm::ScopedAccountId::new(domain_id.clone(), kp_exec.public_key().clone());
        dm::Register::domain(dm::Domain::new(domain_id.clone()))
            .execute(exec_id.account(), &mut stx)
            .expect("register domain");
        dm::Register::account(dm::Account::new(exec_id.clone()))
            .execute(exec_id.account(), &mut stx)
            .expect("register executor account");

        let account_keypair = KeyPair::random_with_algorithm(Algorithm::Ed25519);
        let account_id =
            dm::ScopedAccountId::new(domain_id.clone(), account_keypair.public_key().clone());
        let label = dm::AccountLabel::new(
            domain_id.clone(),
            "primary".parse().expect("valid label name"),
        );
        let account = dm::Account::new(account_id.clone()).with_label(Some(label.clone()));
        dm::Register::account(account)
            .execute(exec_id.account(), &mut stx)
            .expect("register labelled account");

        stx.apply();
        let valid: ValidBlock = unverified
            .clone()
            .validate_and_record_transactions(&mut st_block)
            .unpack(|_| {});
        let committed = valid.clone().commit_unchecked().unpack(|_| {});
        crate::test_utils::finalize_committed_block(&state, st_block, committed);

        let expected = account_id.account().to_string();
        let non_canonical_i105_literal = account_id
            .account()
            .to_account_address()
            .expect("account address")
            .to_i105()
            .expect("i105 encoding");

        let alias_literal = format!("{}@{}", label.label, domain_id);
        let alias_env = crate::filter::QueryEnvelope {
            query: None,
            filter: Some(crate::filter::FilterExpr::Eq(
                crate::filter::FieldPath("id".to_string()),
                Value::String(alias_literal.clone()),
            )),
            select: None,
            sort: Vec::new(),
            pagination: crate::filter::Pagination {
                limit: Some(8),
                offset: 0,
            },
            fetch_size: None,
        };
        let alias_result = handle_v1_accounts_query(
            state.clone(),
            crate::utils::extractors::NoritoJson(alias_env),
            crate::routing::MaybeTelemetry::for_tests(),
        )
        .await;
        assert!(
            alias_result.is_err(),
            "alias literal `{alias_literal}` must be rejected"
        );

        let canonical_env = crate::filter::QueryEnvelope {
            query: None,
            filter: Some(crate::filter::FilterExpr::Eq(
                crate::filter::FieldPath("id".to_string()),
                Value::String(expected.clone()),
            )),
            select: None,
            sort: Vec::new(),
            pagination: crate::filter::Pagination {
                limit: Some(8),
                offset: 0,
            },
            fetch_size: None,
        };
        let resp = handle_v1_accounts_query(
            state.clone(),
            crate::utils::extractors::NoritoJson(canonical_env),
            crate::routing::MaybeTelemetry::for_tests(),
        )
        .await
        .expect("handler ok")
        .into_response();
        assert_eq!(
            resp.status(),
            StatusCode::OK,
            "canonical literal `{expected}` should be accepted"
        );
        let body = resp
            .into_body()
            .collect()
            .await
            .expect("body bytes")
            .to_bytes();
        let doc: norito::json::Value = norito::json::from_slice(&body).expect("valid JSON");
        let items = doc
            .get("items")
            .and_then(norito::json::Value::as_array)
            .expect("items array");
        let ids: Vec<String> = items
            .iter()
            .filter_map(|item| {
                item.get("id")
                    .and_then(norito::json::Value::as_str)
                    .map(str::to_owned)
            })
            .collect();
        assert!(
            ids.iter().any(|id| id == &expected),
            "canonical literal `{expected}` should resolve to `{expected}`, got {ids:?}"
        );
        assert!(
            ids.iter().all(|id| !id.contains('@')),
            "response should expose canonical ids, got {ids:?}"
        );

        let i105_env = crate::filter::QueryEnvelope {
            query: None,
            filter: Some(crate::filter::FilterExpr::Eq(
                crate::filter::FieldPath("id".to_string()),
                Value::String(non_canonical_i105_literal.clone()),
            )),
            select: None,
            sort: Vec::new(),
            pagination: crate::filter::Pagination {
                limit: Some(8),
                offset: 0,
            },
            fetch_size: None,
        };
        let i105_result = handle_v1_accounts_query(
            state.clone(),
            crate::utils::extractors::NoritoJson(i105_env),
            crate::routing::MaybeTelemetry::for_tests(),
        )
        .await;
        assert!(
            i105_result.is_err(),
            "non-canonical I105 literal `{non_canonical_i105_literal}` must be rejected"
        );
    }
}

