#[cfg(feature = "app_api")]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ExplorerTransactionStatusFilter {
    Committed,
    Rejected,
}

#[cfg(feature = "app_api")]
pub fn parse_transaction_status_filter(
    raw: &str,
) -> Result<ExplorerTransactionStatusFilter, Error> {
    match raw.trim().to_ascii_lowercase().as_str() {
        "committed" => Ok(ExplorerTransactionStatusFilter::Committed),
        "rejected" => Ok(ExplorerTransactionStatusFilter::Rejected),
        _ => Err(Error::Query(iroha_data_model::ValidationFail::TooComplex)),
    }
}

#[cfg(feature = "app_api")]
struct ExplorerTransactionFilters {
    authority: Option<AccountId>,
    status: Option<ExplorerTransactionStatusFilter>,
    block: Option<u64>,
    asset_id: Option<iroha_data_model::asset::AssetId>,
}

#[cfg(feature = "app_api")]
impl ExplorerTransactionFilters {
    fn matches(
        &self,
        tx: &SignedTransaction,
        block_height: u64,
        result: &TransactionResult,
    ) -> bool {
        if let Some(expected_block) = self.block {
            if block_height != expected_block {
                return false;
            }
        }
        if let Some(authority) = &self.authority {
            if tx.authority() != authority {
                return false;
            }
        }
        if let Some(status) = &self.status {
            let committed = result.as_ref().is_ok();
            match status {
                ExplorerTransactionStatusFilter::Committed if !committed => return false,
                ExplorerTransactionStatusFilter::Rejected if committed => return false,
                _ => {}
            }
        }
        if let Some(expected) = &self.asset_id {
            if !executable_contains_asset_id(tx.instructions(), expected) {
                return false;
            }
        }
        true
    }
}

#[cfg(feature = "app_api")]
struct ExplorerInstructionFilters {
    account: Option<AccountId>,
    authority: Option<AccountId>,
    transaction_hash: Option<HashOf<TransactionEntrypoint>>,
    status: Option<ExplorerTransactionStatusFilter>,
    block: Option<u64>,
    kind: Option<ExplorerInstructionKind>,
    asset_id: Option<iroha_data_model::asset::AssetId>,
}

#[cfg(feature = "app_api")]
impl ExplorerInstructionFilters {
    fn matches_transaction(
        &self,
        tx: &SignedTransaction,
        block_height: u64,
        result: &TransactionResult,
    ) -> bool {
        if let Some(expected_block) = self.block {
            if block_height != expected_block {
                return false;
            }
        }
        if let Some(expected_hash) = &self.transaction_hash {
            if tx.hash_as_entrypoint() != *expected_hash {
                return false;
            }
        }
        if let Some(authority) = &self.authority {
            if tx.authority() != authority {
                return false;
            }
        }
        if let Some(status) = &self.status {
            let committed = result.as_ref().is_ok();
            match status {
                ExplorerTransactionStatusFilter::Committed if !committed => return false,
                ExplorerTransactionStatusFilter::Rejected if committed => return false,
                _ => {}
            }
        }
        true
    }

    fn matches_instruction(&self, kind: ExplorerInstructionKind) -> bool {
        self.kind.map_or(true, |expected| expected == kind)
    }
}

#[cfg(all(feature = "app_api", feature = "telemetry"))]
pub async fn handle_v1_explorer_metrics(
    state: Arc<CoreState>,
    kura: Arc<Kura>,
    telemetry: MaybeTelemetry,
) -> Result<AxResponse, Error> {
    if !telemetry.allows_metrics() {
        return Err(Error::telemetry_profile_forbidden(
            "v1/explorer/metrics",
            telemetry.profile(),
        ));
    }
    let dto = explorer_network_metrics_snapshot(state, kura, &telemetry).await?;
    Ok(JsonBody(dto).into_response())
}

#[cfg(all(feature = "app_api", feature = "telemetry"))]
async fn explorer_network_metrics_snapshot(
    state: Arc<CoreState>,
    kura: Arc<Kura>,
    telemetry: &MaybeTelemetry,
) -> Result<crate::explorer::ExplorerNetworkMetricsDto, Error> {
    let metrics = telemetry.metrics().await;
    let world = state.world_view();
    let peers = world.peers().len() as u64;
    let domains = world.domains_iter().count() as u64;
    let accounts = world.accounts_iter().count() as u64;
    let assets = world.assets_iter().count() as u64 + world.nfts().iter().count() as u64;
    let finalized_block = state.committed_height() as u64;

    let transactions_accepted = metrics.txs.with_label_values(&["accepted"]).get();
    let transactions_rejected = metrics.txs.with_label_values(&["rejected"]).get();
    let avg_commit_time_ms = metrics.last_commit_time_ms.get();
    let avg_commit_time = if avg_commit_time_ms == 0 {
        None
    } else {
        Some(crate::explorer::ExplorerDurationDto {
            ms: avg_commit_time_ms,
        })
    };
    let block_created_at = latest_block_created_at(kura.as_ref(), finalized_block);
    let avg_block_time = average_block_time_ms(kura.as_ref(), finalized_block, 20)
        .map(|ms| crate::explorer::ExplorerDurationDto { ms });
    Ok(crate::explorer::ExplorerNetworkMetricsDto {
        peers,
        domains,
        accounts,
        assets,
        transactions_accepted,
        transactions_rejected,
        block: finalized_block,
        block_created_at,
        finalized_block,
        avg_commit_time,
        avg_block_time,
    })
}

fn latest_block_created_at(kura: &Kura, height: u64) -> Option<String> {
    let nonzero_height = nonzero_height(height)?;
    let block = kura.get_block(nonzero_height)?;
    Some(crate::explorer::block_created_at(
        block.header().creation_time(),
    ))
}

fn average_block_time_ms(kura: &Kura, latest: u64, window: usize) -> Option<u64> {
    if latest <= 1 || window == 0 {
        return None;
    }
    let mut height = latest;
    let mut prev_ts_ms: Option<u128> = None;
    let mut deltas: Vec<u128> = Vec::new();
    let mut remaining = window;
    while height >= 1 && remaining > 0 {
        let Some(nonzero_height) = nonzero_height(height) else {
            break;
        };
        let Some(block) = kura.get_block(nonzero_height) else {
            break;
        };
        let ts_ms = block.header().creation_time().as_millis();
        if let Some(prev) = prev_ts_ms {
            if prev >= ts_ms {
                deltas.push(prev - ts_ms);
            }
        }
        prev_ts_ms = Some(ts_ms);
        if height == 1 {
            break;
        }
        height -= 1;
        remaining -= 1;
    }
    if deltas.is_empty() {
        None
    } else {
        let sum: u128 = deltas.iter().copied().sum();
        Some((sum / (deltas.len() as u128)) as u64)
    }
}

fn nonzero_height(height: u64) -> Option<NonZeroUsize> {
    let height_usize: usize = height.try_into().ok()?;
    NonZeroUsize::new(height_usize)
}

#[cfg(feature = "app_api")]
pub async fn handle_v1_explorer_transactions(
    state: Arc<CoreState>,
    telemetry: MaybeTelemetry,
    pagination: crate::explorer::ExplorerPaginationQuery,
    authority: Option<AccountId>,
    block: Option<u64>,
    status: Option<ExplorerTransactionStatusFilter>,
    asset_id: Option<iroha_data_model::asset::AssetId>,
) -> Result<AxResponse, Error> {
    let started = std::time::Instant::now();
    let response = (|| -> Result<AxResponse, Error> {
        let max_height = state.committed_height() as u64;
        record_account_literal_selection(&telemetry, ENDPOINT_EXPLORER_TRANSACTIONS);
        if let Some(block_height) = block {
            if block_height > max_height {
                let (items, pagination_meta) = crate::explorer::paginate(
                    Vec::<crate::explorer::ExplorerTransactionDto>::new(),
                    pagination.page,
                    pagination.per_page,
                );
                let empty_page = crate::explorer::ExplorerTransactionsPage {
                    pagination: pagination_meta,
                    items,
                };
                return Ok(JsonBody(empty_page).into_response());
            }
        }
        let filters = ExplorerTransactionFilters {
            authority,
            status,
            block,
            asset_id,
        };
        let (items, pagination_meta) = collect_transaction_summaries(
            state.as_ref(),
            max_height,
            &filters,
            pagination.page,
            pagination.per_page,
        )?;
        let page = crate::explorer::ExplorerTransactionsPage {
            pagination: pagination_meta,
            items,
        };
        Ok(JsonBody(page).into_response())
    })();
    record_explorer_endpoint_result(
        &telemetry,
        ENDPOINT_EXPLORER_TRANSACTIONS,
        started,
        &response,
    );
    response
}

