#[cfg(feature = "app_api")]
enum ExplorerBlockIdentifier {
    Height(NonZeroUsize),
    Hash(HashOf<BlockHeader>),
}

#[cfg(feature = "app_api")]
fn parse_block_identifier(raw: &str) -> Result<ExplorerBlockIdentifier, Error> {
    let trimmed = raw.trim();
    if let Ok(height_value) = trimmed.parse::<u64>() {
        let height_usize: usize = height_value
            .try_into()
            .map_err(|_| conversion_error("block height exceeds host pointer width".into()))?;
        let nonzero_height = NonZeroUsize::new(height_usize)
            .ok_or_else(|| conversion_error("block height must be at least 1".into()))?;
        return Ok(ExplorerBlockIdentifier::Height(nonzero_height));
    }

    let normalized = trimmed.trim_start_matches("0x");
    let hash = Hash::from_str(normalized)
        .map_err(|_| conversion_error("invalid block hash identifier".into()))?;
    Ok(ExplorerBlockIdentifier::Hash(
        HashOf::<BlockHeader>::from_untyped_unchecked(hash),
    ))
}

#[cfg(feature = "app_api")]
pub async fn handle_v1_explorer_block_detail(
    state: Arc<CoreState>,
    telemetry: MaybeTelemetry,
    identifier: String,
) -> Result<AxResponse, Error> {
    let started = std::time::Instant::now();
    let response = (|| -> Result<AxResponse, Error> {
        let lookup = parse_block_identifier(&identifier)?;
        let block = match lookup {
            ExplorerBlockIdentifier::Height(height) => state.block_by_height(height),
            ExplorerBlockIdentifier::Hash(hash) => state.block_by_hash(hash),
        }
        .ok_or_else(explorer_not_found)?;
        let dto = crate::explorer::ExplorerBlockDto::from_block(block.as_ref());
        Ok(JsonBody(dto).into_response())
    })();
    record_explorer_endpoint_result(
        &telemetry,
        ENDPOINT_EXPLORER_BLOCK_DETAIL,
        started,
        &response,
    );
    response
}

#[cfg(feature = "app_api")]
#[derive(Clone)]
struct AssetDefinitionListItem {
    id: String,
}

#[cfg(feature = "app_api")]
fn validate_accounts_filter_adapter(expr: &FilterExpr) -> Result<()> {
    use FilterExpr as F;
    match expr {
        F::And(list) | F::Or(list) => {
            for e in list {
                validate_accounts_filter_adapter(e)?;
            }
            Ok(())
        }
        F::Not(inner) => validate_accounts_filter_adapter(inner),
        F::Eq(f, v) | F::Ne(f, v) => {
            if f.0.as_str() != "id" {
                return Err(Error::Query(iroha_data_model::ValidationFail::TooComplex));
            }
            if !v.is_string() {
                return Err(Error::Query(iroha_data_model::ValidationFail::TooComplex));
            }
            Ok(())
        }
        F::In(f, list) | F::Nin(f, list) => {
            if f.0.as_str() != "id" {
                return Err(Error::Query(iroha_data_model::ValidationFail::TooComplex));
            }
            if !list.iter().all(norito::json::Value::is_string) {
                return Err(Error::Query(iroha_data_model::ValidationFail::TooComplex));
            }
            Ok(())
        }
        F::Exists(f) => {
            if f.0.as_str() != "id" {
                return Err(Error::Query(iroha_data_model::ValidationFail::TooComplex));
            }
            Ok(())
        }
        F::IsNull(_) | F::Lt(_, _) | F::Lte(_, _) | F::Gt(_, _) | F::Gte(_, _) => {
            Err(Error::Query(iroha_data_model::ValidationFail::TooComplex))
        }
    }
}

#[cfg(feature = "app_api")]
#[derive(Clone)]
enum AssetDefinitionSortField {
    Id,
    Metadata(Option<iroha_data_model::prelude::Name>),
    Unsupported,
}

#[cfg(feature = "app_api")]
#[derive(Clone)]
struct AssetDefinitionSortSelector {
    ascending: bool,
    field: AssetDefinitionSortField,
}

#[cfg(feature = "app_api")]
fn compile_asset_definition_sort_spec(
    spec: &[crate::filter::SortKey],
) -> Vec<AssetDefinitionSortSelector> {
    let mut selectors = Vec::new();
    for sk in spec {
        let ascending = matches!(sk.order, crate::filter::Order::Asc);
        let field = if sk.key.0.as_str() == "id" {
            AssetDefinitionSortField::Id
        } else if let Some(rest) = sk.key.0.strip_prefix("metadata.") {
            AssetDefinitionSortField::Metadata(rest.parse().ok())
        } else {
            AssetDefinitionSortField::Unsupported
        };
        selectors.push(AssetDefinitionSortSelector { ascending, field });
    }
    if selectors.is_empty() {
        selectors.push(AssetDefinitionSortSelector {
            ascending: true,
            field: AssetDefinitionSortField::Id,
        });
    }
    selectors
}

#[cfg(feature = "app_api")]
fn asset_definition_sort_key(
    def: &iroha_data_model::asset::definition::AssetDefinition,
    selectors: &[AssetDefinitionSortSelector],
) -> MultiSortKey {
    let mut components = Vec::with_capacity(selectors.len());
    for selector in selectors {
        let value = match selector.field {
            AssetDefinitionSortField::Id => def.id().to_string(),
            AssetDefinitionSortField::Metadata(Some(ref name)) => def
                .metadata()
                .get(name)
                .map(metadata_json_to_string)
                .unwrap_or_default(),
            AssetDefinitionSortField::Metadata(None) | AssetDefinitionSortField::Unsupported => {
                String::new()
            }
        };
        if selector.ascending {
            components.push(SortKeyComponent::asc(value));
        } else {
            components.push(SortKeyComponent::desc(value));
        }
    }
    MultiSortKey::new(components)
}

#[cfg(feature = "app_api")]
fn asset_definition_filter_object(
    expr: &FilterExpr,
    def: &iroha_data_model::asset::definition::AssetDefinition,
) -> bool {
    use FilterExpr as F;
    match expr {
        F::And(list) => list.iter().all(|e| asset_definition_filter_object(e, def)),
        F::Or(list) => list.iter().any(|e| asset_definition_filter_object(e, def)),
        F::Not(inner) => !asset_definition_filter_object(inner, def),
        F::Eq(f, v) => {
            if f.0 == "id" {
                v.as_str().is_some_and(|s| s == def.id().to_string())
            } else if let Some(k) = f.0.strip_prefix("metadata.") {
                if let Ok(name) = k.parse::<iroha_data_model::prelude::Name>() {
                    def.metadata().get(&name).is_some_and(|j| {
                        j.try_into_any_norito::<norito::json::Value>().ok().as_ref() == Some(v)
                    })
                } else {
                    false
                }
            } else {
                false
            }
        }
        F::Ne(f, v) => {
            if f.0 == "id" {
                v.as_str()
                    .map(|s| s != def.id().to_string())
                    .unwrap_or(true)
            } else if let Some(k) = f.0.strip_prefix("metadata.") {
                if let Ok(name) = k.parse::<iroha_data_model::prelude::Name>() {
                    match def.metadata().get(&name) {
                        Some(j) => j
                            .try_into_any_norito::<norito::json::Value>()
                            .ok()
                            .map(|nv| nv != *v)
                            .unwrap_or(true),
                        None => true,
                    }
                } else {
                    true
                }
            } else {
                false
            }
        }
        F::Lt(f, v) | F::Lte(f, v) | F::Gt(f, v) | F::Gte(f, v) => {
            if let Some(k) = f.0.strip_prefix("metadata.") {
                if let (Some(vn), Ok(name)) =
                    (v.as_u64(), k.parse::<iroha_data_model::prelude::Name>())
                {
                    if let Some(j) = def.metadata().get(&name) {
                        if let Ok(nv) = j.try_into_any_norito::<norito::json::Value>() {
                            if let Some(mn) = nv.as_u64() {
                                return match expr {
                                    F::Lt(_, _) => mn < vn,
                                    F::Lte(_, _) => mn <= vn,
                                    F::Gt(_, _) => mn > vn,
                                    F::Gte(_, _) => mn >= vn,
                                    _ => false,
                                };
                            }
                        }
                    }
                }
            }
            false
        }
        F::In(f, list) => {
            if f.0 == "id" {
                let id = def.id().to_string();
                list.iter().filter_map(|v| v.as_str()).any(|s| s == id)
            } else if let Some(k) = f.0.strip_prefix("metadata.") {
                if let Ok(name) = k.parse::<iroha_data_model::prelude::Name>() {
                    if let Some(j) = def.metadata().get(&name) {
                        if let Ok(nv) = j.try_into_any_norito::<norito::json::Value>() {
                            return list.iter().any(|v| v == &nv);
                        }
                    }
                }
                false
            } else {
                false
            }
        }
        F::Nin(f, list) => {
            if f.0 == "id" {
                let id = def.id().to_string();
                list.iter().filter_map(|v| v.as_str()).all(|s| s != id)
            } else if let Some(k) = f.0.strip_prefix("metadata.") {
                if let Ok(name) = k.parse::<iroha_data_model::prelude::Name>() {
                    if let Some(j) = def.metadata().get(&name) {
                        if let Ok(nv) = j.try_into_any_norito::<norito::json::Value>() {
                            return list.iter().all(|v| v != &nv);
                        }
                    } else {
                        return true;
                    }
                }
                true
            } else {
                false
            }
        }
        F::Exists(f) => {
            if f.0 == "id" {
                true
            } else if let Some(k) = f.0.strip_prefix("metadata.") {
                if let Ok(name) = k.parse::<iroha_data_model::prelude::Name>() {
                    def.metadata().get(&name).is_some()
                } else {
                    false
                }
            } else {
                false
            }
        }
        F::IsNull(f) => {
            if let Some(k) = f.0.strip_prefix("metadata.") {
                if let Ok(name) = k.parse::<iroha_data_model::prelude::Name>() {
                    def.metadata().get(&name).is_some_and(|j| {
                        j.try_into_any_norito::<norito::json::Value>()
                            .ok()
                            .is_some_and(|v| v.is_null())
                    })
                } else {
                    false
                }
            } else {
                false
            }
        }
    }
}

#[cfg(feature = "app_api")]
fn asset_definition_filter_projection(expr: &FilterExpr, proj: &AssetDefinitionListItem) -> bool {
    use FilterExpr as F;
    match expr {
        F::And(list) => list
            .iter()
            .all(|e| asset_definition_filter_projection(e, proj)),
        F::Or(list) => list
            .iter()
            .any(|e| asset_definition_filter_projection(e, proj)),
        F::Not(inner) => !asset_definition_filter_projection(inner, proj),
        F::Eq(f, v) => match f.0.as_str() {
            "id" => v.as_str().is_some_and(|s| s == proj.id),
            _ => false,
        },
        F::Ne(f, v) => match f.0.as_str() {
            "id" => v.as_str().is_some_and(|s| s != proj.id),
            _ => false,
        },
        F::In(f, list) => match f.0.as_str() {
            "id" => list.iter().filter_map(|v| v.as_str()).any(|s| s == proj.id),
            _ => false,
        },
        F::Nin(f, list) => match f.0.as_str() {
            "id" => list.iter().filter_map(|v| v.as_str()).all(|s| s != proj.id),
            _ => false,
        },
        F::Exists(f) => matches!(f.0.as_str(), "id"),
        F::IsNull(_) | F::Lt(_, _) | F::Lte(_, _) | F::Gt(_, _) | F::Gte(_, _) => false,
    }
}

/// GET /v1/assets/definitions — List asset definitions with basic pagination.
#[iroha_futures::telemetry_future]
#[cfg(feature = "app_api")]
pub async fn handle_v1_assets_definitions(
    state: Arc<CoreState>,
    crate::NoritoQuery(p): crate::NoritoQuery<ListFilterParams>,
) -> Result<impl IntoResponse> {
    let world = state.world_view();
    let definitions: Vec<_> = world.asset_definitions_iter().cloned().collect();
    drop(world);

    let sort_spec = p.sort.as_deref().map(parse_sort_spec).unwrap_or_default();
    let selectors = compile_asset_definition_sort_spec(&sort_spec);
    let cap = app_query_page_cap(&state);
    let pagination =
        enforce_app_pagination(p.limit, p.offset, cap, ENDPOINT_ASSET_DEFINITIONS_LIST)?;

    let filter_expr = p
        .filter
        .as_ref()
        .and_then(|s| norito::json::from_str::<FilterExpr>(s).ok());
    if let Some(ref expr) = filter_expr {
        crate::filter::validate_filter(expr)
            .map_err(|_| Error::Query(iroha_data_model::ValidationFail::TooComplex))?;
        validate_defs_filter_adapter(expr)?;
    }

    let filter_ref = filter_expr.as_ref();
    let mapped_iter = definitions.into_iter().filter_map({
        let selectors = selectors;
        move |def| {
            if let Some(expr) = filter_ref {
                if !asset_definition_filter_object(expr, &def) {
                    return None;
                }
            }
            let projected = AssetDefinitionListItem {
                id: def.id().to_string(),
            };
            if let Some(expr) = filter_ref {
                if !asset_definition_filter_projection(expr, &projected) {
                    return None;
                }
            }
            let key = asset_definition_sort_key(&def, &selectors);
            Some((key, projected))
        }
    });
    let (items, total) =
        collect_page_streaming(mapped_iter, pagination.offset, pagination.limit, None);

    let mut arr = Vec::with_capacity(items.len());
    for it in &items {
        let mut m = norito::json::Map::new();
        m.insert("id".into(), norito::json::Value::from(it.id.clone()));
        arr.push(norito::json::Value::Object(m));
    }
    let mut top = norito::json::Map::new();
    top.insert("items".into(), norito::json::Value::Array(arr));
    top.insert("total".into(), norito::json::Value::from(total as u64));
    let body = norito::json::to_json_pretty(&top).map_err(|e| {
        Error::Query(iroha_data_model::ValidationFail::InternalError(
            e.to_string(),
        ))
    })?;
    let mut resp = axum::response::Response::new(axum::body::Body::from(body));
    resp.headers_mut().insert(
        axum::http::header::CONTENT_TYPE,
        axum::http::HeaderValue::from_static("application/json"),
    );
    Ok(resp)
}

/// POST /v1/assets/definitions/query — JSON envelope with optional pagination/sort.
#[iroha_futures::telemetry_future]
#[cfg(feature = "app_api")]
pub async fn handle_v1_assets_definitions_query(
    state: Arc<CoreState>,
    NoritoJson(envelope): NoritoJson<crate::filter::QueryEnvelope>,
) -> Result<impl IntoResponse> {
    let world = state.world_view();
    let definitions: Vec<_> = world.asset_definitions_iter().cloned().collect();
    drop(world);

    let selectors = compile_asset_definition_sort_spec(&envelope.sort);
    let cap = app_query_page_cap(&state);
    let pagination = enforce_app_pagination(
        envelope.pagination.limit,
        envelope.pagination.offset,
        cap,
        ENDPOINT_ASSET_DEFINITIONS_QUERY,
    )?;
    let limits = app_query_limits();
    let fetch_size = limits
        .clamp_fetch_size(envelope.fetch_size)
        .map(|opt| opt.map(|val| val.min(pagination.cap)))?;

    if let Some(ref expr) = envelope.filter {
        fn depth(e: &crate::filter::FilterExpr) -> usize {
            use crate::filter::FilterExpr as F;
            match e {
                F::And(list) | F::Or(list) => 1 + list.iter().map(depth).max().unwrap_or(0),
                F::Not(inner) => 1 + depth(inner),
                _ => 1,
            }
        }
        if depth(expr) > 10 {
            return Err(Error::Query(iroha_data_model::ValidationFail::TooComplex));
        }
        crate::filter::validate_filter(expr)
            .map_err(|_| Error::Query(iroha_data_model::ValidationFail::TooComplex))?;
        validate_defs_filter_adapter(expr)?;
    }

    let filter_ref = envelope.filter.as_ref();
    let mapped_iter = definitions.into_iter().filter_map({
        let selectors = selectors;
        move |def| {
            if let Some(expr) = filter_ref {
                if !asset_definition_filter_object(expr, &def) {
                    return None;
                }
            }
            let projected = AssetDefinitionListItem {
                id: def.id().to_string(),
            };
            if let Some(expr) = filter_ref {
                if !asset_definition_filter_projection(expr, &projected) {
                    return None;
                }
            }
            let key = asset_definition_sort_key(&def, &selectors);
            Some((key, projected))
        }
    });
    let (items, total) =
        collect_page_streaming(mapped_iter, pagination.offset, pagination.limit, fetch_size);

    let mut arr = Vec::with_capacity(items.len());
    for it in &items {
        let mut m = norito::json::Map::new();
        m.insert("id".into(), norito::json::Value::from(it.id.clone()));
        arr.push(norito::json::Value::Object(m));
    }
    let mut top = norito::json::Map::new();
    top.insert("items".into(), norito::json::Value::Array(arr));
    top.insert("total".into(), norito::json::Value::from(total as u64));
    let body = norito::json::to_json_pretty(&top).map_err(|e| {
        Error::Query(iroha_data_model::ValidationFail::InternalError(
            e.to_string(),
        ))
    })?;
    let mut resp = axum::response::Response::new(axum::body::Body::from(body));
    resp.headers_mut().insert(
        axum::http::header::CONTENT_TYPE,
        axum::http::HeaderValue::from_static("application/json"),
    );
    Ok(resp)
}

#[cfg(feature = "app_api")]
fn validate_defs_filter_adapter(expr: &FilterExpr) -> Result<()> {
    use FilterExpr as F;
    match expr {
        F::And(list) | F::Or(list) => {
            for e in list {
                validate_defs_filter_adapter(e)?;
            }
            Ok(())
        }
        F::Not(inner) => validate_defs_filter_adapter(inner),
        F::Eq(f, v) | F::Ne(f, v) => {
            if f.0.as_str() != "id" {
                return Err(Error::Query(iroha_data_model::ValidationFail::TooComplex));
            }
            if !v.is_string() {
                return Err(Error::Query(iroha_data_model::ValidationFail::TooComplex));
            }
            Ok(())
        }
        F::In(f, list) | F::Nin(f, list) => {
            if f.0.as_str() != "id" {
                return Err(Error::Query(iroha_data_model::ValidationFail::TooComplex));
            }
            if !list.iter().all(norito::json::Value::is_string) {
                return Err(Error::Query(iroha_data_model::ValidationFail::TooComplex));
            }
            Ok(())
        }
        F::Exists(f) => {
            if f.0.as_str() != "id" {
                return Err(Error::Query(iroha_data_model::ValidationFail::TooComplex));
            }
            Ok(())
        }
        F::IsNull(_) | F::Lt(_, _) | F::Lte(_, _) | F::Gt(_, _) | F::Gte(_, _) => {
            Err(Error::Query(iroha_data_model::ValidationFail::TooComplex))
        }
    }
}

// ---------------------- Offline allowances listing ----------------------

#[cfg(feature = "app_api")]
#[derive(Clone, Copy, Debug, Default, PartialEq, Eq)]
enum OfflineVerdictFilterMode {
    #[default]
    Any,
    Require,
    Missing,
}

#[cfg(feature = "app_api")]
const ALLOWANCE_DEADLINE_WARNING_MS: u64 = 86_400_000;

#[cfg(feature = "app_api")]
#[derive(Clone, Copy)]
enum AllowanceDeadlineState {
    Ok,
    Warning,
    Expired,
}

#[cfg(feature = "app_api")]
impl AllowanceDeadlineState {
    const fn as_label(self) -> &'static str {
        match self {
            Self::Ok => "ok",
            Self::Warning => "warning",
            Self::Expired => "expired",
        }
    }
}

#[cfg(feature = "app_api")]
struct AllowanceDeadlineSummary {
    kind: &'static str,
    deadline_ms: u64,
    millis_remaining: i64,
    state: AllowanceDeadlineState,
}

#[cfg(feature = "app_api")]
#[derive(Clone, Debug, Default)]
struct OfflineAllowanceQueryFilters {
    controller_id: Option<String>,
    asset_id: Option<AssetId>,
    certificate_expires_before_ms: Option<u64>,
    certificate_expires_after_ms: Option<u64>,
    policy_expires_before_ms: Option<u64>,
    policy_expires_after_ms: Option<u64>,
    verdict_id_hex: Option<String>,
    verdict_mode: OfflineVerdictFilterMode,
    refresh_before_ms: Option<u64>,
    refresh_after_ms: Option<u64>,
    attestation_nonce_hex: Option<String>,
    include_expired: bool,
    now_ms: u64,
}

#[cfg(feature = "app_api")]
impl OfflineAllowanceQueryFilters {
    fn from_params(
        params: &OfflineAllowanceListParams,
        now_ms: u64,
        telemetry: &MaybeTelemetry,
        context: &'static str,
    ) -> Result<Self> {
        if params.require_verdict && params.only_missing_verdict {
            return Err(Self::conflicting_flags(
                "require_verdict",
                "only_missing_verdict",
            ));
        }
        if params.only_missing_verdict && params.verdict_id_hex.is_some() {
            return Err(Self::conflicting_flags(
                "verdict_id_hex",
                "only_missing_verdict",
            ));
        }
        let controller_id = canonicalize_query_account_literal(
            "controller_id",
            params.controller_id.as_deref(),
            telemetry,
            context,
        )?;
        let asset_id = params
            .asset_id
            .as_deref()
            .map(|raw| {
                AssetId::parse_encoded(raw)
                    .map_err(|_| Self::conversion_error("asset_id must be a valid asset id"))
            })
            .transpose()?;
        Self::validate_window(
            params.certificate_expires_after_ms,
            params.certificate_expires_before_ms,
            "certificate_expires_after_ms",
            "certificate_expires_before_ms",
        )?;
        Self::validate_window(
            params.policy_expires_after_ms,
            params.policy_expires_before_ms,
            "policy_expires_after_ms",
            "policy_expires_before_ms",
        )?;
        Self::validate_window(
            params.refresh_after_ms,
            params.refresh_before_ms,
            "refresh_after_ms",
            "refresh_before_ms",
        )?;
        let verdict_mode = if params.only_missing_verdict {
            OfflineVerdictFilterMode::Missing
        } else if params.require_verdict || params.verdict_id_hex.is_some() {
            OfflineVerdictFilterMode::Require
        } else {
            OfflineVerdictFilterMode::Any
        };
        Ok(Self {
            controller_id,
            asset_id,
            certificate_expires_before_ms: params.certificate_expires_before_ms,
            certificate_expires_after_ms: params.certificate_expires_after_ms,
            policy_expires_before_ms: params.policy_expires_before_ms,
            policy_expires_after_ms: params.policy_expires_after_ms,
            verdict_id_hex: params
                .verdict_id_hex
                .as_ref()
                .map(|value| value.to_ascii_lowercase()),
            verdict_mode,
            refresh_before_ms: params.refresh_before_ms,
            refresh_after_ms: params.refresh_after_ms,
            attestation_nonce_hex: params
                .attestation_nonce_hex
                .as_ref()
                .map(|value| value.to_ascii_lowercase()),
            include_expired: params.include_expired,
            now_ms,
        })
    }

    fn matches(&self, record: &OfflineAllowanceRecord) -> bool {
        if let Some(expected) = &self.controller_id {
            if record.certificate.controller.to_string() != *expected {
                return false;
            }
        }
        if let Some(expected) = &self.asset_id {
            if &record.certificate.allowance.asset != expected {
                return false;
            }
        }
        if let Some(max) = self.certificate_expires_before_ms {
            if record.certificate.expires_at_ms > max {
                return false;
            }
        }
        if let Some(min) = self.certificate_expires_after_ms {
            if record.certificate.expires_at_ms < min {
                return false;
            }
        }
        if let Some(max) = self.policy_expires_before_ms {
            if record.certificate.policy.expires_at_ms > max {
                return false;
            }
        }
        if let Some(min) = self.policy_expires_after_ms {
            if record.certificate.policy.expires_at_ms < min {
                return false;
            }
        }

        let verdict_hex = allowance_verdict_hex(record);
        if let Some(expected) = &self.verdict_id_hex {
            match verdict_hex.as_deref() {
                Some(actual) if actual.eq_ignore_ascii_case(expected) => {}
                _ => return false,
            }
        }

        match self.verdict_mode {
            OfflineVerdictFilterMode::Any => {}
            OfflineVerdictFilterMode::Require => {
                if verdict_hex.is_none() {
                    return false;
                }
            }
            OfflineVerdictFilterMode::Missing => {
                if verdict_hex.is_some() {
                    return false;
                }
            }
        }

        if let Some(max) = self.refresh_before_ms {
            let refresh_at = allowance_refresh_at_ms(record);
            if refresh_at.map(|value| value > max).unwrap_or(true) {
                return false;
            }
        }
        if let Some(min) = self.refresh_after_ms {
            let refresh_at = allowance_refresh_at_ms(record);
            if refresh_at.map(|value| value < min).unwrap_or(true) {
                return false;
            }
        }

        if let Some(expected) = &self.attestation_nonce_hex {
            match allowance_attestation_nonce_hex(record) {
                Some(actual) if actual.eq_ignore_ascii_case(expected) => {}
                _ => return false,
            }
        }

        if !self.include_expired {
            if record.certificate.expires_at_ms <= self.now_ms {
                return false;
            }
            if record.certificate.policy.expires_at_ms <= self.now_ms {
                return false;
            }
        }

        true
    }

    fn conflicting_flags(lhs: &'static str, rhs: &'static str) -> Error {
        Self::conversion_error(&format!("`{lhs}` cannot be combined with `{rhs}`"))
    }

    fn validate_window(
        lower: Option<u64>,
        upper: Option<u64>,
        lower_label: &'static str,
        upper_label: &'static str,
    ) -> Result<()> {
        if let (Some(min), Some(max)) = (lower, upper) {
            if min > max {
                return Err(Self::conversion_error(&format!(
                    "`{lower_label}` must be <= `{upper_label}`"
                )));
            }
        }
        Ok(())
    }

    fn conversion_error(message: &str) -> Error {
        Error::Query(iroha_data_model::ValidationFail::QueryFailed(
            iroha_data_model::query::error::QueryExecutionFail::Conversion(message.into()),
        ))
    }
}

#[cfg(feature = "app_api")]
#[derive(Clone, Debug, Default)]
struct OfflineTransferQueryFilters {
    controller_id: Option<String>,
    receiver_id: Option<String>,
    deposit_account_id: Option<String>,
    asset_id: Option<AssetId>,
    certificate_expires_before_ms: Option<u64>,
    certificate_expires_after_ms: Option<u64>,
    policy_expires_before_ms: Option<u64>,
    policy_expires_after_ms: Option<u64>,
    refresh_before_ms: Option<u64>,
    refresh_after_ms: Option<u64>,
    verdict_id_hex: Option<String>,
    certificate_id_hex: Option<String>,
    attestation_nonce_hex: Option<String>,
    platform_policy: Option<AndroidIntegrityPolicy>,
    verdict_mode: OfflineVerdictFilterMode,
}

#[cfg(feature = "app_api")]
impl OfflineTransferQueryFilters {
    fn from_params(
        params: &OfflineTransferListParams,
        telemetry: &MaybeTelemetry,
        context: &'static str,
    ) -> Result<Self> {
        if params.require_verdict && params.only_missing_verdict {
            return Err(Self::conflicting_flags(
                "require_verdict",
                "only_missing_verdict",
            ));
        }
        if params.only_missing_verdict && params.verdict_id_hex.is_some() {
            return Err(Self::conflicting_flags(
                "verdict_id_hex",
                "only_missing_verdict",
            ));
        }
        let controller_id = canonicalize_query_account_literal(
            "controller_id",
            params.controller_id.as_deref(),
            telemetry,
            context,
        )?;
        let receiver_id = canonicalize_query_account_literal(
            "receiver_id",
            params.receiver_id.as_deref(),
            telemetry,
            context,
        )?;
        let deposit_account_id = canonicalize_query_account_literal(
            "deposit_account_id",
            params.deposit_account_id.as_deref(),
            telemetry,
            context,
        )?;
        let asset_id = params
            .asset_id
            .as_deref()
            .map(|raw| {
                AssetId::parse_encoded(raw)
                    .map_err(|_| Self::conversion_error("asset_id must be a valid asset id"))
            })
            .transpose()?;
        Self::validate_window(
            params.certificate_expires_after_ms,
            params.certificate_expires_before_ms,
            "certificate_expires_after_ms",
            "certificate_expires_before_ms",
        )?;
        Self::validate_window(
            params.policy_expires_after_ms,
            params.policy_expires_before_ms,
            "policy_expires_after_ms",
            "policy_expires_before_ms",
        )?;
        Self::validate_window(
            params.refresh_after_ms,
            params.refresh_before_ms,
            "refresh_after_ms",
            "refresh_before_ms",
        )?;
        let verdict_mode = if params.only_missing_verdict {
            OfflineVerdictFilterMode::Missing
        } else if params.require_verdict || params.verdict_id_hex.is_some() {
            OfflineVerdictFilterMode::Require
        } else {
            OfflineVerdictFilterMode::Any
        };
        let platform_policy = if let Some(policy) = params.platform_policy.as_deref() {
            let parsed = AndroidIntegrityPolicy::from_str(policy).map_err(|_| {
                Self::conversion_error(
                    "platform_policy must be one of: marker_key, play_integrity, hms_safety_detect, provisioned",
                )
            })?;
            if !matches!(
                parsed,
                AndroidIntegrityPolicy::PlayIntegrity | AndroidIntegrityPolicy::HmsSafetyDetect
            ) {
                return Err(Self::conversion_error(
                    "platform_policy currently supports only play_integrity or hms_safety_detect",
                ));
            }
            Some(parsed)
        } else {
            None
        };

        Ok(Self {
            controller_id,
            receiver_id,
            deposit_account_id,
            asset_id,
            certificate_expires_before_ms: params.certificate_expires_before_ms,
            certificate_expires_after_ms: params.certificate_expires_after_ms,
            policy_expires_before_ms: params.policy_expires_before_ms,
            policy_expires_after_ms: params.policy_expires_after_ms,
            refresh_before_ms: params.refresh_before_ms,
            refresh_after_ms: params.refresh_after_ms,
            certificate_id_hex: params
                .certificate_id_hex
                .as_ref()
                .map(|value| value.to_ascii_lowercase()),
            verdict_id_hex: params
                .verdict_id_hex
                .as_ref()
                .map(|value| value.to_ascii_lowercase()),
            attestation_nonce_hex: params
                .attestation_nonce_hex
                .as_ref()
                .map(|value| value.to_ascii_lowercase()),
            platform_policy,
            verdict_mode,
        })
    }

    fn matches(&self, record: &OfflineTransferRecord) -> bool {
        if let Some(expected) = &self.controller_id {
            if record.controller.to_string() != *expected {
                return false;
            }
        }
        if let Some(expected) = &self.receiver_id {
            if record.transfer.receiver.to_string() != *expected {
                return false;
            }
        }
        if let Some(expected) = &self.deposit_account_id {
            if record.transfer.deposit_account.to_string() != *expected {
                return false;
            }
        }
        if let Some(expected) = &self.asset_id {
            if &record.transfer.balance_proof.initial_commitment.asset != expected {
                return false;
            }
        }
        let cert_expires = transfer_certificate_expires_at_ms(record);
        if let Some(max) = self.certificate_expires_before_ms {
            if cert_expires.map_or(true, |value| value > max) {
                return false;
            }
        }
        if let Some(min) = self.certificate_expires_after_ms {
            if cert_expires.map_or(true, |value| value < min) {
                return false;
            }
        }

        let policy_expires = transfer_policy_expires_at_ms(record);
        if let Some(max) = self.policy_expires_before_ms {
            if policy_expires.map_or(true, |value| value > max) {
                return false;
            }
        }
        if let Some(min) = self.policy_expires_after_ms {
            if policy_expires.map_or(true, |value| value < min) {
                return false;
            }
        }

        let refresh_at = transfer_refresh_at_ms(record);
        if let Some(max) = self.refresh_before_ms {
            if refresh_at.map_or(true, |value| value > max) {
                return false;
            }
        }
        if let Some(min) = self.refresh_after_ms {
            if refresh_at.map_or(true, |value| value < min) {
                return false;
            }
        }

        if let Some(expected) = &self.certificate_id_hex {
            match transfer_certificate_id_hex(record).as_deref() {
                Some(actual) if actual.eq_ignore_ascii_case(expected) => {}
                _ => return false,
            }
        }

        let verdict_hex = transfer_verdict_hex(record);
        if let Some(expected) = &self.verdict_id_hex {
            match verdict_hex.as_deref() {
                Some(actual) if actual.eq_ignore_ascii_case(expected) => {}
                _ => return false,
            }
        }
        if let Some(expected) = &self.attestation_nonce_hex {
            match transfer_attestation_nonce_hex(record).as_deref() {
                Some(actual) if actual.eq_ignore_ascii_case(expected) => {}
                _ => return false,
            }
        }

        if let Some(policy) = self.platform_policy {
            match record
                .platform_snapshot
                .as_ref()
                .and_then(OfflinePlatformTokenSnapshot::policy)
            {
                Some(actual) if actual == policy => {}
                _ => return false,
            }
        }

        match self.verdict_mode {
            OfflineVerdictFilterMode::Any => {}
            OfflineVerdictFilterMode::Require => {
                if verdict_hex.is_none() {
                    return false;
                }
            }
            OfflineVerdictFilterMode::Missing => {
                if verdict_hex.is_some() {
                    return false;
                }
            }
        }
        true
    }

    fn conflicting_flags(lhs: &'static str, rhs: &'static str) -> Error {
        Self::conversion_error(&format!("`{lhs}` cannot be combined with `{rhs}`"))
    }

    fn validate_window(
        lower: Option<u64>,
        upper: Option<u64>,
        lower_label: &'static str,
        upper_label: &'static str,
    ) -> Result<()> {
        if let (Some(min), Some(max)) = (lower, upper) {
            if min > max {
                return Err(Self::conversion_error(&format!(
                    "`{lower_label}` must be <= `{upper_label}`"
                )));
            }
        }
        Ok(())
    }

    fn conversion_error(message: &str) -> Error {
        Error::Query(iroha_data_model::ValidationFail::QueryFailed(
            iroha_data_model::query::error::QueryExecutionFail::Conversion(message.into()),
        ))
    }
}

#[cfg(feature = "app_api")]
fn current_unix_timestamp_ms() -> u64 {
    use core::cmp::min;
    use std::time::{SystemTime, UNIX_EPOCH};

    match SystemTime::now().duration_since(UNIX_EPOCH) {
        Ok(duration) => {
            let millis = duration.as_millis();
            let clamped = min(millis, u128::from(u64::MAX));
            clamped as u64
        }
        Err(_) => 0,
    }
}

#[cfg(feature = "app_api")]
#[derive(Clone)]
struct OfflineAllowanceListItem {
    certificate_id_hex: String,
    controller: AccountId,
    asset_id: String,
    registered_at_ms: u64,
    expires_at_ms: u64,
    policy_expires_at_ms: u64,
    refresh_at_ms: Option<u64>,
    verdict_id_hex: Option<String>,
    attestation_nonce_hex: Option<String>,
    remaining_amount: iroha_primitives::numeric::Numeric,
    record: OfflineAllowanceRecord,
}

#[cfg(feature = "app_api")]
fn allowance_refresh_at_ms(record: &OfflineAllowanceRecord) -> Option<u64> {
    record.refresh_at_ms.or(record.certificate.refresh_at_ms)
}

#[cfg(feature = "app_api")]
fn allowance_verdict_hex(record: &OfflineAllowanceRecord) -> Option<String> {
    record
        .verdict_id
        .as_ref()
        .or(record.certificate.verdict_id.as_ref())
        .map(|hash| hex::encode(hash.as_ref()))
}

#[cfg(feature = "app_api")]
fn allowance_attestation_nonce_hex(record: &OfflineAllowanceRecord) -> Option<String> {
    record
        .attestation_nonce
        .as_ref()
        .or(record.certificate.attestation_nonce.as_ref())
        .map(|hash| hex::encode(hash.as_ref()))
}

#[cfg(feature = "app_api")]
fn allowance_record_string_field(record: &OfflineAllowanceRecord, field: &str) -> Option<String> {
    match field {
        "certificate_id_hex" => Some(hex::encode(record.certificate_id().as_ref())),
        "controller_id" => Some(record.certificate.controller.to_string()),
        "asset_id" => Some(record.certificate.allowance.asset.to_string()),
        "verdict_id_hex" => allowance_verdict_hex(record),
        "attestation_nonce_hex" => allowance_attestation_nonce_hex(record),
        _ => None,
    }
}

#[cfg(feature = "app_api")]
fn allowance_record_numeric_field(record: &OfflineAllowanceRecord, field: &str) -> Option<u64> {
    match field {
        "registered_at_ms" => Some(record.registered_at_ms),
        "refresh_at_ms" => allowance_refresh_at_ms(record),
        "certificate_expires_at_ms" => Some(record.certificate.expires_at_ms),
        "policy_expires_at_ms" => Some(record.certificate.policy.expires_at_ms),
        _ => None,
    }
}

#[cfg(feature = "app_api")]
fn allowance_item_string_field(item: &OfflineAllowanceListItem, field: &str) -> Option<String> {
    match field {
        "certificate_id_hex" => Some(item.certificate_id_hex.clone()),
        "controller_id" => Some(item.controller.to_string()),
        "asset_id" => Some(item.asset_id.clone()),
        "verdict_id_hex" => item.verdict_id_hex.clone(),
        "attestation_nonce_hex" => item.attestation_nonce_hex.clone(),
        _ => None,
    }
}

#[cfg(feature = "app_api")]
fn transfer_record_string_field(record: &OfflineTransferRecord, field: &str) -> Option<String> {
    match field {
        "bundle_id_hex" => Some(hex::encode(record.transfer.bundle_id.as_ref())),
        "controller_id" => Some(record.controller.to_string()),
        "receiver_id" => Some(record.transfer.receiver.to_string()),
        "deposit_account_id" => Some(record.transfer.deposit_account.to_string()),
        "asset_id" => record
            .transfer
            .receipts
            .first()
            .map(|receipt| receipt.asset.to_string()),
        "status" => Some(record.status.as_label().into()),
        "rejection_reason" => record.rejection_reason.clone(),
        "certificate_id_hex" => transfer_certificate_id_hex(record),
        "verdict_id_hex" => transfer_verdict_hex(record),
        "attestation_nonce_hex" => transfer_attestation_nonce_hex(record),
        "platform_policy" => transfer_platform_policy_label(record),
        _ => None,
    }
}

#[cfg(feature = "app_api")]
fn transfer_record_numeric_field(record: &OfflineTransferRecord, field: &str) -> Option<u64> {
    match field {
        "receipt_count" => Some(u64::try_from(record.transfer.receipts.len()).unwrap_or(u64::MAX)),
        "recorded_at_ms" => Some(record.recorded_at_ms),
        "recorded_at_height" => Some(record.recorded_at_height),
        "archived_at_height" => record.archived_at_height,
        "certificate_expires_at_ms" => transfer_certificate_expires_at_ms(record),
        "policy_expires_at_ms" => transfer_policy_expires_at_ms(record),
        "refresh_at_ms" => transfer_refresh_at_ms(record),
        _ => None,
    }
}

#[cfg(feature = "app_api")]
fn allowance_item_numeric_field(item: &OfflineAllowanceListItem, field: &str) -> Option<u64> {
    match field {
        "registered_at_ms" => Some(item.registered_at_ms),
        "refresh_at_ms" => item.refresh_at_ms,
        "certificate_expires_at_ms" => Some(item.expires_at_ms),
        "policy_expires_at_ms" => Some(item.policy_expires_at_ms),
        _ => None,
    }
}

#[cfg(feature = "app_api")]
fn allowance_deadline_summary(
    item: &OfflineAllowanceListItem,
    now_ms: u64,
) -> Option<AllowanceDeadlineSummary> {
    let deadlines = [
        ("refresh", item.refresh_at_ms),
        ("policy", Some(item.policy_expires_at_ms)),
        ("certificate", Some(item.expires_at_ms)),
    ];

    for (kind, maybe_deadline) in deadlines {
        let Some(deadline_ms) = maybe_deadline else {
            continue;
        };
        if deadline_ms == 0 {
            continue;
        }
        let deadline_i128 = i128::from(deadline_ms);
        let now_i128 = i128::from(now_ms);
        let remaining = deadline_i128 - now_i128;
        let (state, remaining_millis) = if remaining <= 0 {
            (
                AllowanceDeadlineState::Expired,
                clamp_i128_to_i64(remaining),
            )
        } else if deadline_ms.saturating_sub(now_ms) <= ALLOWANCE_DEADLINE_WARNING_MS {
            (
                AllowanceDeadlineState::Warning,
                clamp_i128_to_i64(remaining),
            )
        } else {
            (AllowanceDeadlineState::Ok, clamp_i128_to_i64(remaining))
        };
        return Some(AllowanceDeadlineSummary {
            kind,
            deadline_ms,
            millis_remaining: remaining_millis,
            state,
        });
    }
    None
}

#[cfg(feature = "app_api")]
fn clamp_i128_to_i64(value: i128) -> i64 {
    let min = i128::from(i64::MIN);
    let max = i128::from(i64::MAX);
    value.clamp(min, max) as i64
}

