#[cfg(feature = "app_api")]
fn offline_allowance_filter_object(expr: &FilterExpr, record: &OfflineAllowanceRecord) -> bool {
    use FilterExpr as F;
    match expr {
        F::And(list) => list
            .iter()
            .all(|e| offline_allowance_filter_object(e, record)),
        F::Or(list) => list
            .iter()
            .any(|e| offline_allowance_filter_object(e, record)),
        F::Not(inner) => !offline_allowance_filter_object(inner, record),
        F::Eq(field, value) => {
            let key = field.0.as_str();
            if let Some(actual) = allowance_record_string_field(record, key) {
                value.as_str().is_some_and(|candidate| {
                    if allowance_hex_field(key) {
                        candidate.eq_ignore_ascii_case(&actual)
                    } else {
                        candidate == actual
                    }
                })
            } else if let Some(actual) = allowance_record_numeric_field(record, key) {
                value.as_u64().is_some_and(|ts| ts == actual)
            } else {
                false
            }
        }
        F::Ne(field, value) => {
            let key = field.0.as_str();
            if let Some(actual) = allowance_record_string_field(record, key) {
                value
                    .as_str()
                    .map(|candidate| {
                        if allowance_hex_field(key) {
                            !candidate.eq_ignore_ascii_case(&actual)
                        } else {
                            candidate != actual
                        }
                    })
                    .unwrap_or(true)
            } else if let Some(actual) = allowance_record_numeric_field(record, key) {
                value.as_u64().map(|ts| ts != actual).unwrap_or(true)
            } else {
                false
            }
        }
        F::Lt(field, value) | F::Lte(field, value) | F::Gt(field, value) | F::Gte(field, value) => {
            let key = field.0.as_str();
            let Some(current) = allowance_record_numeric_field(record, key) else {
                return false;
            };
            let Some(target) = value.as_u64() else {
                return false;
            };
            match expr {
                F::Lt(_, _) => current < target,
                F::Lte(_, _) => current <= target,
                F::Gt(_, _) => current > target,
                F::Gte(_, _) => current >= target,
                _ => false,
            }
        }
        F::In(field, list) => {
            let key = field.0.as_str();
            let Some(actual) = allowance_record_string_field(record, key) else {
                return false;
            };
            list.iter().filter_map(|v| v.as_str()).any(|candidate| {
                if allowance_hex_field(key) {
                    candidate.eq_ignore_ascii_case(&actual)
                } else {
                    candidate == actual
                }
            })
        }
        F::Nin(field, list) => {
            let key = field.0.as_str();
            let Some(actual) = allowance_record_string_field(record, key) else {
                return false;
            };
            list.iter().filter_map(|v| v.as_str()).all(|candidate| {
                if allowance_hex_field(key) {
                    !candidate.eq_ignore_ascii_case(&actual)
                } else {
                    candidate != actual
                }
            })
        }
        F::Exists(field) => matches!(
            field.0.as_str(),
            "certificate_id_hex" | "controller_id" | "asset_id" | "registered_at_ms"
        ),
        F::IsNull(_) => false,
    }
}

#[cfg(feature = "app_api")]
