#[iroha_futures::telemetry_future]
#[cfg(feature = "app_api")]
pub async fn handle_v1_offline_allowances_query(
    state: Arc<CoreState>,
    NoritoJson(mut envelope): NoritoJson<crate::filter::QueryEnvelope>,
    telemetry: MaybeTelemetry,
) -> Result<impl IntoResponse> {
    let world = state.world_view();
    let records: Vec<_> = world
        .offline_allowances()
        .iter()
        .map(|(_, record)| record.clone())
        .collect();

    let selectors = compile_offline_allowance_sort_spec(&envelope.sort);
    let response_now_ms = current_unix_timestamp_ms();

    if let Some(expr) = envelope.filter.as_mut() {
        fn depth(expr: &FilterExpr) -> usize {
            match expr {
                FilterExpr::And(list) | FilterExpr::Or(list) => {
                    1 + list.iter().map(depth).max().unwrap_or(0)
                }
                FilterExpr::Not(inner) => 1 + depth(inner),
                _ => 1,
            }
        }
        if depth(expr) > 10 {
            return Err(Error::Query(iroha_data_model::ValidationFail::TooComplex));
        }
        crate::filter::validate_filter(expr)
            .map_err(|_| Error::Query(iroha_data_model::ValidationFail::TooComplex))?;
        validate_offline_allowances_filter_adapter(expr)?;
        canonicalize_offline_allowance_filter_literals(
            expr,
            &telemetry,
            ENDPOINT_OFFLINE_ALLOWANCES_QUERY,
        )?;
    }

    record_account_literal_selection(&telemetry, ENDPOINT_OFFLINE_ALLOWANCES_QUERY);
    let cap = app_query_page_cap(&state);
    let pagination = enforce_app_pagination(
        envelope.pagination.limit,
        envelope.pagination.offset,
        cap,
        ENDPOINT_OFFLINE_ALLOWANCES_QUERY,
    )?;
    let limits = app_query_limits();
    let fetch_size = limits
        .clamp_fetch_size(envelope.fetch_size)
        .map(|opt| opt.map(|val| val.min(pagination.cap)))?;

    let filter_ref = envelope.filter.as_ref();
    let projection_ref = envelope.filter.as_ref();
    let mapped_iter = records.into_iter().filter_map({
        let selectors = selectors;
        move |record| {
            if let Some(expr) = filter_ref {
                if !offline_allowance_filter_object(expr, &record) {
                    return None;
                }
            }
            let item = OfflineAllowanceListItem::from(record);
            if let Some(expr) = projection_ref {
                if !offline_allowance_filter_projection(expr, &item) {
                    return None;
                }
            }
            let key = offline_allowance_sort_key(&item.record, &selectors);
            Some((key, item))
        }
    });
    let (items, total) =
        collect_page_streaming(mapped_iter, pagination.offset, pagination.limit, fetch_size);

    let mut arr = Vec::with_capacity(items.len());
    for item in &items {
        let value = offline_allowance_item_to_json(item, response_now_ms)?;
        arr.push(value);
    }
    let mut top = Map::new();
    top.insert("items".into(), Value::Array(arr));
    top.insert("total".into(), Value::from(total as u64));
    let body = norito::json::to_json_pretty(&top).map_err(|e| {
        Error::Query(iroha_data_model::ValidationFail::InternalError(
            e.to_string(),
        ))
    })?;
    let mut resp = axum::response::Response::new(axum::body::Body::from(body));
    resp.headers_mut().insert(
        axum::http::header::CONTENT_TYPE,
        axum::http::HeaderValue::from_static("application/json"),
    );
    Ok(resp)
}

