#[cfg(feature = "app_api")]
#[derive(Clone)]
enum OfflineReceiptSortField {
    RecordedAt,
    BundleId,
    TxId,
    CertificateId,
    Controller,
    Receiver,
    InvoiceId,
    Asset,
    Counter,
    Amount,
    Unsupported,
}

#[cfg(feature = "app_api")]
#[derive(Clone)]
struct OfflineReceiptSortSelector {
    ascending: bool,
    field: OfflineReceiptSortField,
}

#[cfg(feature = "app_api")]
fn compile_offline_receipt_sort_spec(
    spec: &[crate::filter::SortKey],
) -> Vec<OfflineReceiptSortSelector> {
    let mut selectors = Vec::new();
    for sk in spec {
        let ascending = matches!(sk.order, crate::filter::Order::Asc);
        let field = match sk.key.0.as_str() {
            "recorded_at_ms" => OfflineReceiptSortField::RecordedAt,
            "bundle_id_hex" => OfflineReceiptSortField::BundleId,
            "tx_id_hex" => OfflineReceiptSortField::TxId,
            "certificate_id_hex" => OfflineReceiptSortField::CertificateId,
            "controller_id" => OfflineReceiptSortField::Controller,
            "receiver_id" => OfflineReceiptSortField::Receiver,
            "invoice_id" => OfflineReceiptSortField::InvoiceId,
            "asset_id" => OfflineReceiptSortField::Asset,
            "counter" => OfflineReceiptSortField::Counter,
            "amount" => OfflineReceiptSortField::Amount,
            _ => OfflineReceiptSortField::Unsupported,
        };
        selectors.push(OfflineReceiptSortSelector { ascending, field });
    }
    if selectors.is_empty() {
        selectors.push(OfflineReceiptSortSelector {
            ascending: false,
            field: OfflineReceiptSortField::RecordedAt,
        });
    }
    selectors
}

#[cfg(feature = "app_api")]
fn offline_receipt_sort_key(
    item: &OfflineReceiptListItem,
    selectors: &[OfflineReceiptSortSelector],
) -> MultiSortKey {
    let mut components = Vec::with_capacity(selectors.len());
    for selector in selectors {
        let component = match selector.field {
            OfflineReceiptSortField::RecordedAt => {
                let numeric = iroha_primitives::numeric::Numeric::from(item.recorded_at_ms);
                if selector.ascending {
                    SortKeyComponent::asc(numeric)
                } else {
                    SortKeyComponent::desc(numeric)
                }
            }
            OfflineReceiptSortField::BundleId => {
                let value = item.bundle_id_hex.clone();
                if selector.ascending {
                    SortKeyComponent::asc(value)
                } else {
                    SortKeyComponent::desc(value)
                }
            }
            OfflineReceiptSortField::TxId => {
                let value = item.tx_id_hex.clone();
                if selector.ascending {
                    SortKeyComponent::asc(value)
                } else {
                    SortKeyComponent::desc(value)
                }
            }
            OfflineReceiptSortField::CertificateId => {
                let value = item.certificate_id_hex.clone();
                if selector.ascending {
                    SortKeyComponent::asc(value)
                } else {
                    SortKeyComponent::desc(value)
                }
            }
            OfflineReceiptSortField::Controller => {
                let value = item.controller_id.clone();
                if selector.ascending {
                    SortKeyComponent::asc(value)
                } else {
                    SortKeyComponent::desc(value)
                }
            }
            OfflineReceiptSortField::Receiver => {
                let value = item.receiver_id.clone();
                if selector.ascending {
                    SortKeyComponent::asc(value)
                } else {
                    SortKeyComponent::desc(value)
                }
            }
            OfflineReceiptSortField::InvoiceId => {
                let value = item.invoice_id.clone();
                if selector.ascending {
                    SortKeyComponent::asc(value)
                } else {
                    SortKeyComponent::desc(value)
                }
            }
            OfflineReceiptSortField::Asset => {
                let value = item.asset_id.clone();
                if selector.ascending {
                    SortKeyComponent::asc(value)
                } else {
                    SortKeyComponent::desc(value)
                }
            }
            OfflineReceiptSortField::Counter => {
                let numeric = iroha_primitives::numeric::Numeric::from(item.counter);
                if selector.ascending {
                    SortKeyComponent::asc(numeric)
                } else {
                    SortKeyComponent::desc(numeric)
                }
            }
            OfflineReceiptSortField::Amount => {
                let numeric = item.amount.clone();
                if selector.ascending {
                    SortKeyComponent::asc(numeric)
                } else {
                    SortKeyComponent::desc(numeric)
                }
            }
            OfflineReceiptSortField::Unsupported => {
                if selector.ascending {
                    SortKeyComponent::asc(String::new())
                } else {
                    SortKeyComponent::desc(String::new())
                }
            }
        };
        components.push(component);
    }
    MultiSortKey::new(components)
}

#[cfg(feature = "app_api")]
fn validate_offline_receipts_filter_adapter(expr: &FilterExpr) -> Result<()> {
    use FilterExpr as F;
    const STRING_FIELDS: &[&str] = &[
        "bundle_id_hex",
        "tx_id_hex",
        "certificate_id_hex",
        "controller_id",
        "receiver_id",
        "asset_id",
        "invoice_id",
        "amount",
    ];
    const NUMERIC_FIELDS: &[&str] = &["counter", "recorded_at_ms", "recorded_at_height"];
    match expr {
        F::And(list) | F::Or(list) => {
            for e in list {
                validate_offline_receipts_filter_adapter(e)?;
            }
            Ok(())
        }
        F::Not(inner) => validate_offline_receipts_filter_adapter(inner),
        F::Eq(field, value) | F::Ne(field, value) => {
            let key = field.0.as_str();
            if STRING_FIELDS.contains(&key) && value.is_string() {
                return Ok(());
            }
            if NUMERIC_FIELDS.contains(&key) && value.as_u64().is_some() {
                return Ok(());
            }
            Err(Error::Query(iroha_data_model::ValidationFail::TooComplex))
        }
        F::In(field, list) | F::Nin(field, list) => {
            let key = field.0.as_str();
            if STRING_FIELDS.contains(&key) && list.iter().all(norito::json::Value::is_string) {
                return Ok(());
            }
            if NUMERIC_FIELDS.contains(&key) && list.iter().all(|v| v.as_u64().is_some()) {
                return Ok(());
            }
            Err(Error::Query(iroha_data_model::ValidationFail::TooComplex))
        }
        F::Exists(field) => {
            let key = field.0.as_str();
            if STRING_FIELDS.contains(&key) || NUMERIC_FIELDS.contains(&key) {
                return Ok(());
            }
            Err(Error::Query(iroha_data_model::ValidationFail::TooComplex))
        }
        F::Lt(field, value) | F::Lte(field, value) | F::Gt(field, value) | F::Gte(field, value) => {
            let key = field.0.as_str();
            if NUMERIC_FIELDS.contains(&key) && value.as_u64().is_some() {
                return Ok(());
            }
            Err(Error::Query(iroha_data_model::ValidationFail::TooComplex))
        }
        F::IsNull(_) => Err(Error::Query(iroha_data_model::ValidationFail::TooComplex)),
    }
}

#[cfg(feature = "app_api")]
fn receipt_item_string_field(item: &OfflineReceiptListItem, field: &str) -> Option<String> {
    match field {
        "bundle_id_hex" => Some(item.bundle_id_hex.clone()),
        "tx_id_hex" => Some(item.tx_id_hex.clone()),
        "certificate_id_hex" => Some(item.certificate_id_hex.clone()),
        "controller_id" => Some(item.controller_id.clone()),
        "receiver_id" => Some(item.receiver_id.clone()),
        "asset_id" => Some(item.asset_id.clone()),
        "invoice_id" => Some(item.invoice_id.clone()),
        "amount" => Some(item.amount.to_string()),
        _ => None,
    }
}

#[cfg(feature = "app_api")]
fn receipt_item_numeric_field(item: &OfflineReceiptListItem, field: &str) -> Option<u64> {
    match field {
        "counter" => Some(item.counter),
        "recorded_at_ms" => Some(item.recorded_at_ms),
        "recorded_at_height" => Some(item.recorded_at_height),
        _ => None,
    }
}

#[cfg(feature = "app_api")]
fn receipt_hex_field(field: &str) -> bool {
    matches!(field, "bundle_id_hex" | "tx_id_hex" | "certificate_id_hex")
}

#[cfg(feature = "app_api")]
fn offline_receipt_filter_object(expr: &FilterExpr, item: &OfflineReceiptListItem) -> bool {
    use FilterExpr as F;
    match expr {
        F::And(list) => list.iter().all(|e| offline_receipt_filter_object(e, item)),
        F::Or(list) => list.iter().any(|e| offline_receipt_filter_object(e, item)),
        F::Not(inner) => !offline_receipt_filter_object(inner, item),
        F::Eq(field, value) => {
            let key = field.0.as_str();
            if let Some(actual) = receipt_item_string_field(item, key) {
                return value
                    .as_str()
                    .map(|candidate| {
                        if receipt_hex_field(key) {
                            candidate.eq_ignore_ascii_case(&actual)
                        } else {
                            candidate == actual
                        }
                    })
                    .unwrap_or(false);
            }
            if let Some(actual) = receipt_item_numeric_field(item, key) {
                return value
                    .as_u64()
                    .map(|target| target == actual)
                    .unwrap_or(false);
            }
            false
        }
        F::Ne(field, value) => {
            let key = field.0.as_str();
            if let Some(actual) = receipt_item_string_field(item, key) {
                return value
                    .as_str()
                    .map(|candidate| {
                        if receipt_hex_field(key) {
                            !candidate.eq_ignore_ascii_case(&actual)
                        } else {
                            candidate != actual
                        }
                    })
                    .unwrap_or(true);
            }
            if let Some(actual) = receipt_item_numeric_field(item, key) {
                return value
                    .as_u64()
                    .map(|target| target != actual)
                    .unwrap_or(true);
            }
            false
        }
        F::Lt(field, value) | F::Lte(field, value) | F::Gt(field, value) | F::Gte(field, value) => {
            let key = field.0.as_str();
            let Some(current) = receipt_item_numeric_field(item, key) else {
                return false;
            };
            let Some(target) = value.as_u64() else {
                return false;
            };
            match expr {
                F::Lt(_, _) => current < target,
                F::Lte(_, _) => current <= target,
                F::Gt(_, _) => current > target,
                F::Gte(_, _) => current >= target,
                _ => false,
            }
        }
        F::In(field, list) => {
            let key = field.0.as_str();
            let Some(actual) = receipt_item_string_field(item, key) else {
                return false;
            };
            list.iter().filter_map(|v| v.as_str()).any(|candidate| {
                if receipt_hex_field(key) {
                    candidate.eq_ignore_ascii_case(&actual)
                } else {
                    candidate == actual
                }
            })
        }
        F::Nin(field, list) => {
            let key = field.0.as_str();
            let Some(actual) = receipt_item_string_field(item, key) else {
                return false;
            };
            list.iter().filter_map(|v| v.as_str()).all(|candidate| {
                if receipt_hex_field(key) {
                    !candidate.eq_ignore_ascii_case(&actual)
                } else {
                    candidate != actual
                }
            })
        }
        F::Exists(field) => matches!(
            field.0.as_str(),
            "bundle_id_hex"
                | "tx_id_hex"
                | "certificate_id_hex"
                | "controller_id"
                | "receiver_id"
                | "asset_id"
                | "invoice_id"
                | "amount"
                | "counter"
                | "recorded_at_ms"
                | "recorded_at_height"
        ),
        F::IsNull(_) => false,
    }
}

