    #[cfg(feature = "app_api")]
    #[test]
    fn offline_transfer_filters_cover_certificate_metadata() {
        let record = sample_transfer_record();
        let certificate_hex = transfer_certificate_id_hex(&record).expect("certificate id");
        let verdict_hex = transfer_verdict_hex(&record).expect("verdict");
        let refresh_at = transfer_refresh_at_ms(&record).expect("refresh");

        let cert_expr = FilterExpr::Eq(
            FieldPath("certificate_id_hex".into()),
            Value::from(certificate_hex.clone()),
        );
        assert!(offline_transfer_filter_object(&cert_expr, &record));
        let item = OfflineTransferSummary::from(record.clone());
        assert!(offline_transfer_filter_projection(&cert_expr, &item));

        let verdict_expr = FilterExpr::Eq(
            FieldPath("verdict_id_hex".into()),
            Value::from(verdict_hex.to_ascii_uppercase()),
        );
        assert!(offline_transfer_filter_object(&verdict_expr, &record));
        let item = OfflineTransferSummary::from(record.clone());
        assert!(offline_transfer_filter_projection(&verdict_expr, &item));

        let refresh_expr = FilterExpr::Gt(
            FieldPath("refresh_at_ms".into()),
            Value::from(refresh_at - 1),
        );
        assert!(offline_transfer_filter_object(&refresh_expr, &record));
        let item = OfflineTransferSummary::from(record.clone());
        assert!(offline_transfer_filter_projection(&refresh_expr, &item));

        let platform_expr = FilterExpr::Eq(
            FieldPath("platform_policy".into()),
            Value::from("play_integrity"),
        );
        assert!(offline_transfer_filter_object(&platform_expr, &record));
        let item = OfflineTransferSummary::from(record.clone());
        assert!(offline_transfer_filter_projection(&platform_expr, &item));

        let mut rejected = record;
        rejected.status = OfflineTransferStatus::Rejected;
        rejected.rejection_reason = Some("allowance_exceeded".into());
        let rejection_expr = FilterExpr::Eq(
            FieldPath("rejection_reason".into()),
            Value::from("allowance_exceeded"),
        );
        assert!(offline_transfer_filter_object(&rejection_expr, &rejected));
        let item = OfflineTransferSummary::from(rejected);
        assert!(offline_transfer_filter_projection(&rejection_expr, &item));
    }

