    #[cfg(feature = "app_api")]
    #[test]
    fn offline_transfer_filter_canonicalizes_all_account_fields() {
        use iroha_test_samples::{ALICE_ID, BOB_ID, CARPENTER_ID};

        let controller = crate::account_literal::display_literal(&ALICE_ID);
        let receiver = crate::account_literal::display_literal(&BOB_ID);
        let deposit = crate::account_literal::display_literal(&CARPENTER_ID);

        let mut expr = FilterExpr::And(vec![
            FilterExpr::Eq(FieldPath("controller_id".into()), Value::from(controller)),
            FilterExpr::Eq(FieldPath("receiver_id".into()), Value::from(receiver)),
            FilterExpr::Eq(FieldPath("deposit_account_id".into()), Value::from(deposit)),
        ]);

        canonicalize_offline_transfer_filter_literals(
            &mut expr,
            &MaybeTelemetry::for_tests(),
            ENDPOINT_OFFLINE_TRANSFERS_LIST,
        )
        .unwrap();

        if let FilterExpr::And(list) = expr {
            let mut literals = list.into_iter().map(|subexpr| match subexpr {
                FilterExpr::Eq(_, value) => value
                    .as_str()
                    .map(ToString::to_string)
                    .expect("eq expression should contain string"),
                other => panic!("unexpected expression {other:?}"),
            });
            let expected_controller = ALICE_ID.to_string();
            let expected_receiver = BOB_ID.to_string();
            let expected_deposit = CARPENTER_ID.to_string();
            assert_eq!(
                literals.next().as_deref(),
                Some(expected_controller.as_str())
            );
            assert_eq!(literals.next().as_deref(), Some(expected_receiver.as_str()));
            assert_eq!(literals.next().as_deref(), Some(expected_deposit.as_str()));
        } else {
            panic!("expected And expression after canonicalization");
        }
    }

