/// Request payload for applying a Nexus lane lifecycle plan.
#[derive(
    Clone,
    Debug,
    crate::json_macros::JsonDeserialize,
    norito::derive::NoritoDeserialize,
    crate::json_macros::JsonSerialize,
    norito::derive::NoritoSerialize,
)]
pub struct LaneLifecyclePlanDto {
    /// Lane metadata to add or replace.
    #[norito(default)]
    pub additions: Vec<LaneConfig>,
    /// Lane identifiers to retire.
    #[norito(default)]
    pub retire: Vec<LaneId>,
}

impl LaneLifecyclePlanDto {
    #[must_use]
    pub fn into_plan(self) -> LaneLifecyclePlan {
        LaneLifecyclePlan {
            additions: self.additions,
            retire: self.retire,
        }
    }
}

/// Apply a Nexus lane lifecycle plan and refresh queue routing/telemetry.
pub async fn handle_post_nexus_lane_lifecycle(
    state: Arc<CoreState>,
    queue: Arc<Queue>,
    plan: LaneLifecyclePlanDto,
) -> Result<impl IntoResponse> {
    let nexus_before = state.nexus_snapshot();
    if let Err(err) = crate::ensure_nexus_lanes_enabled(
        nexus_before.enabled,
        iroha_torii_shared::uri::NEXUS_LANE_LIFECYCLE,
    ) {
        #[cfg(feature = "telemetry")]
        {
            state.telemetry.record_lane_lifecycle_outcome("disabled");
        }
        return Err(err);
    }

    let plan = plan.into_plan();
    state
        .apply_lane_lifecycle_shared(&plan)
        .map_err(|err| Error::LaneLifecycle {
            reason: err.to_string(),
        })?;

    let nexus = state.nexus_snapshot();
    let lane_compliance = queue.lane_compliance_engine();
    queue.reconfigure_nexus_with_state(&nexus, state.as_ref(), lane_compliance);

    let mut payload = norito::json::Map::new();
    payload.insert("ok".into(), norito::json::Value::from(true));
    payload.insert(
        "lane_count".into(),
        norito::json::Value::from(nexus.lane_catalog.lane_count().get()),
    );
    Ok((
        StatusCode::ACCEPTED,
        utils::NoritoJsonBody(norito::json::Value::Object(payload)),
    ))
}

pub mod block {
    //! Blocks stream handler

    use super::*;
    use crate::{block, stream::WebSocketNorito};

    /// Type for any error during blocks streaming
    #[derive(Debug, displaydoc::Display, thiserror::Error)]
    enum Error {
        /// Block consumption resulted in an error: {_0}
        Consumer(#[source] block::Error),
        /// Connection is closed
        Close,
    }

    impl From<block::Error> for Error {
        fn from(error: block::Error) -> Self {
            match error {
                block::Error::Stream(crate::stream::Error::Closed) => Self::Close,
                other => Self::Consumer(other),
            }
        }
    }

    type Result<T> = core::result::Result<T, Error>;

    #[iroha_futures::telemetry_future]
    pub async fn handle_blocks_stream(
        kura: Arc<Kura>,
        stream: WebSocket,
        ws_message_timeout: std::time::Duration,
    ) -> eyre::Result<()> {
        let mut stream = WebSocketNorito::new(stream, ws_message_timeout);
        let init_and_subscribe = async {
            let mut consumer = block::Consumer::new(&mut stream, kura).await?;
            subscribe_forever(&mut consumer).await
        };

        match init_and_subscribe.await {
            Ok(()) => stream.close().await.map_err(Into::into),
            Err(Error::Close) => Ok(()),
            Err(err) => {
                // NOTE: try close websocket and return initial error
                let _ = stream.close().await;
                Err(err.into())
            }
        }
    }

    /// Make endless `consumer` subscription for `blocks`
    ///
    /// Ideally should return `Result<!>` cause it either runs forever or returns error
    async fn subscribe_forever(consumer: &mut block::Consumer<'_>) -> Result<()> {
        let mut interval = tokio::time::interval(std::time::Duration::from_millis(10));
        loop {
            tokio::select! {
                // Wait for stream to be closed by client
                closed = consumer.stream.closed() => {
                    match closed {
                        Ok(()) => return Err(Error::Close),
                        Err(err) => return Err(block::Error::from(err).into())
                    }
                }
                // This branch sends blocks
                _ = interval.tick() => consumer.consume().await?,
            }
        }
    }
}

pub mod event {
    //! Events stream handler

    use super::*;
    use crate::{event, stream::WebSocketNorito};

    /// Type for any error during events streaming
    #[derive(Debug, displaydoc::Display, thiserror::Error)]
    enum Error {
        /// Event consumption resulted in an error: {_0}
        Consumer(#[source] event::Error),
        /// Event reception error
        Event(#[from] tokio::sync::broadcast::error::RecvError),
        /// Connection is closed
        Close,
    }

    impl From<event::Error> for Error {
        fn from(error: event::Error) -> Self {
            match error {
                event::Error::Stream(crate::stream::Error::Closed) => Self::Close,
                other => Self::Consumer(other),
            }
        }
    }

    type Result<T> = core::result::Result<T, Error>;

    /// Subscribes `stream` for `events` filtered by filter that is
    /// received through the `stream`
    #[iroha_futures::telemetry_future]
    pub async fn handle_events_stream(events: EventsSender, stream: WebSocket) -> eyre::Result<()> {
        handle_events_stream_with_receiver(
            events.subscribe(),
            stream,
            std::time::Duration::from_millis(defaults::torii::WS_MESSAGE_TIMEOUT_MS),
        )
        .await
    }

    /// Subscribe a pre-registered receiver to the event stream, ensuring buffered events
    /// emitted during the WebSocket upgrade are not dropped.
    #[iroha_futures::telemetry_future]
    pub async fn handle_events_stream_with_receiver(
        mut events_rx: tokio::sync::broadcast::Receiver<iroha_data_model::events::EventBox>,
        stream: WebSocket,
        ws_message_timeout: std::time::Duration,
    ) -> eyre::Result<()> {
        let mut stream = WebSocketNorito::new(stream, ws_message_timeout);
        let init_and_subscribe = async {
            let mut consumer = event::Consumer::new(&mut stream).await?;
            subscribe_forever(&mut events_rx, &mut consumer).await
        };

        match init_and_subscribe.await {
            Ok(()) => stream.close().await.map_err(Into::into),
            Err(Error::Close) => Ok(()),
            Err(err) => {
                // NOTE: try close websocket and return initial error
                let _ = stream.close().await;
                Err(err.into())
            }
        }
    }

    /// Make endless `consumer` subscription for `events`
    ///
    /// Ideally should return `Result<!>` cause it either runs forever or returns error
    async fn subscribe_forever(
        events: &mut tokio::sync::broadcast::Receiver<iroha_data_model::events::EventBox>,
        consumer: &mut event::Consumer<'_>,
    ) -> Result<()> {
        loop {
            tokio::select! {
                // Wait for stream to be closed by client
                closed = consumer.stream.closed() => {
                    match closed {
                        Ok(()) => return Err(Error::Close),
                        Err(err) => return Err(event::Error::from(err).into())
                    }
                }
                // This branch catches and sends events
                event = events.recv() => {
                    match event {
                        Ok(event) => {
                            iroha_logger::trace!(?event);
                            consumer.consume(event).await?;
                        }
                        Err(tokio::sync::broadcast::error::RecvError::Lagged(_)) => {
                            iroha_logger::warn!("event stream lagged; skipping buffered events");
                        }
                        Err(err) => return Err(Error::Event(err)),
                    }
                }
            }
        }
    }
}

/// Get running Iroha version (block header version).
#[iroha_futures::telemetry_future]
pub async fn handle_version(state: Arc<CoreState>) -> Response {
    use iroha_version::Version;

    let latest_block = std::num::NonZeroUsize::new(state.committed_height())
        .and_then(|height| state.block_by_height(height));
    let mut resp = match latest_block {
        Some(block) => Response::new(Body::from(block.version().to_string())),
        None => {
            let mut resp = Response::new(Body::from("genesis not applied"));
            *resp.status_mut() = StatusCode::SERVICE_UNAVAILABLE;
            resp
        }
    };
    resp.headers_mut().insert(
        header::CONTENT_TYPE,
        axum::http::HeaderValue::from_static("text/plain; charset=utf-8"),
    );
    resp
}

#[cfg(test)]
mod version_tests {
    use http_body_util::BodyExt as _;
    use iroha_core::{kura::Kura, query::store::LiveQueryStore, state::World};

    use super::*;

    #[tokio::test]
    async fn handle_version_reports_unavailable_without_genesis() {
        let state = Arc::new(CoreState::new_for_testing(
            World::default(),
            Kura::blank_kura_for_testing(),
            LiveQueryStore::start_test(),
        ));
        let response = handle_version(state).await;
        let (parts, body) = response.into_parts();
        assert_eq!(parts.status, StatusCode::SERVICE_UNAVAILABLE);
        assert_eq!(
            parts
                .headers
                .get(header::CONTENT_TYPE)
                .and_then(|value| value.to_str().ok()),
            Some("text/plain; charset=utf-8"),
        );
        let body_bytes = body.collect().await.expect("collect body").to_bytes();
        assert_eq!(
            std::str::from_utf8(&body_bytes).expect("utf8"),
            "genesis not applied"
        );
    }
}

/// List supported Torii API versions and defaults.
pub fn handle_api_versions(
    policy: &api_version::ApiVersionPolicy,
) -> crate::utils::NoritoBody<iroha_torii_shared::ApiVersionInfo> {
    let supported = policy
        .supported
        .iter()
        .copied()
        .map(ApiVersion::to_label)
        .collect();
    crate::utils::NoritoBody(iroha_torii_shared::ApiVersionInfo {
        default: policy.default.to_label(),
        supported,
        sunset_unix: policy.sunset_unix,
        min_proof_version: policy.min_proof.to_label(),
    })
}

