#[cfg(feature = "telemetry")]
#[iroha_futures::telemetry_future]
/// Handle POST `/v1/soranet/privacy/event`, forwarding relay observations into the secure aggregator.
pub async fn handle_post_soranet_privacy_event(
    telemetry: MaybeTelemetry,
    crate::NoritoJson(req): crate::NoritoJson<RecordSoranetPrivacyEventDto>,
) -> Result<impl IntoResponse> {
    if !telemetry.is_enabled() {
        return Err(Error::telemetry_profile_forbidden(
            SORANET_PRIVACY_EVENT_ENDPOINT,
            telemetry.profile(),
        ));
    }

    let RecordSoranetPrivacyEventDto { event, source } = req;
    let bucket_secs = telemetry
        .telemetry()
        .map(|handle| handle.soranet_privacy().config().bucket_secs)
        .unwrap_or_else(|| PrivacyBucketConfig::default().bucket_secs);
    let bucket_start = if bucket_secs > 0 {
        Some((event.timestamp_unix / bucket_secs) * bucket_secs)
    } else {
        None
    };

    telemetry.record_soranet_privacy_event(&event);

    iroha_logger::trace!(
        mode = %event.mode,
        timestamp = event.timestamp_unix,
        bucket_start,
        bucket_secs,
        source = source.as_deref().unwrap_or(""),
        "accepted SoraNet privacy event"
    );

    let mut entries = vec![
        json_entry("status", "accepted"),
        json_entry("mode", event.mode),
        json_entry("timestamp_unix", event.timestamp_unix),
    ];
    if let Some(bucket_start_unix) = bucket_start {
        entries.push(json_entry("bucket_start_unix", bucket_start_unix));
        entries.push(json_entry("bucket_duration_secs", bucket_secs));
    }
    if let Some(source_label) = source {
        entries.push(json_entry("source", source_label));
    }

    let payload = json_object(entries);
    Ok((StatusCode::ACCEPTED, NoritoJsonBody(payload)))
}

#[cfg(feature = "telemetry")]
#[iroha_futures::telemetry_future]
/// Handle POST `/v1/soranet/privacy/share`, ingesting Prio collector contributions.
pub async fn handle_post_soranet_privacy_share(
    telemetry: MaybeTelemetry,
    crate::NoritoJson(req): crate::NoritoJson<RecordSoranetPrivacyShareDto>,
) -> Result<impl IntoResponse> {
    if !telemetry.is_enabled() {
        return Err(Error::telemetry_profile_forbidden(
            SORANET_PRIVACY_SHARE_ENDPOINT,
            telemetry.profile(),
        ));
    }

    let RecordSoranetPrivacyShareDto {
        share,
        forwarded_by,
    } = req;
    let collector_id = share.collector_id;
    let bucket_start_unix = share.bucket_start_unix;
    let bucket_duration_secs = share.bucket_duration_secs;
    let mode = share.mode;
    let suppressed_hint = share.suppressed;

    if let Err(err) = telemetry.ingest_soranet_privacy_share(share) {
        iroha_logger::warn!(
            ?err,
            collector_id,
            bucket_start_unix,
            bucket_duration_secs,
            mode = %mode,
            "failed to ingest SoraNet privacy share"
        );
        return Err(conversion_error(format!(
            "invalid SoraNet privacy share: {err}"
        )));
    }

    iroha_logger::trace!(
        collector_id,
        bucket_start_unix,
        bucket_duration_secs,
        mode = %mode,
        suppressed_hint,
        forwarded_by = forwarded_by.as_deref().unwrap_or(""),
        "accepted SoraNet privacy share"
    );

    let mut entries = vec![
        json_entry("status", "accepted"),
        json_entry("collector_id", collector_id),
        json_entry("bucket_start_unix", bucket_start_unix),
        json_entry("bucket_duration_secs", bucket_duration_secs),
        json_entry("mode", mode),
        json_entry("suppressed_hint", suppressed_hint),
    ];
    if let Some(label) = forwarded_by {
        entries.push(json_entry("forwarded_by", label));
    }

    let payload = json_object(entries);
    Ok((StatusCode::ACCEPTED, NoritoJsonBody(payload)))
}

#[cfg(feature = "telemetry")]
/// Render the Prometheus metrics exposition when enabled by the active telemetry profile.
pub async fn handle_metrics(telemetry: &MaybeTelemetry, nexus_enabled: bool) -> Result<String> {
    if !telemetry.allows_expensive_metrics() {
        return Err(Error::telemetry_profile_forbidden(
            "metrics",
            telemetry.profile(),
        ));
    }

    telemetry
        .metrics()
        .await
        .try_to_string_with_nexus_gate(nexus_enabled)
        .map_err(Error::Prometheus)
}

/// Build a compact response with online peers.
pub fn handle_peers(
    online_peers: &OnlinePeersProvider,
    format: crate::utils::ResponseFormat,
) -> Response {
    // Caution: this short `.get` done frequently might cause the writer part to block, thus
    // blocking the P2P module
    let data = online_peers.get();
    match format {
        crate::utils::ResponseFormat::Norito => crate::NoritoBody(data).into_response(),
        crate::utils::ResponseFormat::Json => JsonBody(data).into_response(),
    }
}

#[cfg(feature = "telemetry")]
#[allow(clippy::unnecessary_wraps)]
/// Render the `/status` JSON payload or a specific nested field when requested.
pub async fn handle_status(
    telemetry: &MaybeTelemetry,
    accept: Option<axum::http::HeaderValue>,
    tail: Option<&str>,
    nexus_enabled: bool,
) -> Result<Response> {
    iroha_logger::debug!(
        tail = tail.unwrap_or(""),
        accept = ?accept,
        "serving /status"
    );
    if !telemetry.allows_metrics() {
        return Err(Error::telemetry_profile_forbidden(
            "status",
            telemetry.profile(),
        ));
    }

    let mut status = Status::from(telemetry.metrics().await);
    if !nexus_enabled {
        status.strip_nexus();
    }
    if let Some(handle) = telemetry.telemetry() {
        status.sorafs_micropayments = handle.sorafs_micropayment_samples();
    }
    iroha_logger::debug!(
        blocks = status.blocks,
        blocks_non_empty = status.blocks_non_empty,
        txs_approved = status.txs_approved,
        txs_rejected = status.txs_rejected,
        "status snapshot built"
    );

    if let Some(tail) = tail {
        if !nexus_enabled && is_nexus_status_segment(tail) {
            return Err(Error::StatusSegmentNotFound(eyre!(
                "Nexus lanes are disabled; field \"{}\" is unavailable",
                tail
            )));
        }
        let segment = status_value_by_path(&status, tail)
            .ok_or_else(|| Error::StatusSegmentNotFound(eyre!("Path not found: \"{}\"", tail)))?;
        let s = norito::json::to_json(&segment).map_err(|e| Error::StatusFailure(eyre!(e)))?;
        let mut resp = axum::response::Response::new(axum::body::Body::from(s));
        resp.headers_mut().insert(
            axum::http::header::CONTENT_TYPE,
            axum::http::HeaderValue::from_static("application/json"),
        );
        Ok(resp)
    } else {
        let format = match crate::utils::negotiate_response_format(accept.as_ref()) {
            Ok(fmt) => fmt,
            Err(resp) => return Ok(resp),
        };
        match format {
            crate::utils::ResponseFormat::Norito => {
                let bytes = norito::codec::encode_adaptive(&status);
                let mut resp = axum::response::Response::new(axum::body::Body::from(bytes));
                resp.headers_mut().insert(
                    axum::http::header::CONTENT_TYPE,
                    axum::http::HeaderValue::from_static(crate::utils::NORITO_MIME_TYPE),
                );
                Ok(resp)
            }
            crate::utils::ResponseFormat::Json => {
                let s = norito::json::to_json_pretty(&status)
                    .map_err(|e| Error::StatusFailure(eyre!(e)))?;
                let mut resp = axum::response::Response::new(axum::body::Body::from(s));
                resp.headers_mut().insert(
                    axum::http::header::CONTENT_TYPE,
                    axum::http::HeaderValue::from_static("application/json"),
                );
                Ok(resp)
            }
        }
    }
}

#[cfg(feature = "telemetry")]
fn status_value_by_path(status: &Status, tail: &str) -> Option<norito::json::Value> {
    let mut segments = tail.split('/').filter(|s| !s.is_empty());
    let field = segments.next()?;
    match field {
        "peers" if segments.next().is_none() => Some(status.peers.into()),
        "blocks" if segments.next().is_none() => Some(status.blocks.into()),
        "blocks_non_empty" if segments.next().is_none() => Some(status.blocks_non_empty.into()),
        "commit_time_ms" if segments.next().is_none() => Some(status.commit_time_ms.into()),
        "txs_approved" if segments.next().is_none() => Some(status.txs_approved.into()),
        "txs_rejected" if segments.next().is_none() => Some(status.txs_rejected.into()),
        "uptime" => {
            let duration = status.uptime.0;
            match segments.next() {
                None => Some(crate::json_object(vec![
                    ("secs", duration.as_secs()),
                    ("nanos", u64::from(duration.subsec_nanos())),
                ])),
                Some("secs") if segments.next().is_none() => Some(duration.as_secs().into()),
                Some("nanos") if segments.next().is_none() => {
                    Some(u64::from(duration.subsec_nanos()).into())
                }
                _ => None,
            }
        }
        "da_receipt_cursors" if segments.next().is_none() => Some(
            status
                .da_receipt_cursors
                .iter()
                .map(|cursor| {
                    crate::json_object(vec![
                        ("lane_id", json_value(&cursor.lane_id)),
                        ("epoch", json_value(&cursor.epoch)),
                        ("highest_sequence", json_value(&cursor.highest_sequence)),
                    ])
                })
                .collect::<Vec<_>>()
                .into(),
        ),
        "view_changes" if segments.next().is_none() => Some(status.view_changes.into()),
        "queue_size" if segments.next().is_none() => Some(status.queue_size.into()),
        "crypto" => match segments.next() {
            None => norito::json::to_value(&status.crypto).ok(),
            Some("sm_helpers_available") if segments.next().is_none() => {
                Some(status.crypto.sm_helpers_available.into())
            }
            Some("sm_openssl_preview_enabled") if segments.next().is_none() => {
                Some(status.crypto.sm_openssl_preview_enabled.into())
            }
            _ => None,
        },
        "governance" if segments.next().is_none() => {
            norito::json::to_value(&status.governance).ok()
        }
        "sorafs_micropayments" => match segments.next() {
            None => norito::json::to_value(&status.sorafs_micropayments).ok(),
            Some(provider_hex) => {
                let sample = status
                    .sorafs_micropayments
                    .iter()
                    .find(|entry| entry.provider_id_hex == provider_hex)?;
                match segments.next() {
                    None => norito::json::to_value(sample).ok(),
                    Some("credits") => match segments.next() {
                        None => norito::json::to_value(&sample.credits).ok(),
                        Some("deterministic_charge") if segments.next().is_none() => {
                            Some(json_value(&sample.credits.deterministic_charge))
                        }
                        Some("credit_generated") if segments.next().is_none() => {
                            Some(json_value(&sample.credits.credit_generated))
                        }
                        Some("credit_applied") if segments.next().is_none() => {
                            Some(json_value(&sample.credits.credit_applied))
                        }
                        Some("credit_carry") if segments.next().is_none() => {
                            Some(json_value(&sample.credits.credit_carry))
                        }
                        Some("outstanding") if segments.next().is_none() => {
                            Some(json_value(&sample.credits.outstanding))
                        }
                        _ => None,
                    },
                    Some("tickets") => match segments.next() {
                        None => norito::json::to_value(&sample.tickets).ok(),
                        Some("processed") if segments.next().is_none() => {
                            Some(sample.tickets.processed.into())
                        }
                        Some("won") if segments.next().is_none() => Some(sample.tickets.won.into()),
                        Some("duplicate") if segments.next().is_none() => {
                            Some(sample.tickets.duplicate.into())
                        }
                        _ => None,
                    },
                    _ => None,
                }
            }
        },
        _ => None,
    }
}

#[cfg(feature = "telemetry")]
fn is_nexus_status_segment(tail: &str) -> bool {
    let mut segments = tail.split('/').filter(|s| !s.is_empty());
    matches!(
        segments.next(),
        Some("teu_lane_commit" | "teu_dataspace_backlog" | "tx_gossip" | "da_receipt_cursors")
    )
}

